import React, { useEffect, useRef, useState, useCallback } from 'react';
import { GoogleGenAI, Modality, LiveServerMessage } from '@google/genai';
import { Persona } from '../types';
import { decode, decodeAudioData, createPcmBlob } from '../services/audioUtils';

interface VoiceModeProps {
  persona: Persona;
  onExit: () => void;
}

export const VoiceMode: React.FC<VoiceModeProps> = ({ persona, onExit }) => {
  const [isConnected, setIsConnected] = useState(false);
  const [isListening, setIsListening] = useState(false);
  const [transcription, setTranscription] = useState<string>("");
  const [aiTranscription, setAiTranscription] = useState<string>("");

  const canvasRef = useRef<HTMLCanvasElement>(null);
  const sessionRef = useRef<any>(null);
  const audioContextRef = useRef<AudioContext | null>(null);
  const outputContextRef = useRef<AudioContext | null>(null);
  const nextStartTimeRef = useRef<number>(0);
  const sourcesRef = useRef<Set<AudioBufferSourceNode>>(new Set());
  const analyserRef = useRef<AnalyserNode | null>(null);
  const animationFrameRef = useRef<number | null>(null);

  const cleanup = useCallback(() => {
    if (sessionRef.current) sessionRef.current.close();
    if (audioContextRef.current) audioContextRef.current.close();
    if (outputContextRef.current) outputContextRef.current.close();
    if (animationFrameRef.current) cancelAnimationFrame(animationFrameRef.current);
    sourcesRef.current.forEach(s => s.stop());
    sourcesRef.current.clear();
  }, []);

  useEffect(() => {
    return cleanup;
  }, [cleanup]);

  const startSession = async () => {
    try {
      const ai = new GoogleGenAI({ apiKey: process.env.API_KEY || '' });

      audioContextRef.current = new (window.AudioContext || (window as any).webkitAudioContext)({ sampleRate: 16000 });
      outputContextRef.current = new (window.AudioContext || (window as any).webkitAudioContext)({ sampleRate: 24000 });

      const stream = await navigator.mediaDevices.getUserMedia({ audio: true });
      const source = audioContextRef.current.createMediaStreamSource(stream);
      const analyser = audioContextRef.current.createAnalyser();
      analyser.fftSize = 256;
      source.connect(analyser);
      analyserRef.current = analyser;

      const sessionPromise = ai.live.connect({
        model: 'gemini-2.5-flash-native-audio-preview-12-2025',
        config: {
          responseModalities: [Modality.AUDIO],
          systemInstruction: persona.systemInstruction + " Provide short, natural conversational turns. Use audio transcription to support the user experience.",
          speechConfig: {
            voiceConfig: { prebuiltVoiceConfig: { voiceName: 'Zephyr' } }
          },
          outputAudioTranscription: {},
          inputAudioTranscription: {}
        },
        callbacks: {
          onopen: () => {
            setIsConnected(true);
            setIsListening(true);

            const scriptProcessor = audioContextRef.current!.createScriptProcessor(4096, 1, 1);
            scriptProcessor.onaudioprocess = (e) => {
              const inputData = e.inputBuffer.getChannelData(0);
              const base64Pcm = createPcmBlob(inputData);
              sessionPromise.then(session => {
                session.sendRealtimeInput({ media: { data: base64Pcm, mimeType: 'audio/pcm;rate=16000' } });
              });
            };
            source.connect(scriptProcessor);
            scriptProcessor.connect(audioContextRef.current!.destination);

            drawVisualizer();
          },
          onmessage: async (message: LiveServerMessage) => {
            if (message.serverContent?.inputTranscription) {
              setTranscription(prev => prev + " " + message.serverContent?.inputTranscription?.text);
            }
            if (message.serverContent?.outputTranscription) {
              setAiTranscription(prev => prev + " " + message.serverContent?.outputTranscription?.text);
            }
            if (message.serverContent?.turnComplete) {
              // Clear for next turn if needed, or keep for history
            }

            const audioData = message.serverContent?.modelTurn?.parts[0]?.inlineData?.data;
            if (audioData && outputContextRef.current) {
              const ctx = outputContextRef.current;
              nextStartTimeRef.current = Math.max(nextStartTimeRef.current, ctx.currentTime);

              const buffer = await decodeAudioData(decode(audioData), ctx, 24000, 1);
              const sourceNode = ctx.createBufferSource();
              sourceNode.buffer = buffer;
              sourceNode.connect(ctx.destination);
              sourceNode.onended = () => sourcesRef.current.delete(sourceNode);
              sourceNode.start(nextStartTimeRef.current);
              nextStartTimeRef.current += buffer.duration;
              sourcesRef.current.add(sourceNode);
            }

            if (message.serverContent?.interrupted) {
              sourcesRef.current.forEach(s => s.stop());
              sourcesRef.current.clear();
              nextStartTimeRef.current = 0;
            }
          },
          onclose: () => setIsConnected(false),
          onerror: (e) => console.error("Live API Error:", e)
        }
      });

      sessionRef.current = await sessionPromise;
    } catch (err) {
      console.error("Failed to start voice session:", err);
    }
  };

  const drawVisualizer = () => {
    if (!canvasRef.current || !analyserRef.current) return;
    const canvas = canvasRef.current;
    const ctx = canvas.getContext('2d');
    if (!ctx) return;

    const bufferLength = analyserRef.current.frequencyBinCount;
    const dataArray = new Uint8Array(bufferLength);

    const render = () => {
      analyserRef.current!.getByteFrequencyData(dataArray);
      ctx.clearRect(0, 0, canvas.width, canvas.height);

      const barWidth = (canvas.width / bufferLength) * 2.5;
      let barHeight;
      let x = 0;

      for (let i = 0; i < bufferLength; i++) {
        barHeight = (dataArray[i] / 255) * canvas.height;
        ctx.fillStyle = `rgb(99, 102, 241)`;
        ctx.fillRect(x, canvas.height - barHeight, barWidth, barHeight);
        x += barWidth + 1;
      }
      animationFrameRef.current = requestAnimationFrame(render);
    };
    render();
  };

  return (
    <div className="flex flex-col h-full bg-slate-900 text-white rounded-3xl overflow-hidden shadow-2xl animate-in fade-in zoom-in duration-300">
      <div className="p-6 bg-slate-800 border-b border-slate-700 flex justify-between items-center">
        <div className="flex items-center gap-4">
          <img src={persona.avatar} alt={persona.name} className="w-12 h-12 rounded-full border-2 border-indigo-500" />
          <div>
            <h2 className="text-xl font-bold">{persona.name}</h2>
            <p className="text-sm text-slate-400">{persona.title}</p>
          </div>
        </div>
        <button 
          onClick={onExit}
          className="bg-slate-700 hover:bg-slate-600 px-4 py-2 rounded-lg text-sm transition-colors"
        >
          End Session
        </button>
      </div>

      <div className="flex-grow flex flex-col items-center justify-center p-8 space-y-12">
        {!isConnected ? (
          <div className="text-center space-y-6">
            <div className="w-24 h-24 bg-indigo-600 rounded-full flex items-center justify-center mx-auto animate-pulse">
               <svg className="w-12 h-12 text-white" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M19 11a7 7 0 01-7 7m0 0a7 7 0 01-7-7m7 7v4m0 0H8m4 0h4m-4-8a3 3 0 01-3-3V5a3 3 0 116 0v6a3 3 0 01-3 3z"></path></svg>
            </div>
            <h2 className="text-2xl font-bold text-slate-100">Ready to speak?</h2>
            <p className="text-slate-400 max-w-md mx-auto">This session uses real-time voice. Ensure you are in a quiet environment for best results.</p>
            <button 
              onClick={startSession}
              className="bg-indigo-600 hover:bg-indigo-500 text-white px-8 py-3 rounded-full font-bold text-lg transition-all transform hover:scale-105"
            >
              Start Microphone
            </button>
          </div>
        ) : (
          <div className="w-full max-w-2xl space-y-8">
            <canvas ref={canvasRef} width={600} height={150} className="w-full rounded-xl opacity-80" />

            <div className="space-y-6">
              <div className="bg-slate-800 p-6 rounded-2xl border border-slate-700">
                <p className="text-xs font-bold text-indigo-400 uppercase mb-2 tracking-widest">You said:</p>
                <p className="text-slate-200 italic min-h-[1.5rem]">{transcription || "Listening..."}</p>
              </div>

              <div className="bg-indigo-900/40 p-6 rounded-2xl border border-indigo-500/30">
                <p className="text-xs font-bold text-indigo-300 uppercase mb-2 tracking-widest">{persona.name}:</p>
                <p className="text-indigo-100 leading-relaxed min-h-[1.5rem]">{aiTranscription || "Thinking..."}</p>
              </div>
            </div>

            <div className="flex justify-center">
              <div className="flex items-center gap-2 px-4 py-2 bg-indigo-600 rounded-full animate-pulse">
                <div className="w-2 h-2 bg-white rounded-full"></div>
                <span className="text-xs font-bold uppercase">Live Connection Active</span>
              </div>
            </div>
          </div>
        )}
      </div>

      <div className="p-4 bg-slate-900 text-center text-[10px] text-slate-500 uppercase tracking-widest">
        Powered by Gemini 2.5 Native Audio • Private Professional Simulation
      </div>
    </div>
  );
};

import React, { useState, useEffect, useRef } from 'react';
import { GoogleGenAI, Chat, GenerateContentResponse } from '@google/genai';
import { Persona, Message } from '../types';

interface TextModeProps {
  persona: Persona;
  onExit: () => void;
}

export const TextMode: React.FC<TextModeProps> = ({ persona, onExit }) => {
  const [messages, setMessages] = useState<Message[]>([]);
  const [inputValue, setInputValue] = useState("");
  const [isTyping, setIsTyping] = useState(false);
  const chatRef = useRef<Chat | null>(null);
  const scrollRef = useRef<HTMLDivElement>(null);

  useEffect(() => {
    const ai = new GoogleGenAI({ apiKey: process.env.API_KEY || '' });
    chatRef.current = ai.chats.create({
      model: 'gemini-3-flash-preview',
      config: {
        systemInstruction: persona.systemInstruction + " Respond with concise but professional text. Challenge the student's phrasing if it is not professional."
      }
    });

    // Initial greeting
    const greet = async () => {
      setIsTyping(true);
      try {
        const result = await chatRef.current!.sendMessage({ message: "Start the meeting by greeting me and asking what's on my mind today." });
        setMessages([{ role: 'model', text: result.text || "", timestamp: Date.now() }]);
      } catch (err) {
        console.error(err);
      } finally {
        setIsTyping(false);
      }
    };
    greet();
  }, [persona]);

  useEffect(() => {
    if (scrollRef.current) {
      scrollRef.current.scrollTop = scrollRef.current.scrollHeight;
    }
  }, [messages, isTyping]);

  const handleSend = async (e: React.FormEvent) => {
    e.preventDefault();
    if (!inputValue.trim() || isTyping || !chatRef.current) return;

    const userMessage: Message = { role: 'user', text: inputValue, timestamp: Date.now() };
    setMessages(prev => [...prev, userMessage]);
    setInputValue("");
    setIsTyping(true);

    try {
      const result = await chatRef.current.sendMessage({ message: inputValue });
      setMessages(prev => [...prev, { role: 'model', text: result.text || "", timestamp: Date.now() }]);
    } catch (err) {
      console.error(err);
      setMessages(prev => [...prev, { role: 'model', text: "I'm sorry, I'm a bit busy at the moment. Can you repeat that?", timestamp: Date.now() }]);
    } finally {
      setIsTyping(false);
    }
  };

  return (
    <div className="flex flex-col h-full bg-white rounded-3xl overflow-hidden shadow-2xl border border-slate-200">
      <div className="p-6 bg-slate-50 border-b border-slate-200 flex justify-between items-center">
        <div className="flex items-center gap-4">
          <img src={persona.avatar} alt={persona.name} className="w-10 h-10 rounded-full border border-slate-200 shadow-sm" />
          <div>
            <h2 className="text-lg font-bold text-slate-800">{persona.name}</h2>
            <div className="flex items-center gap-2">
              <span className="w-2 h-2 bg-green-500 rounded-full animate-pulse"></span>
              <p className="text-xs font-medium text-slate-500 uppercase tracking-tighter">In a meeting</p>
            </div>
          </div>
        </div>
        <button 
          onClick={onExit}
          className="text-slate-500 hover:text-slate-800 text-sm font-medium transition-colors"
        >
          Exit Chat
        </button>
      </div>

      <div ref={scrollRef} className="flex-grow p-6 overflow-y-auto space-y-6 bg-slate-50/50">
        {messages.map((m, i) => (
          <div key={i} className={`flex ${m.role === 'user' ? 'justify-end' : 'justify-start'}`}>
            <div className={`max-w-[80%] p-4 rounded-2xl shadow-sm text-sm leading-relaxed ${
              m.role === 'user' 
                ? 'bg-indigo-600 text-white rounded-br-none' 
                : 'bg-white text-slate-800 rounded-bl-none border border-slate-100'
            }`}>
              {m.text}
            </div>
          </div>
        ))}
        {isTyping && (
          <div className="flex justify-start">
            <div className="bg-white border border-slate-100 p-4 rounded-2xl rounded-bl-none shadow-sm flex gap-1">
              <div className="w-2 h-2 bg-slate-300 rounded-full animate-bounce"></div>
              <div className="w-2 h-2 bg-slate-300 rounded-full animate-bounce delay-75"></div>
              <div className="w-2 h-2 bg-slate-300 rounded-full animate-bounce delay-150"></div>
            </div>
          </div>
        )}
      </div>

      <form onSubmit={handleSend} className="p-6 bg-white border-t border-slate-200">
        <div className="flex gap-4">
          <input
            type="text"
            value={inputValue}
            onChange={(e) => setInputValue(e.target.value)}
            placeholder="Type your response professionally..."
            className="flex-grow p-4 bg-slate-100 rounded-xl outline-none focus:ring-2 focus:ring-indigo-500/20 border border-transparent focus:border-indigo-500 transition-all text-sm"
          />
          <button 
            type="submit"
            disabled={!inputValue.trim() || isTyping}
            className="bg-indigo-600 hover:bg-indigo-700 disabled:opacity-50 text-white p-4 rounded-xl transition-all shadow-lg shadow-indigo-600/20"
          >
            <svg className="w-5 h-5" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M5 13l4 4L19 7"></path></svg>
          </button>
        </div>
      </form>
    </div>
  );
};

import React, { useState } from 'react';
import { PERSONAS } from './constants';
import { Persona, SessionState } from './types';
import { PersonaCard } from './components/PersonaCard';
import { VoiceMode } from './components/VoiceMode';
import { TextMode } from './components/TextMode';

const App: React.FC = () => {
  const [session, setSession] = useState<SessionState>({
    isActive: false,
    mode: 'text',
    persona: null
  });

  const handleSelectPersona = (persona: Persona) => {
    setSession({ ...session, persona });
  };

  const startSession = (mode: 'text' | 'voice') => {
    setSession({ ...session, isActive: true, mode });
  };

  const endSession = () => {
    setSession({ ...session, isActive: false, persona: null });
  };

  if (session.isActive && session.persona) {
    return (
      <div className="h-screen w-full bg-slate-100 p-4 md:p-10 flex items-center justify-center">
        <div className="w-full max-w-5xl h-full max-h-[900px]">
          {session.mode === 'voice' ? (
            <VoiceMode persona={session.persona} onExit={endSession} />
          ) : (
            <TextMode persona={session.persona} onExit={endSession} />
          )}
        </div>
      </div>
    );
  }

  return (
    <div className="min-h-screen bg-slate-50 flex flex-col">
      {/* Header */}
      <header className="bg-white border-b border-slate-200 sticky top-0 z-10">
        <div className="max-w-7xl mx-auto px-6 h-20 flex items-center justify-between">
          <div className="flex items-center gap-3">
            <div className="w-10 h-10 bg-indigo-600 rounded-xl flex items-center justify-center shadow-lg shadow-indigo-600/20">
              <svg className="w-6 h-6 text-white" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M17 8h2a2 2 0 012 2v6a2 2 0 01-2 2h-2v4l-4-4H9a1.994 1.994 0 01-1.414-.586m0 0L11 14h4a2 2 0 002-2V6a2 2 0 00-2-2H5a2 2 0 00-2 2v6a2 2 0 002 2h2v4l.586-.586z"></path></svg>
            </div>
            <div>
              <h1 className="text-xl font-bold text-slate-900 tracking-tight">PowerTalk ELI</h1>
              <p className="text-xs font-semibold text-slate-400 uppercase tracking-widest">High-Stakes Simulation</p>
            </div>
          </div>
          <div className="hidden md:flex gap-8 text-sm font-medium text-slate-500">
            <a href="#" className="hover:text-indigo-600 transition-colors">Library</a>
            <a href="#" className="hover:text-indigo-600 transition-colors">Performance</a>
            <a href="#" className="hover:text-indigo-600 transition-colors">Support</a>
          </div>
        </div>
      </header>

      {/* Main Content */}
      <main className="flex-grow max-w-7xl mx-auto px-6 py-12 w-full">
        {!session.persona ? (
          <div className="space-y-12">
            <div className="max-w-3xl">
              <h2 className="text-4xl md:text-5xl font-extrabold text-slate-900 tracking-tight mb-6">
                Master the Art of <span className="text-indigo-600">Professional English</span>
              </h2>
              <p className="text-lg text-slate-600 leading-relaxed mb-8">
                Simulation training for international graduate students. Practice communicating with faculty, administrators, and hiring managers in high-stakes environments.
              </p>
              <div className="h-1 w-20 bg-indigo-600 rounded-full"></div>
            </div>

            <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-4 gap-6">
              {PERSONAS.map(p => (
                <PersonaCard key={p.id} persona={p} onSelect={handleSelectPersona} />
              ))}
            </div>
          </div>
        ) : (
          <div className="max-w-4xl mx-auto space-y-12 animate-in slide-in-from-bottom duration-500">
            <button 
              onClick={() => setSession({ ...session, persona: null })}
