}

export interface Persona {
  id: PersonaType;
  name: string;
  title: string;
  description: string;
  goal: string;
  systemInstruction: string;
  avatar: string;
  voiceName: 'Kore' | 'Puck' | 'Charon' | 'Fenrir' | 'Zephyr';
}

export interface Message {
  role: 'user' | 'model';
  text: string;
  timestamp: number;
}

export interface SessionState {
  isActive: boolean;
  mode: 'text' | 'voice';
