import React, { useState, useEffect, useRef } from 'react';
import { GoogleGenAI, Chat, GenerateContentResponse, Modality } from '@google/genai';
import { Persona, Message } from '../types';
import { decode, decodeAudioData } from '../services/audioUtils';

interface TextModeProps {
  persona: Persona;
  onExit: () => void;
}

export const TextMode: React.FC<TextModeProps> = ({ persona, onExit }) => {
  const [messages, setMessages] = useState<Message[]>([]);
  const [inputValue, setInputValue] = useState("");
  const [isTyping, setIsTyping] = useState(false);
  const [isSpeaking, setIsSpeaking] = useState<number | null>(null);
  const [isListening, setIsListening] = useState(false);

  const chatRef = useRef<Chat | null>(null);
  const scrollRef = useRef<HTMLDivElement>(null);
  const audioContextRef = useRef<AudioContext | null>(null);
  const recognitionRef = useRef<any>(null);

  useEffect(() => {
    const ai = new GoogleGenAI({ apiKey: process.env.API_KEY || '' });
    chatRef.current = ai.chats.create({
      model: 'gemini-3-flash-preview',
      config: {
        systemInstruction: `You are ${persona.name}, ${persona.title}. ${persona.systemInstruction} Keep your responses to 1-3 sentences to facilitate language practice.`
      }
    });

    const greet = async () => {
      setIsTyping(true);
      try {
        const result = await chatRef.current!.sendMessage({ message: "Start the meeting professionally." });
        const text = result.text || "";
        setMessages([{ role: 'model', text, timestamp: Date.now() }]);
        // Auto-play the first greeting
        playTTS(text, 0);
      } catch (err) {
        console.error(err);
      } finally {
        setIsTyping(false);
      }
    };
    greet();

    // Setup Web Speech API for STT
    const SpeechRecognition = (window as any).SpeechRecognition || (window as any).webkitSpeechRecognition;
    if (SpeechRecognition) {
      recognitionRef.current = new SpeechRecognition();
      recognitionRef.current.continuous = false;
      recognitionRef.current.interimResults = true;
      recognitionRef.current.onresult = (event: any) => {
        const transcript = Array.from(event.results)
          .map((result: any) => result[0])
          .map((result: any) => result.transcript)
          .join('');
        setInputValue(transcript);
      };
      recognitionRef.current.onend = () => setIsListening(false);
    }

    return () => {
      if (audioContextRef.current) audioContextRef.current.close();
    };
  }, [persona]);

  const playTTS = async (text: string, index: number) => {
    setIsSpeaking(index);
    try {
      const ai = new GoogleGenAI({ apiKey: process.env.API_KEY || '' });
      const response = await ai.models.generateContent({
        model: "gemini-2.5-flash-preview-tts",
        contents: [{ parts: [{ text }] }],
        config: {
          responseModalities: [Modality.AUDIO],
          speechConfig: {
            voiceConfig: { prebuiltVoiceConfig: { voiceName: persona.voiceName } },
          },
        },
      });

      const audioData = response.candidates?.[0]?.content?.parts?.[0]?.inlineData?.data;
      if (audioData) {
        if (!audioContextRef.current) {
          audioContextRef.current = new (window.AudioContext || (window as any).webkitAudioContext)({ sampleRate: 24000 });
        }
        const buffer = await decodeAudioData(decode(audioData), audioContextRef.current, 24000, 1);
        const source = audioContextRef.current.createBufferSource();
        source.buffer = buffer;
        source.connect(audioContextRef.current.destination);
        source.onended = () => setIsSpeaking(null);
        source.start();
      }
    } catch (err) {
      console.error("TTS Error:", err);
      setIsSpeaking(null);
    }
  };

  const toggleListening = () => {
    if (isListening) {
      recognitionRef.current?.stop();
    } else {
      setIsListening(true);
      recognitionRef.current?.start();
    }
  };

  const handleSend = async (e?: React.FormEvent) => {
    e?.preventDefault();
    if (!inputValue.trim() || isTyping || !chatRef.current) return;

    const userMessage: Message = { role: 'user', text: inputValue, timestamp: Date.now() };
    setMessages(prev => [...prev, userMessage]);
    setInputValue("");
    setIsTyping(true);

    try {
      const result = await chatRef.current.sendMessage({ message: inputValue });
      const responseText = result.text || "";
      const newMessageIndex = messages.length + 1;
      setMessages(prev => [...prev, { role: 'model', text: responseText, timestamp: Date.now() }]);
      playTTS(responseText, newMessageIndex);
    } catch (err) {
      console.error(err);
    } finally {
      setIsTyping(false);
    }
  };

  return (
    <div className="flex flex-col h-full bg-white rounded-3xl overflow-hidden shadow-2xl border border-slate-200">
      <div className="p-6 bg-slate-50 border-b border-slate-200 flex justify-between items-center">
        <div className="flex items-center gap-4">
          <img src={persona.avatar} alt={persona.name} className="w-12 h-12 rounded-full border-2 border-white shadow-md" />
          <div>
            <h2 className="text-lg font-bold text-slate-800">{persona.name}</h2>
            <p className="text-xs font-semibold text-indigo-600 uppercase">{persona.title}</p>
          </div>
        </div>
        <button onClick={onExit} className="text-slate-400 hover:text-slate-600 font-medium text-sm transition-colors">End Meeting</button>
      </div>

      <div ref={scrollRef} className="flex-grow p-6 overflow-y-auto space-y-6 bg-slate-50/30">
        {messages.map((m, i) => (
          <div key={i} className={`flex items-start gap-3 ${m.role === 'user' ? 'flex-row-reverse' : 'flex-row'}`}>
            <div className={`max-w-[80%] p-4 rounded-2xl shadow-sm text-sm ${
              m.role === 'user' ? 'bg-slate-800 text-white rounded-tr-none' : 'bg-white text-slate-800 rounded-tl-none border border-slate-100'
            }`}>
              <div className="flex justify-between items-start gap-4 mb-1">
                <span className="text-[10px] opacity-60 uppercase font-bold tracking-widest">{m.role === 'user' ? 'You' : persona.name}</span>
                {m.role === 'model' && (
                  <button 
                    onClick={() => playTTS(m.text, i)}
                    className={`p-1 rounded-full transition-colors ${isSpeaking === i ? 'bg-indigo-100 text-indigo-600' : 'hover:bg-slate-100 text-slate-400'}`}
                  >
                    <svg className={`w-4 h-4 ${isSpeaking === i ? 'animate-pulse' : ''}`} fill="none" stroke="currentColor" viewBox="0 0 24 24">
                      <path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M15.536 8.464a5 5 0 010 7.072m2.828-9.9a9 9 0 010 12.728M5.586 15H4a1 1 0 01-1-1v-4a1 1 0 011-1h1.586l4.707-4.707C10.923 3.663 12 4.109 12 5v14c0 .891-1.077 1.337-1.707.707L5.586 15z" />
                    </svg>
                  </button>
                )}
              </div>
              <p className="leading-relaxed">{m.text}</p>
            </div>
          </div>
        ))}
        {isTyping && (
          <div className="flex justify-start">
            <div className="bg-white border border-slate-100 p-4 rounded-2xl shadow-sm flex gap-1">
              <div className="w-1.5 h-1.5 bg-indigo-400 rounded-full animate-bounce"></div>
              <div className="w-1.5 h-1.5 bg-indigo-400 rounded-full animate-bounce delay-75"></div>
              <div className="w-1.5 h-1.5 bg-indigo-400 rounded-full animate-bounce delay-150"></div>
            </div>
          </div>
        )}
      </div>

      <div className="p-6 bg-white border-t border-slate-200">
        <form onSubmit={handleSend} className="relative">
          <input
            type="text"
            value={inputValue}
            onChange={(e) => setInputValue(e.target.value)}
            placeholder={isListening ? "Listening to your voice..." : "Type or dictate your response..."}
            className={`w-full p-4 pr-24 bg-slate-50 rounded-2xl border outline-none transition-all text-sm ${
              isListening ? 'border-indigo-500 ring-4 ring-indigo-500/10' : 'border-slate-200 focus:border-indigo-300'
            }`}
          />
          <div className="absolute right-2 top-2 flex gap-2">
            <button 
              type="button"
              onClick={toggleListening}
              className={`p-2 rounded-xl transition-all ${isListening ? 'bg-red-500 text-white animate-pulse' : 'bg-slate-200 text-slate-500 hover:bg-slate-300'}`}
            >
              <svg className="w-5 h-5" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M19 11a7 7 0 01-7 7m0 0a7 7 0 01-7-7m7 7v4m0 0H8m4 0h4m-4-8a3 3 0 01-3-3V5a3 3 0 116 0v6a3 3 0 01-3 3z"></path></svg>
            </button>
            <button 
              type="submit"
              disabled={!inputValue.trim() || isTyping}
              className="bg-indigo-600 hover:bg-indigo-700 disabled:opacity-50 text-white p-2 rounded-xl shadow-lg shadow-indigo-600/20 transition-all"
            >
              <svg className="w-5 h-5" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M5 13l4 4L19 7"></path></svg>
            </button>
          </div>
        </form>
        <p className="text-[10px] text-slate-400 mt-3 text-center uppercase font-bold tracking-widest">Turn-based Practice: Speak, Type, and Listen</p>
      </div>
    </div>
  );
};

