              }`}
            >
              <svg className="w-3.5 h-3.5" fill="none" stroke="currentColor" viewBox="0 0 24 24">
                <path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M19 11a7 7 0 01-7 7m0 0a7 7 0 01-7-7m7 7v4m0 0H8m4 0h4m-4-8a3 3 0 01-3-3V5a3 3 0 116 0v6a3 3 0 01-3 3z" />
              </svg>
              {isListening ? 'Stop Listening' : 'Toggle Voice Input'}
            </button>
          </div>

          <div className="relative">
            <input
              type="text"
              value={inputValue}
              onChange={(e) => setInputValue(e.target.value)}
              disabled={isTyping}
              placeholder={isListening ? "I'm listening, speak clearly..." : "Type your response here..."}
              className={`w-full p-4 pr-16 bg-slate-50 rounded-2xl border outline-none transition-all text-sm font-medium ${
                isListening 
                  ? 'border-indigo-500 ring-4 ring-indigo-500/10 placeholder-indigo-400 text-indigo-700' 
                  : 'border-slate-200 focus:border-indigo-300 text-slate-700'
              } ${isTyping ? 'opacity-50 cursor-not-allowed' : ''}`}
            />
            <button 
              type="submit"
              disabled={!inputValue.trim() || isTyping}
              className="absolute right-2 top-2 bottom-2 bg-indigo-600 hover:bg-indigo-700 disabled:bg-slate-300 text-white px-4 rounded-xl shadow-lg shadow-indigo-600/20 transition-all transform active:scale-95"
            >
              <svg className="w-5 h-5" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M5 13l4 4L19 7"></path></svg>
            </button>
          </div>
        </form>
        <div className="flex justify-between items-center mt-3">
          <p className="text-[10px] text-slate-400 uppercase font-bold tracking-widest">Goal: {persona.goal}</p>
        </div>
      </div>
    </div>
  );
};

