import React, { useState, useEffect, useRef } from 'react';
import { GoogleGenAI, Chat, Modality } from '@google/genai';
import { Persona, Message, Feedback } from '../types';
import { decode, decodeAudioData } from '../services/audioUtils';
import { FeedbackForm } from './FeedbackForm';

interface TextModeProps {
  persona: Persona;
  onExit: () => void;
}

export const TextMode: React.FC<TextModeProps> = ({ persona, onExit }) => {
  const [messages, setMessages] = useState<Message[]>([]);
  const [inputValue, setInputValue] = useState("");
  const [isTyping, setIsTyping] = useState(false);
  const [isSpeaking, setIsSpeaking] = useState<number | null>(null);
  const [isListening, setIsListening] = useState(false);
  const [feedbackOpen, setFeedbackOpen] = useState<number | null>(null);

  const chatRef = useRef<Chat | null>(null);
  const scrollRef = useRef<HTMLDivElement>(null);
  const audioContextRef = useRef<AudioContext | null>(null);
  const recognitionRef = useRef<any>(null);

  useEffect(() => {
    const ai = new GoogleGenAI({ apiKey: process.env.API_KEY || '' });
    chatRef.current = ai.chats.create({
      model: 'gemini-3-flash-preview',
      config: {
        systemInstruction: `You are ${persona.name}, ${persona.title}. ${persona.systemInstruction} Keep your responses to 1-3 sentences to facilitate language practice. Be professional but direct. Encourage the student to be precise.`
      }
    });

    const greet = async () => {
      setIsTyping(true);
      try {
        const result = await chatRef.current!.sendMessage({ message: "Start the meeting professionally." });
        const text = result.text || "";
        setMessages([{ role: 'model', text, timestamp: Date.now() }]);
        playTTS(text, 0);
      } catch (err) {
        console.error(err);
      } finally {
        setIsTyping(false);
      }
    };
    greet();

    const SpeechRecognition = (window as any).SpeechRecognition || (window as any).webkitSpeechRecognition;
    if (SpeechRecognition) {
      recognitionRef.current = new SpeechRecognition();
      recognitionRef.current.continuous = false; 
      recognitionRef.current.interimResults = true;
      recognitionRef.current.lang = 'en-US';
      recognitionRef.current.onresult = (event: any) => {
        const transcript = Array.from(event.results)
          .map((result: any) => result[0])
          .map((result: any) => result.transcript)
          .join('');
        setInputValue(transcript);
      };
      recognitionRef.current.onstart = () => setIsListening(true);
      recognitionRef.current.onend = () => setIsListening(false);
    }

    return () => {
      if (audioContextRef.current) audioContextRef.current.close();
      if (recognitionRef.current) recognitionRef.current.stop();
    };
  }, [persona]);

  const playTTS = async (text: string, index: number) => {
    setIsSpeaking(index);
    try {
      const ai = new GoogleGenAI({ apiKey: process.env.API_KEY || '' });
      const response = await ai.models.generateContent({
        model: "gemini-2.5-flash-preview-tts",
        contents: [{ parts: [{ text }] }],
        config: {
          responseModalities: [Modality.AUDIO],
          speechConfig: {
            voiceConfig: { prebuiltVoiceConfig: { voiceName: persona.voiceName } },
          },
        },
      });

      const audioData = response.candidates?.[0]?.content?.parts?.[0]?.inlineData?.data;
      if (audioData) {
        if (!audioContextRef.current) {
          audioContextRef.current = new (window.AudioContext || (window as any).webkitAudioContext)({ sampleRate: 24000 });
        }
        const buffer = await decodeAudioData(decode(audioData), audioContextRef.current, 24000, 1);
        const source = audioContextRef.current.createBufferSource();
        source.buffer = buffer;
        source.connect(audioContextRef.current.destination);
        source.onended = () => setIsSpeaking(null);
        source.start();
      }
    } catch (err) {
      console.error("TTS Error:", err);
      setIsSpeaking(null);
    }
  };

  const saveFeedback = (index: number, feedback: Feedback) => {
    const updatedMessages = [...messages];
    updatedMessages[index].feedback = feedback;
    setMessages(updatedMessages);
    setFeedbackOpen(null);

    // Store for future analysis
    const allFeedback = JSON.parse(localStorage.getItem('powertalk_feedback') || '[]');
    allFeedback.push({
      personaId: persona.id,
      messageText: messages[index].text,
      ...feedback
    });
    localStorage.setItem('powertalk_feedback', JSON.stringify(allFeedback));
  };

  const handleSend = async (e?: React.FormEvent) => {
    e?.preventDefault();
    if (!inputValue.trim() || isTyping || !chatRef.current) return;

    const textToSend = inputValue;
    const userMessage: Message = { role: 'user', text: textToSend, timestamp: Date.now() };
    setMessages(prev => [...prev, userMessage]);
    setInputValue("");
    setIsTyping(true);

    try {
      const result = await chatRef.current.sendMessage({ message: textToSend });
      const responseText = result.text || "";
      const newMessageIndex = messages.length + 1;
      setMessages(prev => [...prev, { role: 'model', text: responseText, timestamp: Date.now() }]);
      playTTS(responseText, newMessageIndex);
    } catch (err) {
      console.error(err);
    } finally {
      setIsTyping(false);
    }
  };

  useEffect(() => {
    if (scrollRef.current) {
      scrollRef.current.scrollTop = scrollRef.current.scrollHeight;
    }
  }, [messages, isTyping, feedbackOpen]);

  return (
    <div className="flex flex-col h-full bg-white rounded-3xl overflow-hidden shadow-2xl border border-slate-200">
      <div className="p-6 bg-slate-50 border-b border-slate-200 flex justify-between items-center shrink-0">
        <div className="flex items-center gap-4">
          <img src={persona.avatar} alt={persona.name} className="w-12 h-12 rounded-full border-2 border-white shadow-md" />
          <div>
            <h2 className="text-lg font-bold text-slate-800">{persona.name}</h2>
            <p className="text-xs font-semibold text-indigo-600 uppercase">{persona.title}</p>
          </div>
        </div>
        <button onClick={onExit} className="text-slate-400 hover:text-slate-600 font-medium text-sm transition-colors">End Meeting</button>
      </div>

      <div ref={scrollRef} className="flex-grow p-6 overflow-y-auto space-y-6 bg-slate-50/30">
        {messages.map((m, i) => (
          <div key={i} className={`flex items-start gap-3 ${m.role === 'user' ? 'flex-row-reverse' : 'flex-row'}`}>
            <div className={`max-w-[80%] space-y-2 ${m.role === 'user' ? 'text-right' : ''}`}>
              <div className={`p-4 rounded-2xl shadow-sm text-sm ${
                m.role === 'user' ? 'bg-indigo-600 text-white rounded-tr-none' : 'bg-white text-slate-800 rounded-tl-none border border-slate-100'
              }`}>
                <div className="flex justify-between items-start gap-4 mb-1">
                  <span className="text-[10px] opacity-60 uppercase font-bold tracking-widest">{m.role === 'user' ? 'You' : persona.name}</span>
                  {m.role === 'model' && (
                    <div className="flex gap-2">
                      <button 
                        onClick={() => playTTS(m.text, i)}
                        className={`p-1 rounded-full transition-colors ${isSpeaking === i ? 'bg-indigo-100 text-indigo-600' : 'hover:bg-slate-100 text-slate-400'}`}
                        title="Listen"
                      >
                        <svg className={`w-4 h-4 ${isSpeaking === i ? 'animate-pulse' : ''}`} fill="none" stroke="currentColor" viewBox="0 0 24 24">
                          <path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M15.536 8.464a5 5 0 010 7.072m2.828-9.9a9 9 0 010 12.728M5.586 15H4a1 1 0 01-1-1v-4a1 1 0 011-1h1.586l4.707-4.707C10.923 3.663 12 4.109 12 5v14c0 .891-1.077 1.337-1.707.707L5.586 15z" />
                        </svg>
                      </button>
                      <button 
                        onClick={() => setFeedbackOpen(feedbackOpen === i ? null : i)}
                        className={`p-1 rounded-full transition-colors ${m.feedback ? 'text-green-600 bg-green-50' : 'hover:bg-slate-100 text-slate-400'}`}
                        title="Provide Feedback"
                      >
                        <svg className="w-4 h-4" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M11.049 2.927c.3-.921 1.603-.921 1.902 0l1.519 4.674a1 1 0 00.95.69h4.915c.969 0 1.371 1.24.588 1.81l-3.976 2.888a1 1 0 00-.363 1.118l1.518 4.674c.3.922-.755 1.688-1.54 1.118l-3.976-2.888a1 1 0 00-1.176 0l-3.976 2.888c-.784.57-1.838-.197-1.539-1.118l1.518-4.674a1 1 0 00-.363-1.118l-3.976-2.888c-.784-.57-.38-1.81.588-1.81h4.914a1 1 0 00.951-.69l1.519-4.674z" /></svg>
                      </button>
                    </div>
                  )}
                </div>
                <p className="leading-relaxed text-left">{m.text}</p>
              </div>

              {feedbackOpen === i && (
                <FeedbackForm onSave={(f) => saveFeedback(i, f)} onCancel={() => setFeedbackOpen(null)} />
              )}

              {m.feedback && !feedbackOpen && (
                <div className="flex justify-start">
                  <div className="px-2 py-1 bg-green-50 border border-green-100 rounded-lg flex items-center gap-1">
                    <svg className="w-3 h-3 text-green-500 fill-current" viewBox="0 0 20 20"><path d="M9.049 2.927c.3-.921 1.603-.921 1.902 0l1.07 3.292a1 1 0 00.95.69h3.462c.969 0 1.371 1.24.588 1.81l-2.8 2.034a1 1 0 00-.364 1.118l1.07 3.292c.3.921-.755 1.688-1.54 1.118l-2.8-2.034a1 1 0 00-1.175 0l-2.8 2.034c-.784.57-1.838-.197-1.539-1.118l1.07-3.292a1 1 0 00-.364-1.118L2.98 8.72c-.783-.57-.38-1.81.588-1.81h3.461a1 1 0 00.951-.69l1.07-3.292z" /></svg>
                    <span className="text-[9px] font-bold text-green-600 uppercase tracking-widest">Feedback Saved</span>
                  </div>
                </div>
              )}
            </div>
          </div>
        ))}
        {isTyping && (
          <div className="flex justify-start">
            <div className="bg-white border border-slate-100 p-4 rounded-2xl shadow-sm flex gap-1">
              <div className="w-1.5 h-1.5 bg-indigo-400 rounded-full animate-bounce"></div>
              <div className="w-1.5 h-1.5 bg-indigo-400 rounded-full animate-bounce delay-75"></div>
              <div className="w-1.5 h-1.5 bg-indigo-400 rounded-full animate-bounce delay-150"></div>
            </div>
          </div>
        )}
      </div>

      <div className="p-6 bg-white border-t border-slate-200 shrink-0">
        <form onSubmit={handleSend} className="space-y-3">
          <div className="flex items-center justify-between mb-2">
            <div className="flex items-center gap-2">
              <span className={`text-[10px] font-bold uppercase tracking-widest transition-colors ${isListening ? 'text-indigo-600' : 'text-slate-400'}`}>
                {isListening ? 'Voice Input Active' : 'Keyboard Entry'}
              </span>
              {isListening && (
                <div className="flex gap-1">
                  <span className="w-1 h-1 bg-indigo-600 rounded-full animate-ping"></span>
                  <span className="w-1 h-1 bg-indigo-600 rounded-full animate-ping delay-75"></span>
                  <span className="w-1 h-1 bg-indigo-600 rounded-full animate-ping delay-150"></span>
                </div>
              )}
            </div>
            <button 
              type="button"
              onClick={() => {
                if (isListening) recognitionRef.current?.stop();
                else recognitionRef.current?.start();
              }}
              className={`flex items-center gap-2 px-3 py-1 rounded-full text-[10px] font-bold uppercase tracking-tight transition-all border ${
                isListening 
                  ? 'bg-red-50 border-red-200 text-red-600 animate-pulse shadow-sm' 
                  : 'bg-slate-100 border-slate-200 text-slate-500 hover:bg-slate-200'
              }`}
            >
              <svg className="w-3.5 h-3.5" fill="none" stroke="currentColor" viewBox="0 0 24 24">
                <path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M19 11a7 7 0 01-7 7m0 0a7 7 0 01-7-7m7 7v4m0 0H8m4 0h4m-4-8a3 3 0 01-3-3V5a3 3 0 116 0v6a3 3 0 01-3 3z" />
              </svg>
              {isListening ? 'Stop Listening' : 'Toggle Voice Input'}
            </button>
          </div>

          <div className="relative">
            <input
              type="text"
              value={inputValue}
              onChange={(e) => setInputValue(e.target.value)}
              disabled={isTyping}
              placeholder={isListening ? "I'm listening, speak clearly..." : "Type your response here..."}
              className={`w-full p-4 pr-16 bg-slate-50 rounded-2xl border outline-none transition-all text-sm font-medium ${
                isListening 
                  ? 'border-indigo-500 ring-4 ring-indigo-500/10 placeholder-indigo-400 text-indigo-700' 
