  const sourcesRef = useRef<Set<AudioBufferSourceNode>>(new Set());
  const analyserRef = useRef<AnalyserNode | null>(null);
  const animationFrameRef = useRef<number | null>(null);
  const scrollRef = useRef<HTMLDivElement>(null);

  const cleanup = useCallback(() => {
    if (sessionRef.current) sessionRef.current.close();
    if (audioContextRef.current) audioContextRef.current.close();
    if (outputContextRef.current) outputContextRef.current.close();
    if (animationFrameRef.current) cancelAnimationFrame(animationFrameRef.current);
    sourcesRef.current.forEach(s => s.stop());
    sourcesRef.current.clear();
  }, []);

  useEffect(() => {
    return cleanup;
  }, [cleanup]);

  useEffect(() => {
    if (scrollRef.current) {
      scrollRef.current.scrollTop = scrollRef.current.scrollHeight;
    }
  }, [history, currentOutput, currentInput]);

  const startSession = async () => {
    try {
      const ai = new GoogleGenAI({ apiKey: process.env.API_KEY || '' });

      audioContextRef.current = new (window.AudioContext || (window as any).webkitAudioContext)({ sampleRate: 16000 });
      outputContextRef.current = new (window.AudioContext || (window as any).webkitAudioContext)({ sampleRate: 24000 });

      const stream = await navigator.mediaDevices.getUserMedia({ audio: true });
      const source = audioContextRef.current.createMediaStreamSource(stream);
      const analyser = audioContextRef.current.createAnalyser();
      analyser.fftSize = 256;
      source.connect(analyser);
      analyserRef.current = analyser;

      const sessionPromise = ai.live.connect({
        model: 'gemini-2.5-flash-native-audio-preview-12-2025',
        config: {
          responseModalities: [Modality.AUDIO],
          systemInstruction: persona.systemInstruction + " Provide short, natural conversational turns. Use audio transcription to support the user experience.",
          speechConfig: {
            voiceConfig: { prebuiltVoiceConfig: { voiceName: 'Zephyr' } }
          },
          outputAudioTranscription: {},
          inputAudioTranscription: {}
        },
        callbacks: {
          onopen: () => {
            setIsConnected(true);
            setIsListening(true);

            const scriptProcessor = audioContextRef.current!.createScriptProcessor(4096, 1, 1);
            scriptProcessor.onaudioprocess = (e) => {
              const inputData = e.inputBuffer.getChannelData(0);
              const base64Pcm = createPcmBlob(inputData);
              sessionPromise.then(session => {
                session.sendRealtimeInput({ media: { data: base64Pcm, mimeType: 'audio/pcm;rate=16000' } });
              });
            };
            source.connect(scriptProcessor);
            scriptProcessor.connect(audioContextRef.current!.destination);

            drawVisualizer();
          },
          onmessage: async (message: LiveServerMessage) => {
            if (message.serverContent?.inputTranscription) {
              setCurrentInput(prev => prev + message.serverContent?.inputTranscription?.text);
            }
            if (message.serverContent?.outputTranscription) {
              setCurrentOutput(prev => prev + message.serverContent?.outputTranscription?.text);
            }
            if (message.serverContent?.turnComplete) {
              setHistory(prev => {
                const newHistory = [...prev];
                if (currentInput) newHistory.push({ role: 'user', text: currentInput });
                if (currentOutput) newHistory.push({ role: 'model', text: currentOutput });
                return newHistory;
              });
              setCurrentInput("");
              setCurrentOutput("");
            }

            const audioData = message.serverContent?.modelTurn?.parts[0]?.inlineData?.data;
            if (audioData && outputContextRef.current) {
              const ctx = outputContextRef.current;
              nextStartTimeRef.current = Math.max(nextStartTimeRef.current, ctx.currentTime);

              const buffer = await decodeAudioData(decode(audioData), ctx, 24000, 1);
              const sourceNode = ctx.createBufferSource();
              sourceNode.buffer = buffer;
              sourceNode.connect(ctx.destination);
              sourceNode.onended = () => sourcesRef.current.delete(sourceNode);
              sourceNode.start(nextStartTimeRef.current);
              nextStartTimeRef.current += buffer.duration;
              sourcesRef.current.add(sourceNode);
            }

            if (message.serverContent?.interrupted) {
              sourcesRef.current.forEach(s => s.stop());
              sourcesRef.current.clear();
              nextStartTimeRef.current = 0;
            }
          },
          onclose: () => setIsConnected(false),
          onerror: (e) => console.error("Live API Error:", e)
        }
      });

      sessionRef.current = await sessionPromise;
    } catch (err) {
      console.error("Failed to start voice session:", err);
    }
  };

  const saveFeedback = (index: number, feedback: Feedback) => {
    const updatedHistory = [...history];
    updatedHistory[index].feedback = feedback;
    setHistory(updatedHistory);
    setFeedbackIndex(null);

    const allFeedback = JSON.parse(localStorage.getItem('powertalk_feedback') || '[]');
    allFeedback.push({
      personaId: persona.id,
      messageText: history[index].text,
      ...feedback
    });
    localStorage.setItem('powertalk_feedback', JSON.stringify(allFeedback));
  };

  const drawVisualizer = () => {
    if (!canvasRef.current || !analyserRef.current) return;
    const canvas = canvasRef.current;
    const ctx = canvas.getContext('2d');
    if (!ctx) return;

    const bufferLength = analyserRef.current.frequencyBinCount;
    const dataArray = new Uint8Array(bufferLength);

    const render = () => {
      analyserRef.current!.getByteFrequencyData(dataArray);
      ctx.clearRect(0, 0, canvas.width, canvas.height);
      const barWidth = (canvas.width / bufferLength) * 2.5;
      let barHeight;
      let x = 0;
      for (let i = 0; i < bufferLength; i++) {
        barHeight = (dataArray[i] / 255) * canvas.height;
        ctx.fillStyle = `rgb(99, 102, 241)`;
        ctx.fillRect(x, canvas.height - barHeight, barWidth, barHeight);
        x += barWidth + 1;
      }
      animationFrameRef.current = requestAnimationFrame(render);
    };
    render();
  };

  return (
    <div className="flex flex-col h-full bg-slate-900 text-white rounded-3xl overflow-hidden shadow-2xl animate-in fade-in zoom-in duration-300">
      <div className="p-6 bg-slate-800 border-b border-slate-700 flex justify-between items-center shrink-0">
        <div className="flex items-center gap-4">
          <img src={persona.avatar} alt={persona.name} className="w-12 h-12 rounded-full border-2 border-indigo-500" />
          <div>
            <h2 className="text-xl font-bold">{persona.name}</h2>
            <p className="text-sm text-slate-400">{persona.title}</p>
          </div>
        </div>
        <button 
          onClick={onExit}
          className="bg-slate-700 hover:bg-slate-600 px-4 py-2 rounded-lg text-sm transition-colors font-bold"
        >
          Finish Session
        </button>
      </div>

      <div className="flex-grow flex flex-col items-center p-8 space-y-8 overflow-hidden">
        {!isConnected ? (
          <div className="text-center space-y-6 my-auto">
            <div className="w-24 h-24 bg-indigo-600 rounded-full flex items-center justify-center mx-auto animate-pulse">
               <svg className="w-12 h-12 text-white" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M19 11a7 7 0 01-7 7m0 0a7 7 0 01-7-7m7 7v4m0 0H8m4 0h4m-4-8a3 3 0 01-3-3V5a3 3 0 116 0v6a3 3 0 01-3 3z"></path></svg>
            </div>
            <h2 className="text-2xl font-bold text-slate-100">Ready to speak?</h2>
            <p className="text-slate-400 max-w-md mx-auto">This session uses real-time voice. Ensure you are in a quiet environment for best results.</p>
            <button 
              onClick={startSession}
              className="bg-indigo-600 hover:bg-indigo-500 text-white px-8 py-3 rounded-full font-bold text-lg transition-all transform hover:scale-105"
            >
              Start Microphone
            </button>
          </div>
        ) : (
          <div className="w-full max-w-2xl h-full flex flex-col space-y-6 overflow-hidden">
            <canvas ref={canvasRef} width={600} height={100} className="w-full rounded-xl opacity-80 shrink-0" />

            <div ref={scrollRef} className="flex-grow overflow-y-auto space-y-4 pr-2 custom-scrollbar">
              {history.map((turn, i) => (
                <div key={i} className={`flex flex-col ${turn.role === 'user' ? 'items-end' : 'items-start'}`}>
                  <div className={`p-4 rounded-2xl max-w-[85%] text-sm shadow-sm ${turn.role === 'user' ? 'bg-indigo-600 text-white rounded-tr-none' : 'bg-slate-800 text-slate-200 rounded-tl-none border border-slate-700'}`}>
                    <div className="flex justify-between items-center gap-4 mb-1">
                      <span className="text-[10px] font-bold uppercase tracking-widest opacity-50">{turn.role === 'user' ? 'You' : persona.name}</span>
                      {turn.role === 'model' && (
                        <button 
                          onClick={() => setFeedbackIndex(feedbackIndex === i ? null : i)}
                          className={`p-1 rounded-full transition-colors ${turn.feedback ? 'text-green-400 bg-green-400/10' : 'hover:bg-slate-700 text-slate-500'}`}
                        >
                          <svg className="w-3.5 h-3.5" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M11.049 2.927c.3-.921 1.603-.921 1.902 0l1.519 4.674a1 1 0 00.95.69h4.915c.969 0 1.371 1.24.588 1.81l-3.976 2.888a1 1 0 00-.363 1.118l1.518 4.674c.3.922-.755 1.688-1.54 1.118l-3.976-2.888a1 1 0 00-1.176 0l-3.976 2.888c-.784.57-1.838-.197-1.539-1.118l1.518-4.674a1 1 0 00-.363-1.118l-3.976-2.888c-.784-.57-.38-1.81.588-1.81h4.914a1 1 0 00.951-.69l1.519-4.674z" /></svg>
                        </button>
                      )}
                    </div>
                    <p className="leading-relaxed">{turn.text}</p>
                  </div>
                  {feedbackIndex === i && (
                    <div className="mt-2 w-full max-w-[85%]">
                      <FeedbackForm onSave={(f) => saveFeedback(i, f)} onCancel={() => setFeedbackIndex(null)} />
                    </div>
                  )}
                  {turn.feedback && !feedbackIndex && (
                    <span className="text-[9px] font-bold text-green-400 uppercase tracking-widest mt-1">✓ Feedback Recorded</span>
                  )}
                </div>
              ))}
              {(currentInput || currentOutput) && (
                <div className="space-y-4 opacity-70">
                  {currentInput && (
                    <div className="flex flex-col items-end animate-pulse">
                      <div className="bg-indigo-600/50 p-4 rounded-2xl rounded-tr-none text-sm text-white max-w-[85%]">
                        <p>{currentInput}</p>
                      </div>
                    </div>
                  )}
                  {currentOutput && (
                    <div className="flex flex-col items-start animate-pulse">
                      <div className="bg-slate-800 p-4 rounded-2xl rounded-tl-none text-sm text-slate-200 border border-slate-700 max-w-[85%]">
                        <p>{currentOutput}</p>
                      </div>
                    </div>
                  )}
                </div>
              )}
            </div>

            <div className="flex justify-center shrink-0">
              <div className="flex items-center gap-2 px-4 py-2 bg-indigo-600 rounded-full animate-pulse">
                <div className="w-2 h-2 bg-white rounded-full"></div>
                <span className="text-xs font-bold uppercase">Connection Active</span>
              </div>
            </div>
          </div>
        )}
      </div>

      <div className="p-4 bg-slate-900 text-center text-[10px] text-slate-500 uppercase tracking-widest shrink-0 border-t border-slate-800">
        Real-time Professional Simulation • Review and rate turns anytime
      </div>
      <style>{`
        .custom-scrollbar::-webkit-scrollbar { width: 4px; }
        .custom-scrollbar::-webkit-scrollbar-track { background: transparent; }
        .custom-scrollbar::-webkit-scrollbar-thumb { background: #334155; border-radius: 10px; }
      `}</style>
    </div>
  );
};

export enum PersonaType {
  ADVISOR = 'ADVISOR',
  DEAN = 'DEAN',
  HIRING_MANAGER = 'HIRING_MANAGER',
  GRANT_REVIEWER = 'GRANT_REVIEWER',
  COMMITTEE_CHAIR = 'COMMITTEE_CHAIR',
  PEER_COLLABORATOR = 'PEER_COLLABORATOR'
}

export interface Scenario {
  id: string;
  title: string;
  context: string;
  systemPrompt: string;
}

export interface Persona {
  id: PersonaType;
  name: string;
  title: string;
  description: string;
  goal: string;
  systemInstruction: string;
  avatar: string;
  voiceName: 'Kore' | 'Puck' | 'Charon' | 'Fenrir' | 'Zephyr';
  scenarios: Scenario[];
}

export interface Message {
  role: 'user' | 'model';
  text: string;
  timestamp: number;
  feedback?: Feedback;
}

export interface Feedback {
  rating: number; // 1-5
  clarity: boolean;
  relevance: boolean;
  helpfulness: boolean;
  comments: string;
  timestamp: number;
}

export interface SessionState {
  isActive: boolean;
  mode: 'text' | 'voice';
  persona: Persona | null;
  scenario: Scenario | null;
}

