import React, { useState, useEffect, useRef } from 'react';
import { GoogleGenAI, Chat, Modality } from '@google/genai';
import { Persona, Message, Feedback, Scenario } from '../types';
import { decode, decodeAudioData } from '../services/audioUtils';
import { FeedbackForm } from './FeedbackForm';

interface TextModeProps {
  persona: Persona;
  scenario: Scenario;
  onExit: () => void;
}

export const TextMode: React.FC<TextModeProps> = ({ persona, scenario, onExit }) => {
  const [messages, setMessages] = useState<Message[]>([]);
  const [inputValue, setInputValue] = useState("");
  const [isTyping, setIsTyping] = useState(false);
  const [isSpeaking, setIsSpeaking] = useState<number | null>(null);
  const [isListening, setIsListening] = useState(false);
  const [feedbackOpen, setFeedbackOpen] = useState<number | null>(null);

  const chatRef = useRef<Chat | null>(null);
  const scrollRef = useRef<HTMLDivElement>(null);
  const audioContextRef = useRef<AudioContext | null>(null);
  const recognitionRef = useRef<any>(null);

  useEffect(() => {
    const ai = new GoogleGenAI({ apiKey: process.env.API_KEY || '' });
    chatRef.current = ai.chats.create({
      model: 'gemini-3-flash-preview',
      config: {
        systemInstruction: `You are ${persona.name}, ${persona.title}. ${persona.systemInstruction} Current Situation: ${scenario.systemPrompt} Respond with concise, realistic professional turns.`
      }
    });

    const greet = async () => {
      setIsTyping(true);
      try {
        const result = await chatRef.current!.sendMessage({ message: `Start the meeting professionally according to this scenario: ${scenario.title}.` });
        const text = result.text || "";
        setMessages([{ role: 'model', text, timestamp: Date.now() }]);
        playTTS(text, 0);
      } catch (err) {
        console.error(err);
      } finally {
        setIsTyping(false);
      }
    };
    greet();

    const SpeechRecognition = (window as any).SpeechRecognition || (window as any).webkitSpeechRecognition;
    if (SpeechRecognition) {
      recognitionRef.current = new SpeechRecognition();
      recognitionRef.current.continuous = false; 
      recognitionRef.current.interimResults = true;
      recognitionRef.current.lang = 'en-US';
      recognitionRef.current.onresult = (event: any) => {
        const transcript = Array.from(event.results)
          .map((result: any) => result[0])
          .map((result: any) => result.transcript)
          .join('');
        setInputValue(transcript);
      };
      recognitionRef.current.onstart = () => setIsListening(true);
      recognitionRef.current.onend = () => setIsListening(false);
    }

    return () => {
      if (audioContextRef.current) audioContextRef.current.close();
      if (recognitionRef.current) recognitionRef.current.stop();
    };
  }, [persona, scenario]);

  const playTTS = async (text: string, index: number) => {
    setIsSpeaking(index);
    try {
      const ai = new GoogleGenAI({ apiKey: process.env.API_KEY || '' });
      const response = await ai.models.generateContent({
        model: "gemini-2.5-flash-preview-tts",
        contents: [{ parts: [{ text }] }],
        config: {
          responseModalities: [Modality.AUDIO],
          speechConfig: {
            voiceConfig: { prebuiltVoiceConfig: { voiceName: persona.voiceName } },
          },
        },
      });

      const audioData = response.candidates?.[0]?.content?.parts?.[0]?.inlineData?.data;
      if (audioData) {
        if (!audioContextRef.current) {
          audioContextRef.current = new (window.AudioContext || (window as any).webkitAudioContext)({ sampleRate: 24000 });
        }
        const buffer = await decodeAudioData(decode(audioData), audioContextRef.current, 24000, 1);
        const source = audioContextRef.current.createBufferSource();
        source.buffer = buffer;
        source.connect(audioContextRef.current.destination);
        source.onended = () => setIsSpeaking(null);
        source.start();
      }
    } catch (err) {
      console.error("TTS Error:", err);
      setIsSpeaking(null);
    }
  };

  const saveFeedback = (index: number, feedback: Feedback) => {
    const updatedMessages = [...messages];
    updatedMessages[index].feedback = feedback;
    setMessages(updatedMessages);
    setFeedbackOpen(null);

    const allFeedback = JSON.parse(localStorage.getItem('powertalk_feedback') || '[]');
    allFeedback.push({
      personaId: persona.id,
      scenarioId: scenario.id,
      messageText: messages[index].text,
      ...feedback
    });
    localStorage.setItem('powertalk_feedback', JSON.stringify(allFeedback));
  };

  const handleSend = async (e?: React.FormEvent) => {
    e?.preventDefault();
    if (!inputValue.trim() || isTyping || !chatRef.current) return;

    const textToSend = inputValue;
    const userMessage: Message = { role: 'user', text: textToSend, timestamp: Date.now() };
    setMessages(prev => [...prev, userMessage]);
    setInputValue("");
    setIsTyping(true);

    try {
      const result = await chatRef.current.sendMessage({ message: textToSend });
      const responseText = result.text || "";
      const newMessageIndex = messages.length + 1;
      setMessages(prev => [...prev, { role: 'model', text: responseText, timestamp: Date.now() }]);
      playTTS(responseText, newMessageIndex);
    } catch (err) {
      console.error(err);
    } finally {
      setIsTyping(false);
    }
  };

  useEffect(() => {
    if (scrollRef.current) {
      scrollRef.current.scrollTop = scrollRef.current.scrollHeight;
    }
  }, [messages, isTyping, feedbackOpen]);

  return (
    <div className="flex flex-col h-full bg-white rounded-3xl overflow-hidden shadow-2xl border border-slate-200">
      <div className="p-6 bg-slate-50 border-b border-slate-200 flex justify-between items-center shrink-0">
        <div className="flex items-center gap-4">
          <img src={persona.avatar} alt={persona.name} className="w-12 h-12 rounded-full border-2 border-white shadow-md" />
          <div>
            <h2 className="text-lg font-bold text-slate-800">{persona.name}</h2>
            <p className="text-[10px] font-bold text-indigo-600 uppercase tracking-widest">{scenario.title}</p>
          </div>
        </div>
        <button onClick={onExit} className="text-slate-400 hover:text-slate-600 font-medium text-sm transition-colors">End Practice</button>
      </div>

      <div ref={scrollRef} className="flex-grow p-6 overflow-y-auto space-y-6 bg-slate-50/30">
        {messages.map((m, i) => (
          <div key={i} className={`flex items-start gap-3 ${m.role === 'user' ? 'flex-row-reverse' : 'flex-row'}`}>
            <div className={`max-w-[80%] space-y-2 ${m.role === 'user' ? 'text-right' : ''}`}>
              <div className={`p-4 rounded-2xl shadow-sm text-sm ${
                m.role === 'user' ? 'bg-indigo-600 text-white rounded-tr-none' : 'bg-white text-slate-800 rounded-tl-none border border-slate-100'
              }`}>
                <div className="flex justify-between items-start gap-4 mb-1">
                  <span className="text-[10px] opacity-60 uppercase font-bold tracking-widest">{m.role === 'user' ? 'You' : persona.name}</span>
                  {m.role === 'model' && (
                    <div className="flex gap-2">
                      <button onClick={() => playTTS(m.text, i)} className={`p-1 rounded-full ${isSpeaking === i ? 'bg-indigo-100 text-indigo-600' : 'text-slate-400 hover:text-indigo-600'}`}>
                        <svg className={`w-3.5 h-3.5 ${isSpeaking === i ? 'animate-pulse' : ''}`} fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M15.536 8.464a5 5 0 010 7.072m2.828-9.9a9 9 0 010 12.728M5.586 15H4a1 1 0 01-1-1v-4a1 1 0 011-1h1.586l4.707-4.707C10.923 3.663 12 4.109 12 5v14c0 .891-1.077 1.337-1.707.707L5.586 15z"/></svg>
                      </button>
                      <button onClick={() => setFeedbackOpen(feedbackOpen === i ? null : i)} className={`p-1 rounded-full ${m.feedback ? 'text-green-600' : 'text-slate-400 hover:text-amber-500'}`}>
                        <svg className="w-3.5 h-3.5" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M11.049 2.927c.3-.921 1.603-.921 1.902 0l1.519 4.674a1 1 0 00.95.69h4.915c.969 0 1.371 1.24.588 1.81l-3.976 2.888a1 1 0 00-.363 1.118l1.518 4.674c.3.922-.755 1.688-1.54 1.118l-3.976-2.888a1 1 0 00-1.176 0l-3.976 2.888c-.784.57-1.838-.197-1.539-1.118l1.518-4.674a1 1 0 00-.363-1.118l-3.976-2.888c-.784-.57-.38-1.81.588-1.81h4.914a1 1 0 00.951-.69l1.519-4.674z"/></svg>
                      </button>
                    </div>
                  )}
                </div>
                <p className="leading-relaxed text-left">{m.text}</p>
              </div>
              {feedbackOpen === i && <FeedbackForm onSave={(f) => saveFeedback(i, f)} onCancel={() => setFeedbackOpen(null)} />}
              {m.feedback && !feedbackOpen && <div className="text-[9px] font-bold text-green-500 uppercase flex items-center gap-1 justify-start ml-2"><span className="w-1 h-1 bg-green-500 rounded-full"></span> Feedback Saved</div>}
            </div>
          </div>
        ))}
        {isTyping && (
          <div className="flex justify-start">
            <div className="bg-white border border-slate-100 p-4 rounded-2xl shadow-sm flex gap-1">
              <div className="w-1.5 h-1.5 bg-indigo-400 rounded-full animate-bounce"></div>
              <div className="w-1.5 h-1.5 bg-indigo-400 rounded-full animate-bounce delay-75"></div>
              <div className="w-1.5 h-1.5 bg-indigo-400 rounded-full animate-bounce delay-150"></div>
            </div>
          </div>
        )}
      </div>

      <div className="p-6 bg-white border-t border-slate-200 shrink-0">
        <form onSubmit={handleSend} className="space-y-3">
          <div className="flex items-center justify-between mb-2">
            <div className="flex items-center gap-2">
              <span className={`text-[10px] font-bold uppercase tracking-widest transition-colors ${isListening ? 'text-indigo-600' : 'text-slate-400'}`}>
                {isListening ? 'Voice Input Active' : 'Keyboard Entry'}
              </span>
            </div>
            <button 
              type="button"
              onClick={() => isListening ? recognitionRef.current?.stop() : recognitionRef.current?.start()}
              className={`flex items-center gap-2 px-3 py-1 rounded-full text-[10px] font-bold uppercase tracking-tight transition-all border ${
                isListening ? 'bg-red-50 border-red-200 text-red-600 animate-pulse shadow-sm' : 'bg-slate-100 border-slate-200 text-slate-500 hover:bg-slate-200'
              }`}
            >
              <svg className="w-3.5 h-3.5" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M19 11a7 7 0 01-7 7m0 0a7 7 0 01-7-7m7 7v4m0 0H8m4 0h4m-4-8a3 3 0 01-3-3V5a3 3 0 116 0v6a3 3 0 01-3 3z"/></svg>
              {isListening ? 'Stop' : 'Dictate Response'}
            </button>
          </div>
          <div className="relative">
            <input
              type="text"
              value={inputValue}
              onChange={(e) => setInputValue(e.target.value)}
              disabled={isTyping}
              placeholder={isListening ? "Listening..." : "Type your professional response..."}
              className={`w-full p-4 pr-16 bg-slate-50 rounded-2xl border outline-none transition-all text-sm font-medium ${isListening ? 'border-indigo-500 ring-4 ring-indigo-500/10' : 'border-slate-200 focus:border-indigo-300'}`}
            />
            <button type="submit" disabled={!inputValue.trim() || isTyping} className="absolute right-2 top-2 bottom-2 bg-indigo-600 hover:bg-indigo-700 disabled:bg-slate-300 text-white px-4 rounded-xl shadow-lg shadow-indigo-600/20 transition-all">
              <svg className="w-5 h-5" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M5 13l4 4L19 7"/></svg>
            </button>
          </div>
        </form>
      </div>
    </div>
  );
};

import React, { useEffect, useRef, useState, useCallback } from 'react';
import { GoogleGenAI, Modality, LiveServerMessage } from '@google/genai';
import { Persona, Feedback, Scenario } from '../types';
import { decode, decodeAudioData, createPcmBlob } from '../services/audioUtils';
import { FeedbackForm } from './FeedbackForm';

interface VoiceTurn {
  role: 'user' | 'model';
  text: string;
  feedback?: Feedback;
}

interface VoiceModeProps {
  persona: Persona;
  scenario: Scenario;
  onExit: () => void;
}

export const VoiceMode: React.FC<VoiceModeProps> = ({ persona, scenario, onExit }) => {
  const [isConnected, setIsConnected] = useState(false);
  const [isListening, setIsListening] = useState(false);
  const [history, setHistory] = useState<VoiceTurn[]>([]);
  const [currentInput, setCurrentInput] = useState("");
  const [currentOutput, setCurrentOutput] = useState("");
  const [feedbackIndex, setFeedbackIndex] = useState<number | null>(null);

  const canvasRef = useRef<HTMLCanvasElement>(null);
  const sessionRef = useRef<any>(null);
  const audioContextRef = useRef<AudioContext | null>(null);
  const outputContextRef = useRef<AudioContext | null>(null);
  const nextStartTimeRef = useRef<number>(0);
  const sourcesRef = useRef<Set<AudioBufferSourceNode>>(new Set());
  const analyserRef = useRef<AnalyserNode | null>(null);
  const animationFrameRef = useRef<number | null>(null);
  const scrollRef = useRef<HTMLDivElement>(null);

  const cleanup = useCallback(() => {
    if (sessionRef.current) sessionRef.current.close();
    if (audioContextRef.current) audioContextRef.current.close();
    if (outputContextRef.current) outputContextRef.current.close();
    if (animationFrameRef.current) cancelAnimationFrame(animationFrameRef.current);
    sourcesRef.current.forEach(s => s.stop());
    sourcesRef.current.clear();
  }, []);

  useEffect(() => {
    return cleanup;
  }, [cleanup]);

  useEffect(() => {
    if (scrollRef.current) {
      scrollRef.current.scrollTop = scrollRef.current.scrollHeight;
    }
  }, [history, currentOutput, currentInput]);

  const startSession = async () => {
    try {
      const ai = new GoogleGenAI({ apiKey: process.env.API_KEY || '' });

      audioContextRef.current = new (window.AudioContext || (window as any).webkitAudioContext)({ sampleRate: 16000 });
      outputContextRef.current = new (window.AudioContext || (window as any).webkitAudioContext)({ sampleRate: 24000 });

      const stream = await navigator.mediaDevices.getUserMedia({ audio: true });
      const source = audioContextRef.current.createMediaStreamSource(stream);
      const analyser = audioContextRef.current.createAnalyser();
      analyser.fftSize = 256;
      source.connect(analyser);
      analyserRef.current = analyser;

      const sessionPromise = ai.live.connect({
        model: 'gemini-2.5-flash-native-audio-preview-12-2025',
        config: {
          responseModalities: [Modality.AUDIO],
          systemInstruction: `${persona.systemInstruction} Current Situation: ${scenario.systemPrompt}. Start by greeting the student in character for this specific scenario.`,
          speechConfig: {
            voiceConfig: { prebuiltVoiceConfig: { voiceName: 'Zephyr' } }
          },
          outputAudioTranscription: {},
          inputAudioTranscription: {}
        },
        callbacks: {
          onopen: () => {
            setIsConnected(true);
            setIsListening(true);
            const scriptProcessor = audioContextRef.current!.createScriptProcessor(4096, 1, 1);
            scriptProcessor.onaudioprocess = (e) => {
              const inputData = e.inputBuffer.getChannelData(0);
              const base64Pcm = createPcmBlob(inputData);
              sessionPromise.then(session => {
                session.sendRealtimeInput({ media: { data: base64Pcm, mimeType: 'audio/pcm;rate=16000' } });
              });
            };
            source.connect(scriptProcessor);
            scriptProcessor.connect(audioContextRef.current!.destination);
            drawVisualizer();
          },
          onmessage: async (message: LiveServerMessage) => {
            if (message.serverContent?.inputTranscription) {
              setCurrentInput(prev => prev + message.serverContent?.inputTranscription?.text);
            }
            if (message.serverContent?.outputTranscription) {
              setCurrentOutput(prev => prev + message.serverContent?.outputTranscription?.text);
            }
            if (message.serverContent?.turnComplete) {
              setHistory(prev => {
                const newHistory = [...prev];
                if (currentInput) newHistory.push({ role: 'user', text: currentInput });
                if (currentOutput) newHistory.push({ role: 'model', text: currentOutput });
                return newHistory;
              });
              setCurrentInput("");
              setCurrentOutput("");
            }
            const audioData = message.serverContent?.modelTurn?.parts[0]?.inlineData?.data;
            if (audioData && outputContextRef.current) {
              const ctx = outputContextRef.current;
              nextStartTimeRef.current = Math.max(nextStartTimeRef.current, ctx.currentTime);
              const buffer = await decodeAudioData(decode(audioData), ctx, 24000, 1);
              const sourceNode = ctx.createBufferSource();
              sourceNode.buffer = buffer;
              sourceNode.connect(ctx.destination);
              sourceNode.onended = () => sourcesRef.current.delete(sourceNode);
              sourceNode.start(nextStartTimeRef.current);
              nextStartTimeRef.current += buffer.duration;
              sourcesRef.current.add(sourceNode);
            }
            if (message.serverContent?.interrupted) {
              sourcesRef.current.forEach(s => s.stop());
              sourcesRef.current.clear();
              nextStartTimeRef.current = 0;
            }
          },
          onclose: () => setIsConnected(false),
          onerror: (e) => console.error("Live API Error:", e)
        }
      });
      sessionRef.current = await sessionPromise;
    } catch (err) {
      console.error("Failed to start voice session:", err);
    }
  };

  const saveFeedback = (index: number, feedback: Feedback) => {
    const updatedHistory = [...history];
    updatedHistory[index].feedback = feedback;
    setHistory(updatedHistory);
    setFeedbackIndex(null);
    const allFeedback = JSON.parse(localStorage.getItem('powertalk_feedback') || '[]');
    allFeedback.push({
      personaId: persona.id,
      scenarioId: scenario.id,
      messageText: history[index].text,
      ...feedback
    });
    localStorage.setItem('powertalk_feedback', JSON.stringify(allFeedback));
  };

  const drawVisualizer = () => {
    if (!canvasRef.current || !analyserRef.current) return;
    const canvas = canvasRef.current;
    const ctx = canvas.getContext('2d');
    if (!ctx) return;
    const bufferLength = analyserRef.current.frequencyBinCount;
    const dataArray = new Uint8Array(bufferLength);
    const render = () => {
      analyserRef.current!.getByteFrequencyData(dataArray);
      ctx.clearRect(0, 0, canvas.width, canvas.height);
      const barWidth = (canvas.width / bufferLength) * 2.5;
      let x = 0;
      for (let i = 0; i < bufferLength; i++) {
        const barHeight = (dataArray[i] / 255) * canvas.height;
        ctx.fillStyle = `rgb(99, 102, 241)`;
        ctx.fillRect(x, canvas.height - barHeight, barWidth, barHeight);
        x += barWidth + 1;
      }
      animationFrameRef.current = requestAnimationFrame(render);
    };
    render();
  };

  return (
    <div className="flex flex-col h-full bg-slate-900 text-white rounded-3xl overflow-hidden shadow-2xl animate-in fade-in zoom-in duration-300">
      <div className="p-6 bg-slate-800 border-b border-slate-700 flex justify-between items-center shrink-0">
        <div className="flex items-center gap-4">
          <img src={persona.avatar} alt={persona.name} className="w-12 h-12 rounded-full border-2 border-indigo-500" />
          <div>
            <h2 className="text-xl font-bold">{persona.name}</h2>
            <p className="text-xs text-indigo-400 font-bold uppercase tracking-widest">{scenario.title}</p>
          </div>
        </div>
        <button onClick={onExit} className="bg-slate-700 hover:bg-slate-600 px-4 py-2 rounded-lg text-sm transition-colors font-bold">End</button>
      </div>

      <div className="flex-grow flex flex-col items-center p-8 space-y-6 overflow-hidden">
        {!isConnected ? (
          <div className="text-center space-y-6 my-auto">
            <div className="w-24 h-24 bg-indigo-600 rounded-full flex items-center justify-center mx-auto animate-pulse">
               <svg className="w-12 h-12 text-white" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M19 11a7 7 0 01-7 7m0 0a7 7 0 01-7-7m7 7v4m0 0H8m4 0h4m-4-8a3 3 0 01-3-3V5a3 3 0 116 0v6a3 3 0 01-3 3z"></path></svg>
            </div>
            <h2 className="text-2xl font-bold text-slate-100">Speak into character</h2>
            <p className="text-slate-400 max-w-sm mx-auto text-sm">{scenario.context}</p>
            <button onClick={startSession} className="bg-indigo-600 hover:bg-indigo-500 text-white px-10 py-4 rounded-full font-bold text-lg shadow-xl shadow-indigo-600/30 transition-all transform hover:scale-105">Start Meeting</button>
          </div>
        ) : (
          <div className="w-full max-w-2xl h-full flex flex-col space-y-6 overflow-hidden">
            <canvas ref={canvasRef} width={600} height={80} className="w-full rounded-xl opacity-80 shrink-0" />
            <div ref={scrollRef} className="flex-grow overflow-y-auto space-y-4 pr-2 custom-scrollbar">
              {history.map((turn, i) => (
                <div key={i} className={`flex flex-col ${turn.role === 'user' ? 'items-end' : 'items-start'}`}>
                  <div className={`p-4 rounded-2xl max-w-[85%] text-sm shadow-sm ${turn.role === 'user' ? 'bg-indigo-600 text-white rounded-tr-none' : 'bg-slate-800 text-slate-200 rounded-tl-none border border-slate-700'}`}>
                    <div className="flex justify-between items-center gap-4 mb-1">
                      <span className="text-[10px] font-bold uppercase tracking-widest opacity-50">{turn.role === 'user' ? 'You' : persona.name}</span>
                      {turn.role === 'model' && (
                        <button onClick={() => setFeedbackIndex(feedbackIndex === i ? null : i)} className={`p-1 rounded-full ${turn.feedback ? 'text-green-400 bg-green-400/10' : 'hover:bg-slate-700 text-slate-500'}`}>
                          <svg className="w-3.5 h-3.5" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M11.049 2.927c.3-.921 1.603-.921 1.902 0l1.519 4.674a1 1 0 00.95.69h4.915c.969 0 1.371 1.24.588 1.81l-3.976 2.888a1 1 0 00-.363 1.118l1.518 4.674c.3.922-.755 1.688-1.54 1.118l-3.976-2.888a1 1 0 00-1.176 0l-3.976 2.888c-.784.57-1.838-.197-1.539-1.118l1.518-4.674a1 1 0 00-.363-1.118l-3.976-2.888c-.784-.57-.38-1.81.588-1.81h4.914a1 1 0 00.951-.69l1.519-4.674z"/></svg>
                        </button>
                      )}
                    </div>
                    <p className="leading-relaxed">{turn.text}</p>
                  </div>
                  {feedbackIndex === i && <div className="mt-2 w-full max-w-[85%]"><FeedbackForm onSave={(f) => saveFeedback(i, f)} onCancel={() => setFeedbackIndex(null)} /></div>}
                  {turn.feedback && !feedbackIndex && <span className="text-[9px] font-bold text-green-400 uppercase mt-1 tracking-widest">Feedback Saved</span>}
                </div>
              ))}
              {(currentInput || currentOutput) && (
                <div className="space-y-4 opacity-70 italic text-slate-400 text-xs">
                  {currentInput && <div className="text-right">You: {currentInput}</div>}
                  {currentOutput && <div className="text-left">{persona.name}: {currentOutput}</div>}
                </div>
              )}
            </div>
            <div className="flex justify-center shrink-0">
               <div className="px-4 py-2 bg-indigo-500/20 text-indigo-300 rounded-full text-[10px] font-bold uppercase tracking-widest border border-indigo-500/30 animate-pulse">Live Simulation Active</div>
            </div>
          </div>
        )}
      </div>
      <style>{`.custom-scrollbar::-webkit-scrollbar { width: 4px; } .custom-scrollbar::-webkit-scrollbar-track { background: transparent; } .custom-scrollbar::-webkit-scrollbar-thumb { background: #334155; border-radius: 10px; }`}</style>
    </div>
  );
};

import React, { useState, useEffect, useRef } from 'react';
import { GoogleGenAI, Chat, Modality } from '@google/genai';
import { Persona, Message, Feedback, Scenario } from '../types';
import { decode, decodeAudioData } from '../services/audioUtils';
import { FeedbackForm } from './FeedbackForm';

interface TextModeProps {
  persona: Persona;
  scenario: Scenario;
  onExit: () => void;
}

export const TextMode: React.FC<TextModeProps> = ({ persona, scenario, onExit }) => {
  const [messages, setMessages] = useState<Message[]>([]);
  const [inputValue, setInputValue] = useState("");
  const [isTyping, setIsTyping] = useState(false);
  const [isSpeaking, setIsSpeaking] = useState<number | null>(null);
  const [isListening, setIsListening] = useState(false);
  const [feedbackOpen, setFeedbackOpen] = useState<number | null>(null);
  const [showBriefing, setShowBriefing] = useState(true);

  const chatRef = useRef<Chat | null>(null);
  const scrollRef = useRef<HTMLDivElement>(null);
  const audioContextRef = useRef<AudioContext | null>(null);
  const recognitionRef = useRef<any>(null);

  useEffect(() => {
    const ai = new GoogleGenAI({ apiKey: process.env.API_KEY || '' });
    chatRef.current = ai.chats.create({
      model: 'gemini-3-flash-preview',
      config: {
        systemInstruction: `You are ${persona.name}, ${persona.title}. ${persona.systemInstruction} Current Situation: ${scenario.systemPrompt} Respond with concise, realistic professional turns.`
      }
    });

    const greet = async () => {
      setIsTyping(true);
      try {
        const result = await chatRef.current!.sendMessage({ message: `Start the meeting professionally according to this scenario: ${scenario.title}.` });
        const text = result.text || "";
        setMessages([{ role: 'model', text, timestamp: Date.now() }]);
        playTTS(text, 0);
      } catch (err) {
        console.error(err);
      } finally {
        setIsTyping(false);
      }
    };
    greet();

    const SpeechRecognition = (window as any).SpeechRecognition || (window as any).webkitSpeechRecognition;
    if (SpeechRecognition) {
      recognitionRef.current = new SpeechRecognition();
      recognitionRef.current.continuous = false; 
      recognitionRef.current.interimResults = true;
      recognitionRef.current.lang = 'en-US';
      recognitionRef.current.onresult = (event: any) => {
        const transcript = Array.from(event.results)
          .map((result: any) => result[0])
          .map((result: any) => result.transcript)
          .join('');
        setInputValue(transcript);
      };
      recognitionRef.current.onstart = () => setIsListening(true);
      recognitionRef.current.onend = () => setIsListening(false);
    }

    return () => {
      if (audioContextRef.current) audioContextRef.current.close();
      if (recognitionRef.current) recognitionRef.current.stop();
    };
  }, [persona, scenario]);

  const playTTS = async (text: string, index: number) => {
    setIsSpeaking(index);
    try {
      const ai = new GoogleGenAI({ apiKey: process.env.API_KEY || '' });
      const response = await ai.models.generateContent({
        model: "gemini-2.5-flash-preview-tts",
        contents: [{ parts: [{ text }] }],
        config: {
          responseModalities: [Modality.AUDIO],
          speechConfig: {
            voiceConfig: { prebuiltVoiceConfig: { voiceName: persona.voiceName } },
          },
        },
      });

      const audioData = response.candidates?.[0]?.content?.parts?.[0]?.inlineData?.data;
      if (audioData) {
        if (!audioContextRef.current) {
          audioContextRef.current = new (window.AudioContext || (window as any).webkitAudioContext)({ sampleRate: 24000 });
        }
        const buffer = await decodeAudioData(decode(audioData), audioContextRef.current, 24000, 1);
        const source = audioContextRef.current.createBufferSource();
        source.buffer = buffer;
        source.connect(audioContextRef.current.destination);
        source.onended = () => setIsSpeaking(null);
        source.start();
      }
    } catch (err) {
      console.error("TTS Error:", err);
      setIsSpeaking(null);
    }
  };

  const saveFeedback = (index: number, feedback: Feedback) => {
    const updatedMessages = [...messages];
    updatedMessages[index].feedback = feedback;
    setMessages(updatedMessages);
    setFeedbackOpen(null);

    const allFeedback = JSON.parse(localStorage.getItem('powertalk_feedback') || '[]');
    allFeedback.push({
      personaId: persona.id,
      scenarioId: scenario.id,
      messageText: messages[index].text,
      ...feedback
    });
    localStorage.setItem('powertalk_feedback', JSON.stringify(allFeedback));
  };

  const handleSend = async (e?: React.FormEvent) => {
    e?.preventDefault();
    if (!inputValue.trim() || isTyping || !chatRef.current) return;

    const textToSend = inputValue;
    const userMessage: Message = { role: 'user', text: textToSend, timestamp: Date.now() };
    setMessages(prev => [...prev, userMessage]);
    setInputValue("");
    setIsTyping(true);

    try {
      const result = await chatRef.current.sendMessage({ message: textToSend });
      const responseText = result.text || "";
      const newMessageIndex = messages.length + 1;
      setMessages(prev => [...prev, { role: 'model', text: responseText, timestamp: Date.now() }]);
      playTTS(responseText, newMessageIndex);
    } catch (err) {
      console.error(err);
    } finally {
      setIsTyping(false);
    }
  };

  useEffect(() => {
    if (scrollRef.current) {
      scrollRef.current.scrollTop = scrollRef.current.scrollHeight;
    }
  }, [messages, isTyping, feedbackOpen]);

  return (
    <div className="flex flex-col h-full bg-white rounded-3xl overflow-hidden shadow-2xl border border-slate-200">
      <div className="p-6 bg-slate-50 border-b border-slate-200 flex justify-between items-center shrink-0">
        <div className="flex items-center gap-4">
          <img src={persona.avatar} alt={persona.name} className="w-12 h-12 rounded-full border-2 border-white shadow-md" />
          <div>
            <h2 className="text-lg font-bold text-slate-800">{persona.name}</h2>
            <p className="text-[10px] font-bold text-indigo-600 uppercase tracking-widest">{scenario.title}</p>
          </div>
        </div>
        <button onClick={onExit} className="text-slate-400 hover:text-slate-600 font-medium text-sm transition-colors">End Practice</button>
      </div>

      <div ref={scrollRef} className="flex-grow p-6 overflow-y-auto space-y-6 bg-slate-50/30">
        {/* Scenario Briefing Section */}
        {showBriefing && (
          <div className="mb-8 p-6 bg-indigo-50/50 border border-indigo-100 rounded-2xl relative group animate-in fade-in slide-in-from-top-4 duration-500">
            <button 
              onClick={() => setShowBriefing(false)} 
              className="absolute top-4 right-4 text-indigo-300 hover:text-indigo-500 transition-colors"
              title="Dismiss Briefing"
            >
              <svg className="w-4 h-4" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M6 18L18 6M6 6l12 12" /></svg>
            </button>
            <div className="flex items-center gap-2 mb-3 text-indigo-600">
              <div className="p-1.5 bg-indigo-100 rounded-lg">
                <svg className="w-4 h-4" fill="none" stroke="currentColor" viewBox="0 0 24 24">
                  <path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M13 16h-1v-4h-1m1-4h.01M21 12a9 9 0 11-18 0 9 9 0 0118 0z" />
                </svg>
              </div>
              <span className="text-[10px] font-bold uppercase tracking-widest">Active Scenario Briefing</span>
            </div>
            <p className="text-slate-700 text-sm leading-relaxed italic pr-8">
              "{scenario.context}"
            </p>
          </div>
        )}

        {messages.map((m, i) => (
          <div key={i} className={`flex items-start gap-3 ${m.role === 'user' ? 'flex-row-reverse' : 'flex-row'}`}>
            <div className={`max-w-[80%] space-y-2 ${m.role === 'user' ? 'text-right' : ''}`}>
              <div className={`p-4 rounded-2xl shadow-sm text-sm ${
                m.role === 'user' ? 'bg-indigo-600 text-white rounded-tr-none' : 'bg-white text-slate-800 rounded-tl-none border border-slate-100'
              }`}>
                <div className="flex justify-between items-start gap-4 mb-1">
                  <span className="text-[10px] opacity-60 uppercase font-bold tracking-widest">{m.role === 'user' ? 'You' : persona.name}</span>
                  {m.role === 'model' && (
                    <div className="flex gap-2">
                      <button onClick={() => playTTS(m.text, i)} className={`p-1 rounded-full ${isSpeaking === i ? 'bg-indigo-100 text-indigo-600' : 'text-slate-400 hover:text-indigo-600'}`}>
                        <svg className={`w-3.5 h-3.5 ${isSpeaking === i ? 'animate-pulse' : ''}`} fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M15.536 8.464a5 5 0 010 7.072m2.828-9.9a9 9 0 010 12.728M5.586 15H4a1 1 0 01-1-1v-4a1 1 0 011-1h1.586l4.707-4.707C10.923 3.663 12 4.109 12 5v14c0 .891-1.077 1.337-1.707.707L5.586 15z"/></svg>
                      </button>
                      <button onClick={() => setFeedbackOpen(feedbackOpen === i ? null : i)} className={`p-1 rounded-full ${m.feedback ? 'text-green-600' : 'text-slate-400 hover:text-amber-500'}`}>
                        <svg className="w-3.5 h-3.5" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M11.049 2.927c.3-.921 1.603-.921 1.902 0l1.519 4.674a1 1 0 00.95.69h4.915c.969 0 1.371 1.24.588 1.81l-3.976 2.888a1 1 0 00-.363 1.118l1.518 4.674c.3.922-.755 1.688-1.54 1.118l-3.976-2.888a1 1 0 00-1.176 0l-3.976 2.888c-.784.57-1.838-.197-1.539-1.118l1.518-4.674a1 1 0 00-.363-1.118l-3.976-2.888c-.784-.57-.38-1.81.588-1.81h4.914a1 1 0 00.951-.69l1.519-4.674z"/></svg>
                      </button>
                    </div>
                  )}
                </div>
                <p className="leading-relaxed text-left">{m.text}</p>
              </div>
              {feedbackOpen === i && <FeedbackForm onSave={(f) => saveFeedback(i, f)} onCancel={() => setFeedbackOpen(null)} />}
              {m.feedback && !feedbackOpen && <div className="text-[9px] font-bold text-green-500 uppercase flex items-center gap-1 justify-start ml-2"><span className="w-1 h-1 bg-green-500 rounded-full"></span> Feedback Saved</div>}
            </div>
          </div>
        ))}
        {isTyping && (
          <div className="flex justify-start">
            <div className="bg-white border border-slate-100 p-4 rounded-2xl shadow-sm flex gap-1">
              <div className="w-1.5 h-1.5 bg-indigo-400 rounded-full animate-bounce"></div>
              <div className="w-1.5 h-1.5 bg-indigo-400 rounded-full animate-bounce delay-75"></div>
              <div className="w-1.5 h-1.5 bg-indigo-400 rounded-full animate-bounce delay-150"></div>
            </div>
          </div>
        )}
      </div>

      <div className="p-6 bg-white border-t border-slate-200 shrink-0">
        <form onSubmit={handleSend} className="space-y-3">
          <div className="flex items-center justify-between mb-2">
            <div className="flex items-center gap-2">
              <span className={`text-[10px] font-bold uppercase tracking-widest transition-colors ${isListening ? 'text-indigo-600' : 'text-slate-400'}`}>
                {isListening ? 'Voice Input Active' : 'Keyboard Entry'}
              </span>
              {!showBriefing && (
                <button 
                  type="button" 
                  onClick={() => setShowBriefing(true)}
                  className="text-[9px] font-bold text-indigo-400 hover:text-indigo-600 uppercase transition-colors underline decoration-dotted"
                >
                  Show Briefing
                </button>
              )}
            </div>
            <button 
              type="button"
              onClick={() => isListening ? recognitionRef.current?.stop() : recognitionRef.current?.start()}
              className={`flex items-center gap-2 px-3 py-1 rounded-full text-[10px] font-bold uppercase tracking-tight transition-all border ${
                isListening ? 'bg-red-50 border-red-200 text-red-600 animate-pulse shadow-sm' : 'bg-slate-100 border-slate-200 text-slate-500 hover:bg-slate-200'
              }`}
            >
              <svg className="w-3.5 h-3.5" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M19 11a7 7 0 01-7 7m0 0a7 7 0 01-7-7m7 7v4m0 0H8m4 0h4m-4-8a3 3 0 01-3-3V5a3 3 0 116 0v6a3 3 0 01-3 3z"/></svg>
              {isListening ? 'Stop' : 'Dictate Response'}
            </button>
          </div>
          <div className="relative">
            <input
              type="text"
              value={inputValue}
              onChange={(e) => setInputValue(e.target.value)}
              disabled={isTyping}
              placeholder={isListening ? "Listening..." : "Type your professional response..."}
              className={`w-full p-4 pr-16 bg-slate-50 rounded-2xl border outline-none transition-all text-sm font-medium ${isListening ? 'border-indigo-500 ring-4 ring-indigo-500/10' : 'border-slate-200 focus:border-indigo-300'}`}
            />
            <button type="submit" disabled={!inputValue.trim() || isTyping} className="absolute right-2 top-2 bottom-2 bg-indigo-600 hover:bg-indigo-700 disabled:bg-slate-300 text-white px-4 rounded-xl shadow-lg shadow-indigo-600/20 transition-all">
              <svg className="w-5 h-5" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M5 13l4 4L19 7"/></svg>
            </button>
          </div>
        </form>
      </div>
    </div>
  );
};

import React, { useState, useEffect, useRef } from 'react';
import { GoogleGenAI, Chat, Modality } from '@google/genai';
import { Persona, Message, Feedback, Scenario } from '../types';
import { decode, decodeAudioData } from '../services/audioUtils';
import { FeedbackForm } from './FeedbackForm';

interface TextModeProps {
  persona: Persona;
  scenario: Scenario;
  onExit: () => void;
}

export const TextMode: React.FC<TextModeProps> = ({ persona, scenario, onExit }) => {
  const [messages, setMessages] = useState<Message[]>([]);
  const [inputValue, setInputValue] = useState("");
  const [isTyping, setIsTyping] = useState(false);
  const [isSpeaking, setIsSpeaking] = useState<number | null>(null);
  const [isListening, setIsListening] = useState(false);
  const [feedbackOpen, setFeedbackOpen] = useState<number | null>(null);
  const [showBriefing, setShowBriefing] = useState(true);
  const [speechRate, setSpeechRate] = useState(1.0);

  const chatRef = useRef<Chat | null>(null);
  const scrollRef = useRef<HTMLDivElement>(null);
  const audioContextRef = useRef<AudioContext | null>(null);
  const recognitionRef = useRef<any>(null);
  const currentAudioSourceRef = useRef<AudioBufferSourceNode | null>(null);

  useEffect(() => {
    const ai = new GoogleGenAI({ apiKey: process.env.API_KEY || '' });
    chatRef.current = ai.chats.create({
      model: 'gemini-3-flash-preview',
      config: {
        systemInstruction: `You are ${persona.name}, ${persona.title}. ${persona.systemInstruction} Current Situation: ${scenario.systemPrompt} Respond with concise, realistic professional turns.`
      }
    });

    const greet = async () => {
      setIsTyping(true);
      try {
        const result = await chatRef.current!.sendMessage({ message: `Start the meeting professionally according to this scenario: ${scenario.title}.` });
        const text = result.text || "";
        setMessages([{ role: 'model', text, timestamp: Date.now() }]);
        playTTS(text, 0);
      } catch (err) {
        console.error(err);
      } finally {
        setIsTyping(false);
      }
    };
    greet();

    const SpeechRecognition = (window as any).SpeechRecognition || (window as any).webkitSpeechRecognition;
    if (SpeechRecognition) {
      recognitionRef.current = new SpeechRecognition();
      recognitionRef.current.continuous = false; 
      recognitionRef.current.interimResults = true;
      recognitionRef.current.lang = 'en-US';
      recognitionRef.current.onresult = (event: any) => {
        const transcript = Array.from(event.results)
          .map((result: any) => result[0])
          .map((result: any) => result.transcript)
          .join('');
        setInputValue(transcript);
      };
      recognitionRef.current.onstart = () => setIsListening(true);
      recognitionRef.current.onend = () => setIsListening(false);
    }

    return () => {
      if (audioContextRef.current) audioContextRef.current.close();
      if (recognitionRef.current) recognitionRef.current.stop();
      if (currentAudioSourceRef.current) currentAudioSourceRef.current.stop();
    };
  }, [persona, scenario]);

  const playTTS = async (text: string, index: number) => {
    // Stop any currently playing audio
    if (currentAudioSourceRef.current) {
      try {
        currentAudioSourceRef.current.stop();
      } catch (e) {
        // Source might have already finished
      }
      currentAudioSourceRef.current = null;
    }

    setIsSpeaking(index);
    try {
      const ai = new GoogleGenAI({ apiKey: process.env.API_KEY || '' });
      const response = await ai.models.generateContent({
        model: "gemini-2.5-flash-preview-tts",
        contents: [{ parts: [{ text }] }],
        config: {
          responseModalities: [Modality.AUDIO],
          speechConfig: {
            voiceConfig: { prebuiltVoiceConfig: { voiceName: persona.voiceName } },
          },
        },
      });

      const audioData = response.candidates?.[0]?.content?.parts?.[0]?.inlineData?.data;
      if (audioData) {
        if (!audioContextRef.current) {
          audioContextRef.current = new (window.AudioContext || (window as any).webkitAudioContext)({ sampleRate: 24000 });
        }
        const buffer = await decodeAudioData(decode(audioData), audioContextRef.current, 24000, 1);
        const source = audioContextRef.current.createBufferSource();
        source.buffer = buffer;
        source.playbackRate.value = speechRate;
        source.connect(audioContextRef.current.destination);
        source.onended = () => {
          if (currentAudioSourceRef.current === source) {
            setIsSpeaking(null);
            currentAudioSourceRef.current = null;
          }
        };
        currentAudioSourceRef.current = source;
        source.start();
      }
    } catch (err) {
      console.error("TTS Error:", err);
      setIsSpeaking(null);
    }
  };

  const saveFeedback = (index: number, feedback: Feedback) => {
    const updatedMessages = [...messages];
    updatedMessages[index].feedback = feedback;
    setMessages(updatedMessages);
    setFeedbackOpen(null);

    const allFeedback = JSON.parse(localStorage.getItem('powertalk_feedback') || '[]');
    allFeedback.push({
      personaId: persona.id,
      scenarioId: scenario.id,
      messageText: messages[index].text,
      ...feedback
    });
    localStorage.setItem('powertalk_feedback', JSON.stringify(allFeedback));
  };

  const handleSend = async (e?: React.FormEvent) => {
    e?.preventDefault();
    if (!inputValue.trim() || isTyping || !chatRef.current) return;

    const textToSend = inputValue;
    const userMessage: Message = { role: 'user', text: textToSend, timestamp: Date.now() };
    setMessages(prev => [...prev, userMessage]);
    setInputValue("");
    setIsTyping(true);

    try {
      const result = await chatRef.current.sendMessage({ message: textToSend });
      const responseText = result.text || "";
      const newMessageIndex = messages.length + 1;
      setMessages(prev => [...prev, { role: 'model', text: responseText, timestamp: Date.now() }]);
      playTTS(responseText, newMessageIndex);
    } catch (err) {
      console.error(err);
    } finally {
      setIsTyping(false);
    }
  };

  useEffect(() => {
    if (scrollRef.current) {
      scrollRef.current.scrollTop = scrollRef.current.scrollHeight;
    }
  }, [messages, isTyping, feedbackOpen]);

  return (
    <div className="flex flex-col h-full bg-white rounded-3xl overflow-hidden shadow-2xl border border-slate-200">
      <div className="p-6 bg-slate-50 border-b border-slate-200 flex justify-between items-center shrink-0">
        <div className="flex items-center gap-4">
          <img src={persona.avatar} alt={persona.name} className="w-12 h-12 rounded-full border-2 border-white shadow-md" />
          <div>
            <h2 className="text-lg font-bold text-slate-800">{persona.name}</h2>
            <p className="text-[10px] font-bold text-indigo-600 uppercase tracking-widest">{scenario.title}</p>
          </div>
        </div>

        <div className="flex items-center gap-6">
          <div className="hidden md:flex flex-col items-end gap-1">
            <label className="text-[9px] font-bold text-slate-400 uppercase tracking-widest flex items-center gap-2">
              Speech Rate: <span className="text-indigo-600 font-black">{speechRate.toFixed(1)}x</span>
            </label>
            <input 
              type="range" 
              min="0.5" 
              max="2.0" 
              step="0.1" 
              value={speechRate} 
              onChange={(e) => setSpeechRate(parseFloat(e.target.value))}
              className="w-24 h-1 bg-slate-200 rounded-lg appearance-none cursor-pointer accent-indigo-600"
            />
          </div>
          <button onClick={onExit} className="text-slate-400 hover:text-red-500 font-bold text-xs uppercase tracking-widest transition-colors border border-slate-200 px-3 py-1.5 rounded-lg hover:border-red-100 hover:bg-red-50">End Practice</button>
        </div>
      </div>

      <div ref={scrollRef} className="flex-grow p-6 overflow-y-auto space-y-6 bg-slate-50/30">
        {/* Scenario Briefing Section */}
        {showBriefing && (
          <div className="mb-8 p-6 bg-indigo-50/50 border border-indigo-100 rounded-2xl relative group animate-in fade-in slide-in-from-top-4 duration-500">
            <button 
              onClick={() => setShowBriefing(false)} 
              className="absolute top-4 right-4 text-indigo-300 hover:text-indigo-500 transition-colors"
              title="Dismiss Briefing"
            >
              <svg className="w-4 h-4" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M6 18L18 6M6 6l12 12" /></svg>
            </button>
            <div className="flex items-center gap-2 mb-3 text-indigo-600">
              <div className="p-1.5 bg-indigo-100 rounded-lg">
                <svg className="w-4 h-4" fill="none" stroke="currentColor" viewBox="0 0 24 24">
                  <path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M13 16h-1v-4h-1m1-4h.01M21 12a9 9 0 11-18 0 9 9 0 0118 0z" />
                </svg>
              </div>
              <span className="text-[10px] font-bold uppercase tracking-widest">Active Scenario Briefing</span>
            </div>
            <p className="text-slate-700 text-sm leading-relaxed italic pr-8">
              "{scenario.context}"
            </p>
          </div>
        )}

        {messages.map((m, i) => (
          <div key={i} className={`flex items-start gap-3 ${m.role === 'user' ? 'flex-row-reverse' : 'flex-row'}`}>
            <div className={`max-w-[80%] space-y-2 ${m.role === 'user' ? 'text-right' : ''}`}>
              <div className={`p-4 rounded-2xl shadow-sm text-sm ${
                m.role === 'user' ? 'bg-indigo-600 text-white rounded-tr-none' : 'bg-white text-slate-800 rounded-tl-none border border-slate-100'
              }`}>
                <div className="flex justify-between items-start gap-4 mb-1">
                  <span className="text-[10px] opacity-60 uppercase font-bold tracking-widest">{m.role === 'user' ? 'You' : persona.name}</span>
                  {m.role === 'model' && (
                    <div className="flex gap-2">
                      <button onClick={() => playTTS(m.text, i)} className={`p-1 rounded-full ${isSpeaking === i ? 'bg-indigo-100 text-indigo-600' : 'text-slate-400 hover:text-indigo-600'}`}>
                        <svg className={`w-3.5 h-3.5 ${isSpeaking === i ? 'animate-pulse' : ''}`} fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M15.536 8.464a5 5 0 010 7.072m2.828-9.9a9 9 0 010 12.728M5.586 15H4a1 1 0 01-1-1v-4a1 1 0 011-1h1.586l4.707-4.707C10.923 3.663 12 4.109 12 5v14c0 .891-1.077 1.337-1.707.707L5.586 15z"/></svg>
                      </button>
                      <button onClick={() => setFeedbackOpen(feedbackOpen === i ? null : i)} className={`p-1 rounded-full ${m.feedback ? 'text-green-600' : 'text-slate-400 hover:text-amber-500'}`}>
                        <svg className="w-3.5 h-3.5" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M11.049 2.927c.3-.921 1.603-.921 1.902 0l1.519 4.674a1 1 0 00.95.69h4.915c.969 0 1.371 1.24.588 1.81l-3.976 2.888a1 1 0 00-.363 1.118l1.518 4.674c.3.922-.755 1.688-1.54 1.118l-3.976-2.888a1 1 0 00-1.176 0l-3.976 2.888c-.784.57-1.838-.197-1.539-1.118l1.518-4.674a1 1 0 00-.363-1.118l-3.976-2.888c-.784-.57-.38-1.81.588-1.81h4.914a1 1 0 00.951-.69l1.519-4.674z"/></svg>
                      </button>
                    </div>
                  )}
                </div>
                <p className="leading-relaxed text-left">{m.text}</p>
              </div>
              {feedbackOpen === i && <FeedbackForm onSave={(f) => saveFeedback(i, f)} onCancel={() => setFeedbackOpen(null)} />}
              {m.feedback && !feedbackOpen && <div className="text-[9px] font-bold text-green-500 uppercase flex items-center gap-1 justify-start ml-2"><span className="w-1 h-1 bg-green-500 rounded-full"></span> Feedback Saved</div>}
            </div>
          </div>
        ))}
        {isTyping && (
          <div className="flex justify-start">
            <div className="bg-white border border-slate-100 p-4 rounded-2xl shadow-sm flex gap-1">
              <div className="w-1.5 h-1.5 bg-indigo-400 rounded-full animate-bounce"></div>
              <div className="w-1.5 h-1.5 bg-indigo-400 rounded-full animate-bounce delay-75"></div>
              <div className="w-1.5 h-1.5 bg-indigo-400 rounded-full animate-bounce delay-150"></div>
            </div>
          </div>
        )}
      </div>

      <div className="p-6 bg-white border-t border-slate-200 shrink-0">
        <form onSubmit={handleSend} className="space-y-3">
          <div className="flex items-center justify-between mb-2">
            <div className="flex items-center gap-2">
              <span className={`text-[10px] font-bold uppercase tracking-widest transition-colors ${isListening ? 'text-indigo-600' : 'text-slate-400'}`}>
                {isListening ? 'Voice Input Active' : 'Keyboard Entry'}
              </span>
              {!showBriefing && (
                <button 
                  type="button" 
                  onClick={() => setShowBriefing(true)}
                  className="text-[9px] font-bold text-indigo-400 hover:text-indigo-600 uppercase transition-colors underline decoration-dotted"
                >
                  Show Briefing
                </button>
              )}
            </div>

            <div className="flex items-center gap-4">
               {/* Mobile speech rate slider */}
              <div className="flex md:hidden items-center gap-2">
                <span className="text-[9px] font-bold text-slate-400 uppercase">{speechRate.toFixed(1)}x</span>
                <input 
                  type="range" 
                  min="0.5" 
                  max="2.0" 
                  step="0.1" 
                  value={speechRate} 
                  onChange={(e) => setSpeechRate(parseFloat(e.target.value))}
                  className="w-16 h-1 bg-slate-200 rounded-lg appearance-none cursor-pointer accent-indigo-600"
                />
              </div>

              <button 
                type="button"
                onClick={() => isListening ? recognitionRef.current?.stop() : recognitionRef.current?.start()}
                className={`flex items-center gap-2 px-3 py-1 rounded-full text-[10px] font-bold uppercase tracking-tight transition-all border ${
                  isListening ? 'bg-red-50 border-red-200 text-red-600 animate-pulse shadow-sm' : 'bg-slate-100 border-slate-200 text-slate-500 hover:bg-slate-200'
                }`}
              >
                <svg className="w-3.5 h-3.5" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M19 11a7 7 0 01-7 7m0 0a7 7 0 01-7-7m7 7v4m0 0H8m4 0h4m-4-8a3 3 0 01-3-3V5a3 3 0 116 0v6a3 3 0 01-3 3z"/></svg>
                {isListening ? 'Stop' : 'Dictate Response'}
              </button>
            </div>
          </div>
          <div className="relative">
            <input
              type="text"
              value={inputValue}
              onChange={(e) => setInputValue(e.target.value)}
              disabled={isTyping}
              placeholder={isListening ? "Listening..." : "Type your professional response..."}
              className={`w-full p-4 pr-16 bg-slate-50 rounded-2xl border outline-none transition-all text-sm font-medium ${isListening ? 'border-indigo-500 ring-4 ring-indigo-500/10' : 'border-slate-200 focus:border-indigo-300'}`}
            />
            <button type="submit" disabled={!inputValue.trim() || isTyping} className="absolute right-2 top-2 bottom-2 bg-indigo-600 hover:bg-indigo-700 disabled:bg-slate-300 text-white px-4 rounded-xl shadow-lg shadow-indigo-600/20 transition-all">
              <svg className="w-5 h-5" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M5 13l4 4L19 7"/></svg>
            </button>
          </div>
        </form>
      </div>
    </div>
  );
};

import React, { useState, useEffect, useRef } from 'react';
import { GoogleGenAI, Modality, Type } from '@google/genai';
import { Persona, Message, Feedback, Scenario } from '../types';
import { decode, decodeAudioData } from '../services/audioUtils';
import { FeedbackForm } from './FeedbackForm';

interface TextModeProps {
  persona: Persona;
  scenario: Scenario;
  onExit: () => void;
}

interface Alternative {
  text: string;
  label: string;
}

export const TextMode: React.FC<TextModeProps> = ({ persona, scenario, onExit }) => {
  const [messages, setMessages] = useState<Message[]>([]);
  const [inputValue, setInputValue] = useState("");
  const [isTyping, setIsTyping] = useState(false);
  const [isSpeaking, setIsSpeaking] = useState<number | null>(null);
  const [isListening, setIsListening] = useState(false);
  const [feedbackOpen, setFeedbackOpen] = useState<number | null>(null);
  const [showBriefing, setShowBriefing] = useState(true);
  const [speechRate, setSpeechRate] = useState(1.0);
  const [pendingAlternatives, setPendingAlternatives] = useState<Alternative[] | null>(null);

  const scrollRef = useRef<HTMLDivElement>(null);
  const audioContextRef = useRef<AudioContext | null>(null);
  const recognitionRef = useRef<any>(null);
  const currentAudioSourceRef = useRef<AudioBufferSourceNode | null>(null);

  const getAIResponse = async (history: Message[]) => {
    setIsTyping(true);
    setPendingAlternatives(null);
    try {
      const ai = new GoogleGenAI({ apiKey: process.env.API_KEY || '' });

      const contents = history.map(m => ({
        role: m.role,
        parts: [{ text: m.text }]
      }));

      const systemInstruction = `You are ${persona.name}, ${persona.title}. ${persona.systemInstruction} 
      Current Situation: ${scenario.systemPrompt} 
      Task: Provide 3 alternative ways you would respond to the student right now. 
      Vary the tone slightly for each (e.g., one more direct, one more supportive, one more formal) while staying in character. 
      Keep each response between 1-3 sentences.`;

      const response = await ai.models.generateContent({
        model: 'gemini-3-flash-preview',
        contents,
        config: {
          systemInstruction,
          responseMimeType: "application/json",
          responseSchema: {
            type: Type.OBJECT,
            properties: {
              options: {
                type: Type.ARRAY,
                items: {
                  type: Type.OBJECT,
                  properties: {
                    text: { type: Type.STRING, description: "The response text." },
                    label: { type: Type.STRING, description: "A short tone label (e.g., 'Direct', 'Formal', 'Supportive')." }
                  },
                  required: ["text", "label"]
                },
                minItems: 3,
                maxItems: 3
              }
            },
            required: ["options"]
          }
        }
      });

      const jsonStr = response.text.trim();
      const data = JSON.parse(jsonStr);
      setPendingAlternatives(data.options);
    } catch (err) {
      console.error("AI Error:", err);
    } finally {
      setIsTyping(false);
    }
  };

  useEffect(() => {
    // Initial Greeting
    getAIResponse([]);

    const SpeechRecognition = (window as any).SpeechRecognition || (window as any).webkitSpeechRecognition;
    if (SpeechRecognition) {
      recognitionRef.current = new SpeechRecognition();
      recognitionRef.current.continuous = false; 
      recognitionRef.current.interimResults = true;
      recognitionRef.current.lang = 'en-US';
      recognitionRef.current.onresult = (event: any) => {
        const transcript = Array.from(event.results)
          .map((result: any) => result[0])
          .map((result: any) => result.transcript)
          .join('');
        setInputValue(transcript);
      };
      recognitionRef.current.onstart = () => setIsListening(true);
      recognitionRef.current.onend = () => setIsListening(false);
    }

    return () => {
      if (audioContextRef.current) audioContextRef.current.close();
      if (recognitionRef.current) recognitionRef.current.stop();
      if (currentAudioSourceRef.current) currentAudioSourceRef.current.stop();
    };
  }, [persona, scenario]);

  const playTTS = async (text: string, index: number) => {
    if (currentAudioSourceRef.current) {
      try { currentAudioSourceRef.current.stop(); } catch (e) {}
      currentAudioSourceRef.current = null;
    }

    setIsSpeaking(index);
    try {
      const ai = new GoogleGenAI({ apiKey: process.env.API_KEY || '' });
      const response = await ai.models.generateContent({
        model: "gemini-2.5-flash-preview-tts",
        contents: [{ parts: [{ text }] }],
        config: {
          responseModalities: [Modality.AUDIO],
          speechConfig: {
            voiceConfig: { prebuiltVoiceConfig: { voiceName: persona.voiceName } },
          },
        },
      });

      const audioData = response.candidates?.[0]?.content?.parts?.[0]?.inlineData?.data;
      if (audioData) {
        if (!audioContextRef.current) {
          audioContextRef.current = new (window.AudioContext || (window as any).webkitAudioContext)({ sampleRate: 24000 });
        }
        const buffer = await decodeAudioData(decode(audioData), audioContextRef.current, 24000, 1);
        const source = audioContextRef.current.createBufferSource();
        source.buffer = buffer;
        source.playbackRate.value = speechRate;
        source.connect(audioContextRef.current.destination);
        source.onended = () => {
          if (currentAudioSourceRef.current === source) {
            setIsSpeaking(null);
            currentAudioSourceRef.current = null;
          }
        };
        currentAudioSourceRef.current = source;
        source.start();
      }
    } catch (err) {
      console.error("TTS Error:", err);
      setIsSpeaking(null);
    }
  };

  const handleSelectAlternative = (alt: Alternative) => {
    const newMessage: Message = { role: 'model', text: alt.text, timestamp: Date.now() };
    const updatedMessages = [...messages, newMessage];
    setMessages(updatedMessages);
    setPendingAlternatives(null);
    playTTS(alt.text, updatedMessages.length - 1);
  };

  const handleSend = async (e?: React.FormEvent) => {
    e?.preventDefault();
    if (!inputValue.trim() || isTyping || pendingAlternatives) return;

    const userMsg: Message = { role: 'user', text: inputValue, timestamp: Date.now() };
    const newHistory = [...messages, userMsg];
    setMessages(newHistory);
    setInputValue("");
    getAIResponse(newHistory);
  };

  const saveFeedback = (index: number, feedback: Feedback) => {
    const updatedMessages = [...messages];
    updatedMessages[index].feedback = feedback;
    setMessages(updatedMessages);
    setFeedbackOpen(null);

    const allFeedback = JSON.parse(localStorage.getItem('powertalk_feedback') || '[]');
    allFeedback.push({ personaId: persona.id, scenarioId: scenario.id, messageText: messages[index].text, ...feedback });
    localStorage.setItem('powertalk_feedback', JSON.stringify(allFeedback));
  };

  useEffect(() => {
    if (scrollRef.current) {
      scrollRef.current.scrollTop = scrollRef.current.scrollHeight;
    }
  }, [messages, isTyping, pendingAlternatives]);

  return (
    <div className="flex flex-col h-full bg-white rounded-3xl overflow-hidden shadow-2xl border border-slate-200">
      {/* Header */}
      <div className="p-6 bg-slate-50 border-b border-slate-200 flex justify-between items-center shrink-0">
        <div className="flex items-center gap-4">
          <img src={persona.avatar} alt={persona.name} className="w-12 h-12 rounded-full border-2 border-white shadow-md" />
          <div>
            <h2 className="text-lg font-bold text-slate-800">{persona.name}</h2>
            <p className="text-[10px] font-bold text-indigo-600 uppercase tracking-widest">{scenario.title}</p>
          </div>
        </div>

        <div className="flex items-center gap-6">
          <div className="hidden md:flex flex-col items-end gap-1">
            <label className="text-[9px] font-bold text-slate-400 uppercase tracking-widest flex items-center gap-2">
              Speech Rate: <span className="text-indigo-600 font-black">{speechRate.toFixed(1)}x</span>
            </label>
            <input 
              type="range" min="0.5" max="2.0" step="0.1" value={speechRate} 
              onChange={(e) => setSpeechRate(parseFloat(e.target.value))}
              className="w-24 h-1 bg-slate-200 rounded-lg appearance-none cursor-pointer accent-indigo-600"
            />
          </div>
          <button onClick={onExit} className="text-slate-400 hover:text-red-500 font-bold text-xs uppercase tracking-widest transition-colors border border-slate-200 px-3 py-1.5 rounded-lg hover:border-red-100 hover:bg-red-50">End Practice</button>
        </div>
      </div>

      {/* Message History */}
      <div ref={scrollRef} className="flex-grow p-6 overflow-y-auto space-y-6 bg-slate-50/30">
        {showBriefing && (
          <div className="mb-8 p-6 bg-indigo-50/50 border border-indigo-100 rounded-2xl relative group animate-in fade-in slide-in-from-top-4 duration-500">
            <button onClick={() => setShowBriefing(false)} className="absolute top-4 right-4 text-indigo-300 hover:text-indigo-500"><svg className="w-4 h-4" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M6 18L18 6M6 6l12 12" /></svg></button>
            <div className="flex items-center gap-2 mb-3 text-indigo-600">
              <div className="p-1.5 bg-indigo-100 rounded-lg"><svg className="w-4 h-4" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M13 16h-1v-4h-1m1-4h.01M21 12a9 9 0 11-18 0 9 9 0 0118 0z" /></svg></div>
              <span className="text-[10px] font-bold uppercase tracking-widest">Active Scenario Briefing</span>
            </div>
            <p className="text-slate-700 text-sm leading-relaxed italic pr-8">"{scenario.context}"</p>
          </div>
        )}

        {messages.map((m, i) => (
          <div key={i} className={`flex items-start gap-3 ${m.role === 'user' ? 'flex-row-reverse' : 'flex-row'}`}>
            <div className={`max-w-[80%] space-y-2 ${m.role === 'user' ? 'text-right' : ''}`}>
              <div className={`p-4 rounded-2xl shadow-sm text-sm ${
                m.role === 'user' ? 'bg-indigo-600 text-white rounded-tr-none' : 'bg-white text-slate-800 rounded-tl-none border border-slate-100'
              }`}>
                <div className="flex justify-between items-start gap-4 mb-1">
                  <span className="text-[10px] opacity-60 uppercase font-bold tracking-widest">{m.role === 'user' ? 'You' : persona.name}</span>
                  {m.role === 'model' && (
                    <div className="flex gap-2">
                      <button onClick={() => playTTS(m.text, i)} className={`p-1 rounded-full ${isSpeaking === i ? 'bg-indigo-100 text-indigo-600' : 'text-slate-400 hover:text-indigo-600'}`}>
                        <svg className={`w-3.5 h-3.5 ${isSpeaking === i ? 'animate-pulse' : ''}`} fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M15.536 8.464a5 5 0 010 7.072m2.828-9.9a9 9 0 010 12.728M5.586 15H4a1 1 0 01-1-1v-4a1 1 0 011-1h1.586l4.707-4.707C10.923 3.663 12 4.109 12 5v14c0 .891-1.077 1.337-1.707.707L5.586 15z"/></svg>
                      </button>
                      <button onClick={() => setFeedbackOpen(feedbackOpen === i ? null : i)} className={`p-1 rounded-full ${m.feedback ? 'text-green-600' : 'text-slate-400 hover:text-amber-500'}`}>
                        <svg className="w-3.5 h-3.5" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M11.049 2.927c.3-.921 1.603-.921 1.902 0l1.519 4.674a1 1 0 00.95.69h4.915c.969 0 1.371 1.24.588 1.81l-3.976 2.888a1 1 0 00-.363 1.118l1.518 4.674c.3.922-.755 1.688-1.54 1.118l-3.976-2.888a1 1 0 00-1.176 0l-3.976 2.888c-.784.57-1.838-.197-1.539-1.118l1.518-4.674a1 1 0 00-.363-1.118l-3.976-2.888c-.784-.57-.38-1.81.588-1.81h4.914a1 1 0 00.951-.69l1.519-4.674z"/></svg>
                      </button>
                    </div>
                  )}
                </div>
                <p className="leading-relaxed text-left">{m.text}</p>
              </div>
              {feedbackOpen === i && <FeedbackForm onSave={(f) => saveFeedback(i, f)} onCancel={() => setFeedbackOpen(null)} />}
            </div>
          </div>
        ))}

        {/* Alternative Selection UI */}
        {pendingAlternatives && !isTyping && (
          <div className="space-y-4 animate-in fade-in slide-in-from-bottom-4 duration-500 pb-4">
            <div className="flex items-center gap-3">
              <div className="h-px bg-indigo-200 flex-grow"></div>
              <span className="text-[10px] font-bold text-indigo-400 uppercase tracking-widest px-2">Choose {persona.name}'s Response Tone</span>
              <div className="h-px bg-indigo-200 flex-grow"></div>
            </div>
            <div className="grid grid-cols-1 md:grid-cols-3 gap-4">
              {pendingAlternatives.map((alt, idx) => (
                <div 
                  key={idx}
                  onClick={() => handleSelectAlternative(alt)}
                  className="bg-white border-2 border-indigo-50 hover:border-indigo-500 p-4 rounded-2xl shadow-sm hover:shadow-md cursor-pointer transition-all flex flex-col group relative"
                >
                  <span className="inline-block self-start px-2 py-0.5 mb-3 bg-indigo-100 text-indigo-600 rounded-md text-[9px] font-black uppercase tracking-wider group-hover:bg-indigo-600 group-hover:text-white transition-colors">
                    {alt.label}
                  </span>
                  <p className="text-slate-700 text-sm leading-snug flex-grow">{alt.text}</p>
                  <div className="mt-4 flex items-center justify-between opacity-0 group-hover:opacity-100 transition-opacity">
                    <span className="text-[10px] font-bold text-indigo-500 uppercase">Select This</span>
                    <svg className="w-4 h-4 text-indigo-500" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M5 13l4 4L19 7"/></svg>
                  </div>
                </div>
              ))}
            </div>
          </div>
        )}

        {isTyping && (
          <div className="flex justify-start">
            <div className="bg-white border border-slate-100 p-4 rounded-2xl shadow-sm flex items-center gap-3">
              <div className="flex gap-1">
                <div className="w-1.5 h-1.5 bg-indigo-400 rounded-full animate-bounce"></div>
                <div className="w-1.5 h-1.5 bg-indigo-400 rounded-full animate-bounce delay-75"></div>
                <div className="w-1.5 h-1.5 bg-indigo-400 rounded-full animate-bounce delay-150"></div>
              </div>
              <span className="text-[10px] font-bold text-slate-400 uppercase tracking-widest">{persona.name} is considering options...</span>
            </div>
          </div>
        )}
      </div>

      {/* Input Area */}
      <div className="p-6 bg-white border-t border-slate-200 shrink-0">
        <form onSubmit={handleSend} className="space-y-3">
          <div className="flex items-center justify-between mb-2">
            <div className="flex items-center gap-2">
              <span className={`text-[10px] font-bold uppercase tracking-widest transition-colors ${isListening ? 'text-indigo-600' : 'text-slate-400'}`}>
                {pendingAlternatives ? 'Response Selection Required' : isListening ? 'Voice Input Active' : 'Keyboard Entry'}
              </span>
            </div>

            <div className="flex items-center gap-4">
              <div className="hidden md:flex items-center gap-2">
                <span className="text-[9px] font-bold text-slate-400 uppercase">{speechRate.toFixed(1)}x</span>
                <input 
                  type="range" min="0.5" max="2.0" step="0.1" value={speechRate} 
                  onChange={(e) => setSpeechRate(parseFloat(e.target.value))}
                  className="w-16 h-1 bg-slate-200 rounded-lg appearance-none cursor-pointer accent-indigo-600"
                />
              </div>

              <button 
                type="button"
                disabled={!!pendingAlternatives}
                onClick={() => isListening ? recognitionRef.current?.stop() : recognitionRef.current?.start()}
                className={`flex items-center gap-2 px-3 py-1 rounded-full text-[10px] font-bold uppercase tracking-tight transition-all border ${
                  isListening ? 'bg-red-50 border-red-200 text-red-600 animate-pulse' : 'bg-slate-100 border-slate-200 text-slate-500 hover:bg-slate-200'
                } ${pendingAlternatives ? 'opacity-50 cursor-not-allowed' : ''}`}
              >
                <svg className="w-3.5 h-3.5" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M19 11a7 7 0 01-7 7m0 0a7 7 0 01-7-7m7 7v4m0 0H8m4 0h4m-4-8a3 3 0 01-3-3V5a3 3 0 116 0v6a3 3 0 01-3 3z"/></svg>
                {isListening ? 'Stop' : 'Dictate'}
              </button>
            </div>
          </div>
          <div className="relative">
            <input
              type="text"
              value={inputValue}
              onChange={(e) => setInputValue(e.target.value)}
              disabled={isTyping || !!pendingAlternatives}
              placeholder={pendingAlternatives ? "Select a response above to continue..." : isListening ? "Listening..." : "Type your response..."}
              className={`w-full p-4 pr-16 bg-slate-50 rounded-2xl border outline-none transition-all text-sm font-medium ${isListening ? 'border-indigo-500 ring-4 ring-indigo-500/10' : 'border-slate-200 focus:border-indigo-300'}`}
            />
            <button 
              type="submit" 
              disabled={!inputValue.trim() || isTyping || !!pendingAlternatives} 
              className="absolute right-2 top-2 bottom-2 bg-indigo-600 hover:bg-indigo-700 disabled:bg-slate-300 text-white px-4 rounded-xl shadow-lg transition-all"
            >
              <svg className="w-5 h-5" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M5 13l4 4L19 7"/></svg>
            </button>
          </div>
        </form>
      </div>
    </div>
  );
};

