  ETHICS_OFFICER = 'ETHICS_OFFICER',
  LAB_MANAGER = 'LAB_MANAGER'
}

export interface Scenario {
  id: string;
  title: string;
  context: string;
  systemPrompt: string;
}

export interface Persona {
  id: PersonaType;
  name: string;
  title: string;
  description: string;
  goal: string;
  systemInstruction: string;
  avatar: string;
  voiceName: 'Kore' | 'Puck' | 'Charon' | 'Fenrir' | 'Zephyr';
