}

export interface Message {
  role: 'user' | 'model';
  text: string;
  timestamp: number;
  feedback?: Feedback;
}

export interface Feedback {
  rating: number; // 1-5
  clarity: boolean;
  relevance: boolean;
  helpfulness: boolean;
  comments: string;
  timestamp: number;
}

export interface SessionState {
  isActive: boolean;
  mode: 'text' | 'voice';
  persona: Persona | null;
  scenario: Scenario | null;
}

