import React, { useState } from 'react';
import { PERSONAS } from './constants';
import { Persona, SessionState, Scenario } from './types';
import { PersonaCard } from './components/PersonaCard';
import { VoiceMode } from './components/VoiceMode';
import { TextMode } from './components/TextMode';

const App: React.FC = () => {
  const [session, setSession] = useState<SessionState>({
    isActive: false,
    mode: 'text',
    persona: null,
    scenario: null
  });

  const handleSelectPersona = (persona: Persona) => {
    setSession({ ...session, persona, scenario: null });
  };

  const handleSelectScenario = (scenario: Scenario) => {
    setSession({ ...session, scenario });
  };

  const startSession = (mode: 'text' | 'voice') => {
    setSession({ ...session, isActive: true, mode });
  };

  const endSession = () => {
    setSession({ ...session, isActive: false, persona: null, scenario: null });
  };

  const resetToPersona = () => {
    setSession({ ...session, persona: null, scenario: null });
  };

  const resetToScenario = () => {
    setSession({ ...session, scenario: null });
  };

  if (session.isActive && session.persona && session.scenario) {
    return (
      <div className="h-screen w-full bg-[#E8EAED] p-4 md:p-10 flex items-center justify-center">
        <div className="w-full max-w-5xl h-full max-h-[900px]">
          {session.mode === 'voice' ? (
            <VoiceMode persona={session.persona} scenario={session.scenario} onExit={endSession} />
          ) : (
            <TextMode persona={session.persona} scenario={session.scenario} onExit={endSession} />
          )}
        </div>
      </div>
    );
  }

  return (
    <div className="min-h-screen bg-white flex flex-col">
      <header className="bg-[#00274C] border-b border-[#FFCB05] sticky top-0 z-10">
        <div className="max-w-7xl mx-auto px-6 h-24 flex items-center justify-between">
          <div className="flex items-center gap-4">
            <div className="w-12 h-12 bg-[#FFCB05] rounded-xl flex items-center justify-center shadow-lg shrink-0">
              <svg className="w-7 h-7 text-[#00274C]" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M17 8h2a2 2 0 012 2v6a2 2 0 01-2 2h-2v4l-4-4H9a1.994 1.994 0 01-1.414-.586m0 0L11 14h4a2 2 0 002-2V6a2 2 0 00-2-2H5a2 2 0 00-2 2v6a2 2 0 002 2h2v4l.586-.586z"></path></svg>
            </div>
            <div>
              <h1 className="text-xl font-black text-white tracking-tight leading-none mb-1 uppercase">Practice High-Stakes</h1>
              <p className="text-[10px] font-bold text-[#FFCB05] uppercase tracking-widest">Academic English Simulator</p>
            </div>
          </div>
          <div className="text-white/60 text-xs font-medium hidden sm:block text-right">
            University of Michigan<br/>Academic Excellence
          </div>
        </div>
      </header>

      <main className="flex-grow max-w-7xl mx-auto px-6 py-12 w-full">
        {!session.persona ? (
          <div className="space-y-12">
            <div className="max-w-3xl">
              <h2 className="text-4xl md:text-5xl font-extrabold text-[#00274C] tracking-tight mb-6 leading-[1.1]">
                Master the Art of <span className="text-[#FFCB05] bg-[#00274C] px-2">High-Stakes</span> Academic Dialogue
              </h2>
              <p className="text-lg text-slate-600 leading-relaxed mb-8">
                Welcome to the Practice High-Stakes Academic English Simulator. This tool helps international scholars navigate institutional hierarchies and professional challenges with confidence.
              </p>
              <div className="h-1.5 w-24 bg-[#FFCB05] rounded-full"></div>
            </div>

            <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-4 gap-6">
              {PERSONAS.map(p => (
                <PersonaCard key={p.id} persona={p} onSelect={handleSelectPersona} />
              ))}
            </div>
          </div>
        ) : !session.scenario ? (
          <div className="max-w-4xl mx-auto space-y-12 animate-in fade-in slide-in-from-bottom duration-500">
