import React, { useEffect, useRef, useState, useCallback } from 'react';
import { GoogleGenAI, Modality, LiveServerMessage } from '@google/genai';
import { Persona, Feedback, Scenario } from '../types';
import { decode, decodeAudioData, createPcmBlob } from '../services/audioUtils';
import { FeedbackForm } from './FeedbackForm';

interface VoiceTurn {
  role: 'user' | 'model';
  text: string;
  feedback?: Feedback;
}

interface VoiceModeProps {
  persona: Persona;
  scenario: Scenario;
  onExit: () => void;
}

export const VoiceMode: React.FC<VoiceModeProps> = ({ persona, scenario, onExit }) => {
  const [isConnected, setIsConnected] = useState(false);
  const [history, setHistory] = useState<VoiceTurn[]>([]);
  const [currentInput, setCurrentInput] = useState("");
  const [currentOutput, setCurrentOutput] = useState("");
  const [feedbackIndex, setFeedbackIndex] = useState<number | null>(null);

  const canvasRef = useRef<HTMLCanvasElement>(null);
  const sessionRef = useRef<any>(null);
  const audioContextRef = useRef<AudioContext | null>(null);
  const outputContextRef = useRef<AudioContext | null>(null);
  const nextStartTimeRef = useRef<number>(0);
  const sourcesRef = useRef<Set<AudioBufferSourceNode>>(new Set());
  const analyserRef = useRef<AnalyserNode | null>(null);
  const animationFrameRef = useRef<number | null>(null);
  const scrollRef = useRef<HTMLDivElement>(null);

  const cleanup = useCallback(() => {
    if (sessionRef.current) sessionRef.current.close();
    if (audioContextRef.current) audioContextRef.current.close();
    if (outputContextRef.current) outputContextRef.current.close();
    if (animationFrameRef.current) cancelAnimationFrame(animationFrameRef.current);
    sourcesRef.current.forEach(s => s.stop());
    sourcesRef.current.clear();
  }, []);

  useEffect(() => {
    return cleanup;
  }, [cleanup]);

  useEffect(() => {
    if (scrollRef.current) {
      scrollRef.current.scrollTop = scrollRef.current.scrollHeight;
    }
  }, [history, currentOutput, currentInput]);

  const startSession = async () => {
    try {
      const ai = new GoogleGenAI({ apiKey: process.env.API_KEY || '' });

      audioContextRef.current = new (window.AudioContext || (window as any).webkitAudioContext)({ sampleRate: 16000 });
      outputContextRef.current = new (window.AudioContext || (window as any).webkitAudioContext)({ sampleRate: 24000 });

      const stream = await navigator.mediaDevices.getUserMedia({ audio: true });
      const source = audioContextRef.current.createMediaStreamSource(stream);
      const analyser = audioContextRef.current.createAnalyser();
      analyser.fftSize = 256;
      source.connect(analyser);
      analyserRef.current = analyser;

      const sessionPromise = ai.live.connect({
        model: 'gemini-2.5-flash-native-audio-preview-12-2025',
        config: {
          responseModalities: [Modality.AUDIO],
          systemInstruction: `${persona.systemInstruction} Current Situation: ${scenario.systemPrompt}. Start by greeting the student in character.`,
          speechConfig: {
            voiceConfig: { prebuiltVoiceConfig: { voiceName: persona.voiceName } }
          },
          outputAudioTranscription: {},
          inputAudioTranscription: {}
        },
        callbacks: {
          onopen: () => {
            setIsConnected(true);
            const scriptProcessor = audioContextRef.current!.createScriptProcessor(4096, 1, 1);
            scriptProcessor.onaudioprocess = (e) => {
              const inputData = e.inputBuffer.getChannelData(0);
              const base64Pcm = createPcmBlob(inputData);
              sessionPromise.then(session => {
                session.sendRealtimeInput({ media: { data: base64Pcm, mimeType: 'audio/pcm;rate=16000' } });
              });
            };
            source.connect(scriptProcessor);
            scriptProcessor.connect(audioContextRef.current!.destination);
            drawVisualizer();
          },
          onmessage: async (message: LiveServerMessage) => {
            if (message.serverContent?.inputTranscription) {
              setCurrentInput(prev => prev + message.serverContent?.inputTranscription?.text);
            }
            if (message.serverContent?.outputTranscription) {
              setCurrentOutput(prev => prev + message.serverContent?.outputTranscription?.text);
            }
            if (message.serverContent?.turnComplete) {
              setHistory(prev => {
                const newHistory = [...prev];
                if (currentInput) newHistory.push({ role: 'user', text: currentInput });
                if (currentOutput) newHistory.push({ role: 'model', text: currentOutput });
                return newHistory;
              });
              setCurrentInput("");
              setCurrentOutput("");
            }
            const audioData = message.serverContent?.modelTurn?.parts[0]?.inlineData?.data;
            if (audioData && outputContextRef.current) {
              const ctx = outputContextRef.current;
              nextStartTimeRef.current = Math.max(nextStartTimeRef.current, ctx.currentTime);
              const buffer = await decodeAudioData(decode(audioData), ctx, 24000, 1);
              const sourceNode = ctx.createBufferSource();
              sourceNode.buffer = buffer;
              sourceNode.connect(ctx.destination);
              sourceNode.onended = () => sourcesRef.current.delete(sourceNode);
              sourceNode.start(nextStartTimeRef.current);
              nextStartTimeRef.current += buffer.duration;
              sourcesRef.current.add(sourceNode);
            }
          },
          onclose: () => setIsConnected(false),
          onerror: (e) => console.error("Live API Error:", e)
        }
      });
      sessionRef.current = await sessionPromise;
    } catch (err) {
      console.error("Failed to start voice session:", err);
    }
  };

  const drawVisualizer = () => {
    if (!canvasRef.current || !analyserRef.current) return;
    const canvas = canvasRef.current;
    const ctx = canvas.getContext('2d');
    if (!ctx) return;
    const bufferLength = analyserRef.current.frequencyBinCount;
    const dataArray = new Uint8Array(bufferLength);
    const render = () => {
      analyserRef.current!.getByteFrequencyData(dataArray);
      ctx.clearRect(0, 0, canvas.width, canvas.height);
      const barWidth = (canvas.width / bufferLength) * 2.5;
      let x = 0;
      for (let i = 0; i < bufferLength; i++) {
        const barHeight = (dataArray[i] / 255) * canvas.height;
        ctx.fillStyle = `#FFCB05`;
        ctx.fillRect(x, canvas.height - barHeight, barWidth, barHeight);
        x += barWidth + 1;
      }
      animationFrameRef.current = requestAnimationFrame(render);
    };
    render();
  };

  return (
    <div className="flex flex-col h-full bg-[#00274C] text-white rounded-3xl overflow-hidden shadow-2xl border-4 border-[#FFCB05]/30">
      <div className="p-6 bg-[#001d3a] border-b border-[#FFCB05]/20 flex justify-between items-center shrink-0">
        <div className="flex items-center gap-4">
          <img src={persona.avatar} alt={persona.name} className="w-12 h-12 rounded-full border-2 border-[#FFCB05]" />
          <div>
            <h2 className="text-xl font-black">{persona.name}</h2>
            <p className="text-[10px] text-[#FFCB05] font-black uppercase tracking-widest">{scenario.title}</p>
          </div>
        </div>
        <button onClick={onExit} className="bg-[#FFCB05] hover:bg-[#ffdb4d] text-[#00274C] px-5 py-2 rounded-lg text-xs font-black uppercase tracking-widest transition-colors">End Session</button>
      </div>

      <div className="flex-grow flex flex-col items-center p-8 space-y-6 overflow-hidden">
        {!isConnected ? (
          <div className="text-center space-y-8 my-auto animate-in fade-in zoom-in duration-500">
            <div className="w-32 h-32 bg-[#FFCB05] rounded-full flex items-center justify-center mx-auto shadow-2xl shadow-[#FFCB05]/20 animate-pulse">
               <svg className="w-16 h-16 text-[#00274C]" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M19 11a7 7 0 01-7 7m0 0a7 7 0 01-7-7m7 7v4m0 0H8m4 0h4m-4-8a3 3 0 01-3-3V5a3 3 0 116 0v6a3 3 0 01-3 3z"></path></svg>
            </div>
            <div className="space-y-4">
              <h2 className="text-3xl font-black text-white uppercase tracking-tight">Academic English Voice Workspace</h2>
              <p className="text-[#FFCB05]/70 max-w-sm mx-auto text-sm font-medium leading-relaxed italic">" {scenario.context} "</p>
            </div>
            <button onClick={startSession} className="bg-[#FFCB05] hover:bg-[#ffdb4d] text-[#00274C] px-12 py-5 rounded-full font-black text-lg shadow-2xl transition-all transform hover:scale-105 active:scale-95 uppercase tracking-widest">Connect to Faculty</button>
          </div>
        ) : (
          <div className="w-full max-w-2xl h-full flex flex-col space-y-6 overflow-hidden">
            <canvas ref={canvasRef} width={600} height={80} className="w-full rounded-xl opacity-80 shrink-0 bg-[#001d3a]" />
            <div ref={scrollRef} className="flex-grow overflow-y-auto space-y-4 pr-2 custom-scrollbar">
              {history.map((turn, i) => (
                <div key={i} className={`flex flex-col ${turn.role === 'user' ? 'items-end' : 'items-start'}`}>
                  <div className={`p-4 rounded-2xl max-w-[85%] text-sm shadow-md font-medium ${turn.role === 'user' ? 'bg-[#FFCB05] text-[#00274C] rounded-tr-none' : 'bg-[#003d77] text-white rounded-tl-none border border-white/10'}`}>
                    <span className={`text-[10px] font-black uppercase tracking-widest opacity-60 mb-1 block ${turn.role === 'user' ? 'text-[#00274C]' : 'text-[#FFCB05]'}`}>
                      {turn.role === 'user' ? 'You' : persona.name}
                    </span>
                    <p className="leading-relaxed">{turn.text}</p>
                  </div>
                </div>
              ))}
              {(currentInput || currentOutput) && (
                <div className="space-y-3 opacity-60 italic text-[#FFCB05] text-xs font-medium">
                  {currentInput && <div className="text-right">Listening: {currentInput}</div>}
                  {currentOutput && <div className="text-left">{persona.name} responding...</div>}
                </div>
              )}
            </div>
            <div className="flex justify-center shrink-0">
               <div className="px-5 py-2 bg-[#FFCB05]/10 text-[#FFCB05] rounded-full text-[10px] font-black uppercase tracking-widest border border-[#FFCB05]/30 animate-pulse">Live Practice Active</div>
            </div>
          </div>
        )}
      </div>
      <style>{`.custom-scrollbar::-webkit-scrollbar { width: 4px; } .custom-scrollbar::-webkit-scrollbar-track { background: transparent; } .custom-scrollbar::-webkit-scrollbar-thumb { background: #FFCB05; border-radius: 10px; }`}</style>
    </div>
  );
};

import { Persona, Scenario, Message } from '../types';

export function generateTranscript(persona: Persona, scenario: Scenario, messages: Message[] | any[]): string {
  const timestamp = new Date().toLocaleString();
  let report = `UNIVERSITY OF MICHIGAN - ACADEMIC COMMUNICATION PORTFOLIO\n`;
  report += `Generated: ${timestamp}\n`;
  report += `------------------------------------------------------------\n\n`;
  report += `PARTICIPANT PROFILE:\n`;
  report += `Interaction Partner: ${persona.name} (${persona.title})\n`;
  report += `Communication Scenario: ${scenario.title}\n`;
  report += `Context: ${scenario.context}\n\n`;
  report += `------------------------------------------------------------\n`;
  report += `DIALOGUE TRANSCRIPT:\n\n`;

  messages.forEach((m, i) => {
    const role = m.role === 'user' ? 'STUDENT' : persona.name.toUpperCase();
    report += `[${role}]: ${m.text}\n`;
    if (m.feedback) {
      report += `   >> ASSESSMENT: Rating ${m.feedback.rating}/5 | `;
      report += `Flags: ${[
        m.feedback.clarity ? 'Clear' : null,
        m.feedback.relevance ? 'Relevant' : null,
        m.feedback.helpfulness ? 'Helpful' : null
      ].filter(Boolean).join(', ')}\n`;
      if (m.feedback.comments) {
        report += `   >> NOTES: ${m.feedback.comments}\n`;
      }
    }
    report += `\n`;
  });

  report += `------------------------------------------------------------\n`;
  report += `END OF REPORT\n`;
  return report;
}

export function downloadFile(content: string, fileName: string, contentType: string) {
  const a = document.createElement("a");
  const file = new Blob([content], { type: contentType });
  a.href = URL.createObjectURL(file);
  a.download = fileName;
  a.click();
  URL.revokeObjectURL(a.href);
}

export function shareToInstructor(persona: Persona, scenario: Scenario) {
  const subject = encodeURIComponent(`Academic Communication Portfolio: ${scenario.title}`);
  const body = encodeURIComponent(`Hello Instructor,\n\nI have completed a high-stakes communication simulation with ${persona.name} regarding "${scenario.title}".\n\nPlease find my attached transcript and recording for review.\n\nBest regards,`);
  window.location.href = `mailto:?subject=${subject}&body=${body}`;
}

import React, { useState, useEffect, useRef } from 'react';
import { GoogleGenAI, Modality, Type } from '@google/genai';
import { Persona, Message, Feedback, Scenario } from '../types';
import { decode, decodeAudioData } from '../services/audioUtils';
import { FeedbackForm } from './FeedbackForm';
import { generateTranscript, downloadFile, shareToInstructor } from '../services/reportUtils';

interface TextModeProps {
  persona: Persona;
  scenario: Scenario;
  onExit: () => void;
}

interface Alternative {
  text: string;
  label: string;
}

export const TextMode: React.FC<TextModeProps> = ({ persona, scenario, onExit }) => {
  const [messages, setMessages] = useState<Message[]>([]);
  const [inputValue, setInputValue] = useState("");
  const [isTyping, setIsTyping] = useState(false);
  const [isSpeaking, setIsSpeaking] = useState<number | null>(null);
  const [isListening, setIsListening] = useState(false);
  const [feedbackOpen, setFeedbackOpen] = useState<number | null>(null);
  const [showBriefing, setShowBriefing] = useState(true);
  const [speechRate, setSpeechRate] = useState(1.0);
  const [pendingAlternatives, setPendingAlternatives] = useState<Alternative[] | null>(null);

  const scrollRef = useRef<HTMLDivElement>(null);
  const audioContextRef = useRef<AudioContext | null>(null);
  const recognitionRef = useRef<any>(null);
  const currentAudioSourceRef = useRef<AudioBufferSourceNode | null>(null);

  const getAIResponse = async (history: Message[]) => {
    setIsTyping(true);
    setPendingAlternatives(null);
    try {
      const ai = new GoogleGenAI({ apiKey: process.env.API_KEY || '' });

      const contents = history.map(m => ({
        role: m.role,
        parts: [{ text: m.text }]
      }));

      const systemInstruction = `You are ${persona.name}, ${persona.title}. ${persona.systemInstruction} 
      Current Situation: ${scenario.systemPrompt} 
      Task: Provide 3 alternative ways you would respond to the student right now. 
      Vary the tone slightly for each (e.g., one more direct, one more supportive, one more formal) while staying in character. 
      Keep each response between 1-3 sentences.`;

      const response = await ai.models.generateContent({
        model: 'gemini-3-flash-preview',
        contents,
        config: {
          systemInstruction,
          responseMimeType: "application/json",
          responseSchema: {
            type: Type.OBJECT,
            properties: {
              options: {
                type: Type.ARRAY,
                items: {
                  type: Type.OBJECT,
                  properties: {
                    text: { type: Type.STRING, description: "The response text." },
                    label: { type: Type.STRING, description: "A short tone label (e.g., 'Direct', 'Formal', 'Supportive')." }
                  },
                  required: ["text", "label"]
                },
                minItems: 3,
                maxItems: 3
              }
            },
            required: ["options"]
          }
        }
      });

      const jsonStr = response.text.trim();
      const data = JSON.parse(jsonStr);
      setPendingAlternatives(data.options);
    } catch (err) {
      console.error("AI Error:", err);
    } finally {
      setIsTyping(false);
    }
  };

  useEffect(() => {
    getAIResponse([]);

    const SpeechRecognition = (window as any).SpeechRecognition || (window as any).webkitRecognition || (window as any).webkitSpeechRecognition;
    if (SpeechRecognition) {
      recognitionRef.current = new SpeechRecognition();
      recognitionRef.current.continuous = false; 
      recognitionRef.current.interimResults = true;
      recognitionRef.current.lang = 'en-US';
      recognitionRef.current.onresult = (event: any) => {
        const transcript = Array.from(event.results)
          .map((result: any) => result[0])
          .map((result: any) => result.transcript)
          .join('');
        setInputValue(transcript);
      };
      recognitionRef.current.onstart = () => setIsListening(true);
      recognitionRef.current.onend = () => setIsListening(false);
    }

    return () => {
      if (audioContextRef.current) audioContextRef.current.close();
      if (recognitionRef.current) recognitionRef.current.stop();
      if (currentAudioSourceRef.current) currentAudioSourceRef.current.stop();
    };
  }, [persona, scenario]);

  const playTTS = async (text: string, index: number) => {
    if (currentAudioSourceRef.current) {
      try { currentAudioSourceRef.current.stop(); } catch (e) {}
      currentAudioSourceRef.current = null;
    }

    setIsSpeaking(index);
    try {
      const ai = new GoogleGenAI({ apiKey: process.env.API_KEY || '' });
      const response = await ai.models.generateContent({
        model: "gemini-2.5-flash-preview-tts",
        contents: [{ parts: [{ text }] }],
        config: {
          responseModalities: [Modality.AUDIO],
          speechConfig: {
            voiceConfig: { prebuiltVoiceConfig: { voiceName: persona.voiceName } },
          },
        },
      });

      const audioData = response.candidates?.[0]?.content?.parts?.[0]?.inlineData?.data;
      if (audioData) {
        if (!audioContextRef.current) {
          audioContextRef.current = new (window.AudioContext || (window as any).webkitAudioContext)({ sampleRate: 24000 });
        }
        const buffer = await decodeAudioData(decode(audioData), audioContextRef.current, 24000, 1);
        const source = audioContextRef.current.createBufferSource();
        source.buffer = buffer;
        source.playbackRate.value = speechRate;
        source.connect(audioContextRef.current.destination);
        source.onended = () => {
          if (currentAudioSourceRef.current === source) {
            setIsSpeaking(null);
            currentAudioSourceRef.current = null;
          }
        };
        currentAudioSourceRef.current = source;
        source.start();
      }
    } catch (err) {
      console.error("TTS Error:", err);
      setIsSpeaking(null);
    }
  };

  const handleSelectAlternative = (alt: Alternative) => {
    const newMessage: Message = { role: 'model', text: alt.text, timestamp: Date.now() };
    const updatedMessages = [...messages, newMessage];
    setMessages(updatedMessages);
    setPendingAlternatives(null);
    playTTS(alt.text, updatedMessages.length - 1);
  };

  const handleSend = async (e?: React.FormEvent) => {
    e?.preventDefault();
    if (!inputValue.trim() || isTyping || pendingAlternatives) return;

    const userMsg: Message = { role: 'user', text: inputValue, timestamp: Date.now() };
    const newHistory = [...messages, userMsg];
    setMessages(newHistory);
    setInputValue("");
    getAIResponse(newHistory);
  };

  const saveFeedback = (index: number, feedback: Feedback) => {
    const updatedMessages = [...messages];
    updatedMessages[index].feedback = feedback;
    setMessages(updatedMessages);
    setFeedbackOpen(null);

    const allFeedback = JSON.parse(localStorage.getItem('umich_eli_feedback') || '[]');
    allFeedback.push({ 
      personaId: persona.id, 
      scenarioId: scenario.id, 
      messageText: messages[index].text, 
      ...feedback 
    });
    localStorage.setItem('umich_eli_feedback', JSON.stringify(allFeedback));
  };

  const handleDownload = () => {
    const transcript = generateTranscript(persona, scenario, messages);
    downloadFile(transcript, `Portfolio_${persona.name.replace(/\s/g, '_')}_${scenario.title.replace(/\s/g, '_')}.txt`, 'text/plain');
  };

  const handleShare = () => {
    shareToInstructor(persona, scenario);
  };

  useEffect(() => {
    if (scrollRef.current) {
      scrollRef.current.scrollTop = scrollRef.current.scrollHeight;
    }
  }, [messages, isTyping, pendingAlternatives]);

  return (
    <div className="flex flex-col h-full bg-white rounded-3xl overflow-hidden shadow-2xl border-2 border-[#00274C]">
      {/* Header */}
      <div className="p-6 bg-[#00274C] flex flex-col md:flex-row justify-between items-center gap-4 shrink-0">
        <div className="flex items-center gap-4 text-white w-full md:w-auto">
          <img src={persona.avatar} alt={persona.name} className="w-12 h-12 rounded-full border-2 border-[#FFCB05]" />
          <div>
            <h2 className="text-lg font-black">{persona.name}</h2>
            <p className="text-[10px] font-bold text-[#FFCB05] uppercase tracking-widest">{scenario.title}</p>
          </div>
        </div>

        <div className="flex items-center gap-3 w-full md:w-auto justify-end">
          <button 
            onClick={handleDownload}
            disabled={messages.length === 0}
            className="flex items-center gap-2 text-[#FFCB05] hover:text-white font-black text-[10px] uppercase tracking-widest transition-colors border border-[#FFCB05]/30 px-3 py-2 rounded-lg disabled:opacity-30"
          >
            <svg className="w-4 h-4" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M12 10v6m0 0l-3-3m3 3l3-3m2 8H7a2 2 0 01-2-2V5a2 2 0 012-2h5.586a1 1 0 01.707.293l5.414 5.414a1 1 0 01.293.707V19a2 2 0 01-2 2z"/></svg>
            Portfolio
          </button>
          <button 
            onClick={handleShare}
            className="flex items-center gap-2 text-[#FFCB05] hover:text-white font-black text-[10px] uppercase tracking-widest transition-colors border border-[#FFCB05]/30 px-3 py-2 rounded-lg"
          >
            <svg className="w-4 h-4" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M3 8l7.89 5.26a2 2 0 002.22 0L21 8M5 19h14a2 2 0 002-2V7a2 2 0 00-2-2H5a2 2 0 00-2 2v10a2 2 0 002 2z"/></svg>
            Share
          </button>
          <button onClick={onExit} className="text-white bg-red-600/20 hover:bg-red-600/40 font-black text-[10px] uppercase tracking-widest transition-colors border border-red-600/30 px-4 py-2 rounded-lg">Exit</button>
        </div>
      </div>

      {/* Message History */}
      <div ref={scrollRef} className="flex-grow p-6 overflow-y-auto space-y-6 bg-[#F8F9FA]">
        {showBriefing && (
          <div className="mb-8 p-6 bg-[#00274C]/5 border-l-4 border-[#00274C] rounded-r-2xl relative group">
            <button onClick={() => setShowBriefing(false)} className="absolute top-4 right-4 text-[#00274C]/30 hover:text-[#00274C]"><svg className="w-4 h-4" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M6 18L18 6M6 6l12 12" /></svg></button>
            <div className="flex items-center gap-2 mb-2 text-[#00274C]">
              <span className="text-[10px] font-black uppercase tracking-widest">Scenario Briefing</span>
            </div>
            <p className="text-slate-700 text-sm leading-relaxed italic pr-8 font-medium">"{scenario.context}"</p>
          </div>
        )}

        {messages.map((m, i) => (
          <div key={i} className={`flex items-start gap-3 ${m.role === 'user' ? 'flex-row-reverse' : 'flex-row'}`}>
            <div className={`max-w-[80%] space-y-2 ${m.role === 'user' ? 'text-right' : ''}`}>
              <div className={`p-4 rounded-2xl shadow-sm text-sm font-medium ${
                m.role === 'user' ? 'bg-[#00274C] text-white rounded-tr-none' : 'bg-white text-[#00274C] rounded-tl-none border border-[#00274C]/10'
              }`}>
                <div className="flex justify-between items-start gap-4 mb-1">
                  <span className={`text-[10px] uppercase font-black tracking-widest ${m.role === 'user' ? 'text-[#FFCB05]' : 'text-[#00274C]/40'}`}>
                    {m.role === 'user' ? 'You' : persona.name}
                  </span>
                  {m.role === 'model' && (
                    <div className="flex gap-2">
                      <button 
                        onClick={() => playTTS(m.text, i)} 
                        className={`p-1 rounded-lg transition-colors ${isSpeaking === i ? 'bg-[#FFCB05] text-[#00274C]' : 'text-[#00274C]/30 hover:text-[#00274C] hover:bg-[#00274C]/5'}`}
                        title="Hear response"
                      >
                        <svg className={`w-3.5 h-3.5 ${isSpeaking === i ? 'animate-pulse' : ''}`} fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M15.536 8.464a5 5 0 010 7.072m2.828-9.9a9 9 0 010 12.728M5.586 15H4a1 1 0 01-1-1v-4a1 1 0 011-1h1.586l4.707-4.707C10.923 3.663 12 4.109 12 5v14c0 .891-1.077 1.337-1.707.707L5.586 15z"/></svg>
                      </button>
                      <button 
                        onClick={() => setFeedbackOpen(feedbackOpen === i ? null : i)}
                        className={`p-1 rounded-lg transition-colors ${m.feedback ? 'text-[#FFCB05] bg-[#00274C]' : 'text-[#00274C]/30 hover:text-[#00274C] hover:bg-[#00274C]/5'}`}
                        title="Provide assessment"
                      >
                        <svg className="w-3.5 h-3.5" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M11 5H6a2 2 0 00-2 2v11a2 2 0 002 2h11a2 2 0 002-2v-5m-1.414-9.414a2 2 0 112.828 2.828L11.828 15H9v-2.828l8.586-8.586z"/></svg>
                      </button>
                    </div>
                  )}
                </div>
                <p className="leading-relaxed text-left">{m.text}</p>
                {m.feedback && (
                  <div className="mt-3 pt-2 border-t border-[#00274C]/5 flex items-center gap-2">
                    <div className="flex text-[#FFCB05]">
                      {[...Array(m.feedback.rating)].map((_, idx) => (
                        <svg key={idx} className="w-2.5 h-2.5 fill-current" viewBox="0 0 20 20"><path d="M9.049 2.927c.3-.921 1.603-.921 1.902 0l1.07 3.292a1 1 0 00.95.69h3.462c.969 0 1.371 1.24.588 1.81l-2.8 2.034a1 1 0 00-.364 1.118l1.07 3.292c.3.921-.755 1.688-1.54 1.118l-2.8-2.034a1 1 0 00-1.175 0l-2.8 2.034c-.784.57-1.838-.197-1.539-1.118l1.07-3.292a1 1 0 00-.364-1.118L2.98 8.72c-.783-.57-.38-1.81.588-1.81h3.461a1 1 0 00.951-.69l1.07-3.292z"/></svg>
                      ))}
                    </div>
                    <span className="text-[8px] font-black uppercase text-[#00274C]/40 tracking-wider">Assessment Saved</span>
                  </div>
                )}
              </div>
              {feedbackOpen === i && <FeedbackForm onSave={(f) => saveFeedback(i, f)} onCancel={() => setFeedbackOpen(null)} />}
            </div>
          </div>
        ))}

        {/* Alternative Selection UI */}
        {pendingAlternatives && !isTyping && (
          <div className="space-y-4 animate-in fade-in slide-in-from-bottom-4 duration-500 pb-4">
            <div className="flex items-center gap-3">
              <div className="h-px bg-[#00274C]/10 flex-grow"></div>
              <span className="text-[10px] font-black text-[#00274C] uppercase tracking-widest px-2">Choose Response Tone</span>
              <div className="h-px bg-[#00274C]/10 flex-grow"></div>
            </div>
            <div className="grid grid-cols-1 md:grid-cols-3 gap-4">
              {pendingAlternatives.map((alt, idx) => (
                <div 
                  key={idx}
                  onClick={() => handleSelectAlternative(alt)}
                  className="bg-white border-2 border-transparent hover:border-[#00274C] p-5 rounded-2xl shadow-sm hover:shadow-xl cursor-pointer transition-all flex flex-col group relative"
                >
                  <span className="inline-block self-start px-2.5 py-1 mb-4 bg-[#FFCB05] text-[#00274C] rounded-md text-[9px] font-black uppercase tracking-wider group-hover:bg-[#00274C] group-hover:text-[#FFCB05] transition-colors shadow-sm">
                    {alt.label}
                  </span>
                  <p className="text-[#00274C] text-sm leading-snug flex-grow font-medium">{alt.text}</p>
                  <div className="mt-4 flex items-center justify-between opacity-0 group-hover:opacity-100 transition-opacity">
                    <span className="text-[10px] font-black text-[#00274C] uppercase">Select</span>
                    <svg className="w-4 h-4 text-[#00274C]" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M5 13l4 4L19 7"/></svg>
                  </div>
                </div>
              ))}
            </div>
          </div>
        )}

        {isTyping && (
          <div className="flex justify-start">
            <div className="bg-white border border-[#00274C]/10 p-4 rounded-2xl shadow-sm flex items-center gap-3">
              <div className="flex gap-1">
                <div className="w-1.5 h-1.5 bg-[#00274C] rounded-full animate-bounce"></div>
                <div className="w-1.5 h-1.5 bg-[#00274C] rounded-full animate-bounce delay-75"></div>
                <div className="w-1.5 h-1.5 bg-[#00274C] rounded-full animate-bounce delay-150"></div>
              </div>
              <span className="text-[10px] font-black text-[#00274C]/40 uppercase tracking-widest">{persona.name} is formulating options...</span>
            </div>
          </div>
        )}
      </div>

      {/* Input Area */}
      <div className="p-6 bg-white border-t-2 border-[#00274C] shrink-0">
        <form onSubmit={handleSend} className="space-y-3">
          <div className="flex items-center justify-between mb-1">
            <span className={`text-[10px] font-black uppercase tracking-widest ${isListening ? 'text-[#00274C]' : 'text-[#00274C]/30'}`}>
              {pendingAlternatives ? 'Response Selection Required' : isListening ? 'Voice Input Active' : 'Keyboard Entry'}
            </span>
            <div className="flex items-center gap-4">
              <div className="hidden md:flex flex-col items-end gap-1">
                <label className="text-[8px] font-bold text-[#00274C]/40 uppercase tracking-widest">
                  Speech Rate: <span className="text-[#00274C] font-black">{speechRate.toFixed(1)}x</span>
                </label>
                <input 
                  type="range" min="0.5" max="2.0" step="0.1" value={speechRate} 
                  onChange={(e) => setSpeechRate(parseFloat(e.target.value))}
                  className="w-20 h-1 bg-[#F8F9FA] rounded-lg appearance-none cursor-pointer accent-[#00274C]"
                />
              </div>
              <button 
                type="button"
                disabled={!!pendingAlternatives}
                onClick={() => isListening ? recognitionRef.current?.stop() : recognitionRef.current?.start()}
                className={`flex items-center gap-2 px-4 py-1.5 rounded-full text-[10px] font-black uppercase tracking-widest transition-all border-2 ${
                  isListening ? 'bg-[#FFCB05] border-[#00274C] text-[#00274C] animate-pulse' : 'bg-white border-[#00274C]/10 text-[#00274C]/60 hover:border-[#00274C]'
                } ${pendingAlternatives ? 'opacity-30 cursor-not-allowed' : ''}`}
              >
                <svg className="w-3.5 h-3.5" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M19 11a7 7 0 01-7 7m0 0a7 7 0 01-7-7m7 7v4m0 0H8m4 0h4m-4-8a3 3 0 01-3-3V5a3 3 0 116 0v6a3 3 0 01-3 3z"/></svg>
                {isListening ? 'Stop' : 'Dictate'}
              </button>
            </div>
          </div>
          <div className="relative">
            <input
              type="text"
              value={inputValue}
              onChange={(e) => setInputValue(e.target.value)}
              disabled={isTyping || !!pendingAlternatives}
              placeholder={pendingAlternatives ? "Select a response tone above..." : isListening ? "Listening..." : "Type your professional response..."}
              className={`w-full p-4 pr-16 bg-[#F8F9FA] rounded-2xl border-2 outline-none transition-all text-sm font-bold text-[#00274C] ${isListening ? 'border-[#FFCB05] ring-4 ring-[#FFCB05]/10' : 'border-[#00274C]/10 focus:border-[#00274C]'}`}
            />
            <button 
              type="submit" 
              disabled={!inputValue.trim() || isTyping || !!pendingAlternatives} 
              className="absolute right-2 top-2 bottom-2 bg-[#00274C] hover:bg-[#003d77] disabled:bg-slate-300 text-[#FFCB05] px-4 rounded-xl shadow-lg transition-all"
            >
              <svg className="w-5 h-5" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M5 13l4 4L19 7"/></svg>
            </button>
          </div>
        </form>
      </div>
    </div>
  );
};

import React, { useEffect, useRef, useState, useCallback } from 'react';
import { GoogleGenAI, Modality, LiveServerMessage } from '@google/genai';
import { Persona, Feedback, Scenario } from '../types';
import { decode, decodeAudioData, createPcmBlob } from '../services/audioUtils';
import { generateTranscript, downloadFile, shareToInstructor } from '../services/reportUtils';

interface VoiceTurn {
  role: 'user' | 'model';
  text: string;
  feedback?: Feedback;
}

interface VoiceModeProps {
  persona: Persona;
  scenario: Scenario;
  onExit: () => void;
}

export const VoiceMode: React.FC<VoiceModeProps> = ({ persona, scenario, onExit }) => {
  const [isConnected, setIsConnected] = useState(false);
  const [history, setHistory] = useState<VoiceTurn[]>([]);
  const [currentInput, setCurrentInput] = useState("");
  const [currentOutput, setCurrentOutput] = useState("");
  const [isRecording, setIsRecording] = useState(false);

  const canvasRef = useRef<HTMLCanvasElement>(null);
  const sessionRef = useRef<any>(null);
  const audioContextRef = useRef<AudioContext | null>(null);
  const outputContextRef = useRef<AudioContext | null>(null);
  const nextStartTimeRef = useRef<number>(0);
  const sourcesRef = useRef<Set<AudioBufferSourceNode>>(new Set());
  const analyserRef = useRef<AnalyserNode | null>(null);
  const animationFrameRef = useRef<number | null>(null);
  const scrollRef = useRef<HTMLDivElement>(null);

  // Recording Ref
  const mediaRecorderRef = useRef<MediaRecorder | null>(null);
  const audioChunksRef = useRef<Blob[]>([]);

  const cleanup = useCallback(() => {
    if (sessionRef.current) sessionRef.current.close();
    if (audioContextRef.current) audioContextRef.current.close();
    if (outputContextRef.current) outputContextRef.current.close();
    if (animationFrameRef.current) cancelAnimationFrame(animationFrameRef.current);
    if (mediaRecorderRef.current) mediaRecorderRef.current.stop();
    sourcesRef.current.forEach(s => s.stop());
    sourcesRef.current.clear();
  }, []);

  useEffect(() => {
    return cleanup;
  }, [cleanup]);

  useEffect(() => {
    if (scrollRef.current) {
      scrollRef.current.scrollTop = scrollRef.current.scrollHeight;
    }
  }, [history, currentOutput, currentInput]);

  const startSession = async () => {
    try {
      const ai = new GoogleGenAI({ apiKey: process.env.API_KEY || '' });

      audioContextRef.current = new (window.AudioContext || (window as any).webkitAudioContext)({ sampleRate: 16000 });
      outputContextRef.current = new (window.AudioContext || (window as any).webkitAudioContext)({ sampleRate: 24000 });

      const stream = await navigator.mediaDevices.getUserMedia({ audio: true });

      // Setup Local Recording
      const mediaRecorder = new MediaRecorder(stream);
      audioChunksRef.current = [];
      mediaRecorder.ondataavailable = (e) => audioChunksRef.current.push(e.data);
      mediaRecorder.start();
      mediaRecorderRef.current = mediaRecorder;
      setIsRecording(true);

      const source = audioContextRef.current.createMediaStreamSource(stream);
      const analyser = audioContextRef.current.createAnalyser();
      analyser.fftSize = 256;
      source.connect(analyser);
      analyserRef.current = analyser;

      const sessionPromise = ai.live.connect({
        model: 'gemini-2.5-flash-native-audio-preview-12-2025',
        config: {
          responseModalities: [Modality.AUDIO],
          systemInstruction: `${persona.systemInstruction} Current Situation: ${scenario.systemPrompt}. Start by greeting the student in character.`,
          speechConfig: {
            voiceConfig: { prebuiltVoiceConfig: { voiceName: persona.voiceName } }
          },
          outputAudioTranscription: {},
          inputAudioTranscription: {}
        },
        callbacks: {
          onopen: () => {
            setIsConnected(true);
            const scriptProcessor = audioContextRef.current!.createScriptProcessor(4096, 1, 1);
            scriptProcessor.onaudioprocess = (e) => {
              const inputData = e.inputBuffer.getChannelData(0);
              const base64Pcm = createPcmBlob(inputData);
              sessionPromise.then(session => {
                session.sendRealtimeInput({ media: { data: base64Pcm, mimeType: 'audio/pcm;rate=16000' } });
              });
            };
            source.connect(scriptProcessor);
            scriptProcessor.connect(audioContextRef.current!.destination);
            drawVisualizer();
          },
          onmessage: async (message: LiveServerMessage) => {
            if (message.serverContent?.inputTranscription) {
              setCurrentInput(prev => prev + message.serverContent?.inputTranscription?.text);
            }
            if (message.serverContent?.outputTranscription) {
              setCurrentOutput(prev => prev + message.serverContent?.outputTranscription?.text);
            }
            if (message.serverContent?.turnComplete) {
              setHistory(prev => {
                const newHistory = [...prev];
                if (currentInput) newHistory.push({ role: 'user', text: currentInput });
                if (currentOutput) newHistory.push({ role: 'model', text: currentOutput });
                return newHistory;
              });
              setCurrentInput("");
              setCurrentOutput("");
            }
            const audioData = message.serverContent?.modelTurn?.parts[0]?.inlineData?.data;
            if (audioData && outputContextRef.current) {
              const ctx = outputContextRef.current;
              nextStartTimeRef.current = Math.max(nextStartTimeRef.current, ctx.currentTime);
              const buffer = await decodeAudioData(decode(audioData), ctx, 24000, 1);
              const sourceNode = ctx.createBufferSource();
              sourceNode.buffer = buffer;
              sourceNode.connect(ctx.destination);
              sourceNode.onended = () => sourcesRef.current.delete(sourceNode);
              sourceNode.start(nextStartTimeRef.current);
              nextStartTimeRef.current += buffer.duration;
              sourcesRef.current.add(sourceNode);
            }
          },
          onclose: () => setIsConnected(false),
          onerror: (e) => console.error("Live API Error:", e)
        }
      });
      sessionRef.current = await sessionPromise;
    } catch (err) {
      console.error("Failed to start voice session:", err);
    }
  };

  const drawVisualizer = () => {
    if (!canvasRef.current || !analyserRef.current) return;
    const canvas = canvasRef.current;
    const ctx = canvas.getContext('2d');
    if (!ctx) return;
    const bufferLength = analyserRef.current.frequencyBinCount;
    const dataArray = new Uint8Array(bufferLength);
    const render = () => {
      analyserRef.current!.getByteFrequencyData(dataArray);
      ctx.clearRect(0, 0, canvas.width, canvas.height);
      const barWidth = (canvas.width / bufferLength) * 2.5;
      let x = 0;
      for (let i = 0; i < bufferLength; i++) {
        const barHeight = (dataArray[i] / 255) * canvas.height;
        ctx.fillStyle = `#FFCB05`;
        ctx.fillRect(x, canvas.height - barHeight, barWidth, barHeight);
        x += barWidth + 1;
      }
      animationFrameRef.current = requestAnimationFrame(render);
    };
    render();
  };

  const handleDownloadPortfolio = () => {
    // 1. Transcript
    const transcript = generateTranscript(persona, scenario, history);
    downloadFile(transcript, `Portfolio_Voice_${persona.name.replace(/\s/g, '_')}.txt`, 'text/plain');

    // 2. Audio Recording
    if (audioChunksRef.current.length > 0) {
      const audioBlob = new Blob(audioChunksRef.current, { type: 'audio/webm' });
      const url = URL.createObjectURL(audioBlob);
      const a = document.createElement('a');
      a.href = url;
      a.download = `Recording_${persona.name.replace(/\s/g, '_')}.webm`;
      a.click();
      URL.revokeObjectURL(url);
    }
  };

  const handleShare = () => {
    shareToInstructor(persona, scenario);
  };

  return (
    <div className="flex flex-col h-full bg-[#00274C] text-white rounded-3xl overflow-hidden shadow-2xl border-4 border-[#FFCB05]/30">
      <div className="p-6 bg-[#001d3a] border-b border-[#FFCB05]/20 flex justify-between items-center shrink-0">
        <div className="flex items-center gap-4">
          <img src={persona.avatar} alt={persona.name} className="w-12 h-12 rounded-full border-2 border-[#FFCB05]" />
          <div>
            <h2 className="text-xl font-black">{persona.name}</h2>
            <p className="text-[10px] text-[#FFCB05] font-black uppercase tracking-widest">{scenario.title}</p>
          </div>
        </div>

        <div className="flex items-center gap-2">
          {isConnected && (
            <>
              <button 
                onClick={handleDownloadPortfolio}
                className="flex items-center gap-2 text-[#FFCB05] hover:text-white font-black text-[10px] uppercase tracking-widest transition-colors border border-[#FFCB05]/30 px-3 py-2 rounded-lg"
              >
                <svg className="w-4 h-4" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M12 10v6m0 0l-3-3m3 3l3-3m2 8H7a2 2 0 01-2-2V5a2 2 0 012-2h5.586a1 1 0 01.707.293l5.414 5.414a1 1 0 01.293.707V19a2 2 0 01-2 2z"/></svg>
                Portfolio
              </button>
              <button 
                onClick={handleShare}
                className="flex items-center gap-2 text-[#FFCB05] hover:text-white font-black text-[10px] uppercase tracking-widest transition-colors border border-[#FFCB05]/30 px-3 py-2 rounded-lg"
              >
                <svg className="w-4 h-4" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M3 8l7.89 5.26a2 2 0 002.22 0L21 8M5 19h14a2 2 0 002-2V7a2 2 0 00-2-2H5a2 2 0 00-2 2v10a2 2 0 002 2z"/></svg>
                Share
              </button>
            </>
          )}
          <button onClick={onExit} className="bg-red-600/20 hover:bg-red-600/40 text-white px-5 py-2 rounded-lg text-xs font-black uppercase tracking-widest transition-colors border border-red-600/30">End</button>
        </div>
      </div>

      <div className="flex-grow flex flex-col items-center p-8 space-y-6 overflow-hidden">
        {!isConnected ? (
          <div className="text-center space-y-8 my-auto animate-in fade-in zoom-in duration-500">
            <div className="w-32 h-32 bg-[#FFCB05] rounded-full flex items-center justify-center mx-auto shadow-2xl shadow-[#FFCB05]/20 animate-pulse">
               <svg className="w-16 h-16 text-[#00274C]" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M19 11a7 7 0 01-7 7m0 0a7 7 0 01-7-7m7 7v4m0 0H8m4 0h4m-4-8a3 3 0 01-3-3V5a3 3 0 116 0v6a3 3 0 01-3 3z"></path></svg>
            </div>
            <div className="space-y-4">
              <h2 className="text-3xl font-black text-white uppercase tracking-tight">Voice Workspace</h2>
              <p className="text-[#FFCB05]/70 max-w-sm mx-auto text-sm font-medium leading-relaxed italic">" {scenario.context} "</p>
            </div>
            <button onClick={startSession} className="bg-[#FFCB05] hover:bg-[#ffdb4d] text-[#00274C] px-12 py-5 rounded-full font-black text-lg shadow-2xl transition-all transform hover:scale-105 active:scale-95 uppercase tracking-widest">Connect to Faculty</button>
          </div>
        ) : (
          <div className="w-full max-w-2xl h-full flex flex-col space-y-6 overflow-hidden">
            <div className="bg-[#001d3a] p-4 rounded-xl space-y-2 border border-[#FFCB05]/10 shrink-0">
               <div className="flex justify-between items-center text-[10px] font-black uppercase tracking-widest text-[#FFCB05]">
                  <span>Voice Visualizer</span>
                  {isRecording && <span className="flex items-center gap-2 animate-pulse text-red-400">Recording In Progress</span>}
               </div>
               <canvas ref={canvasRef} width={600} height={60} className="w-full rounded-lg opacity-80" />
            </div>

            <div ref={scrollRef} className="flex-grow overflow-y-auto space-y-4 pr-2 custom-scrollbar">
              {history.map((turn, i) => (
                <div key={i} className={`flex flex-col ${turn.role === 'user' ? 'items-end' : 'items-start'}`}>
                  <div className={`p-4 rounded-2xl max-w-[85%] text-sm shadow-md font-medium ${turn.role === 'user' ? 'bg-[#FFCB05] text-[#00274C] rounded-tr-none' : 'bg-[#003d77] text-white rounded-tl-none border border-white/10'}`}>
                    <span className={`text-[10px] font-black uppercase tracking-widest opacity-60 mb-1 block ${turn.role === 'user' ? 'text-[#00274C]' : 'text-[#FFCB05]'}`}>
                      {turn.role === 'user' ? 'You' : persona.name}
                    </span>
                    <p className="leading-relaxed">{turn.text}</p>
                  </div>
                </div>
              ))}
              {(currentInput || currentOutput) && (
                <div className="space-y-3 opacity-60 italic text-[#FFCB05] text-xs font-medium">
                  {currentInput && <div className="text-right">Listening: {currentInput}</div>}
                  {currentOutput && <div className="text-left">{persona.name} responding...</div>}
                </div>
              )}
            </div>
            <div className="flex justify-center shrink-0">
               <div className="px-5 py-2 bg-[#FFCB05]/10 text-[#FFCB05] rounded-full text-[10px] font-black uppercase tracking-widest border border-[#FFCB05]/30 animate-pulse">Live Practice Active</div>
            </div>
          </div>
        )}
      </div>
      <style>{`.custom-scrollbar::-webkit-scrollbar { width: 4px; } .custom-scrollbar::-webkit-scrollbar-track { background: transparent; } .custom-scrollbar::-webkit-scrollbar-thumb { background: #FFCB05; border-radius: 10px; }`}</style>
    </div>
  );
};

export function encode(bytes: Uint8Array): string {
  let binary = '';
  const len = bytes.byteLength;
  for (let i = 0; i < len; i++) {
    binary += String.fromCharCode(bytes[i]);
  }
  return btoa(binary);
}

export function decode(base64: string): Uint8Array {
  const binaryString = atob(base64);
  const len = binaryString.length;
  const bytes = new Uint8Array(len);
  for (let i = 0; i < len; i++) {
    bytes[i] = binaryString.charCodeAt(i);
  }
  return bytes;
}

export async function decodeAudioData(
  data: Uint8Array,
  ctx: AudioContext,
  sampleRate: number,
  numChannels: number,
): Promise<AudioBuffer> {
  const dataInt16 = new Int16Array(data.buffer);
  const frameCount = dataInt16.length / numChannels;
  const buffer = ctx.createBuffer(numChannels, frameCount, sampleRate);

  for (let channel = 0; channel < numChannels; channel++) {
    const channelData = buffer.getChannelData(channel);
    for (let i = 0; i < frameCount; i++) {
      channelData[i] = dataInt16[i * numChannels + channel] / 32768.0;
    }
  }
  return buffer;
}

export function createPcmBlob(data: Float32Array): string {
  const l = data.length;
  const int16 = new Int16Array(l);
  for (let i = 0; i < l; i++) {
    int16[i] = data[i] * 32768;
  }
  return encode(new Uint8Array(int16.buffer));
}

/**
 * Creates a WAV file Blob from raw 16-bit PCM data.
 * @param pcmData The raw PCM bytes (16-bit)
 * @param sampleRate The sample rate (e.g., 24000)
 */
export function createWavBlob(pcmData: Uint8Array, sampleRate: number): Blob {
  const header = new ArrayBuffer(44);
  const view = new DataView(header);

  const writeString = (offset: number, string: string) => {
    for (let i = 0; i < string.length; i++) {
      view.setUint8(offset + i, string.charCodeAt(i));
    }
  };

  /* RIFF identifier */
  writeString(0, 'RIFF');
  /* file length */
  view.setUint32(4, 36 + pcmData.length, true);
  /* RIFF type */
  writeString(8, 'WAVE');
  /* format chunk identifier */
  writeString(12, 'fmt ');
  /* format chunk length */
  view.setUint32(16, 16, true);
  /* sample format (raw) */
  view.setUint16(20, 1, true);
  /* channel count */
  view.setUint16(22, 1, true);
  /* sample rate */
  view.setUint32(24, sampleRate, true);
  /* byte rate (sample rate * block align) */
  view.setUint32(28, sampleRate * 2, true);
  /* block align (channel count * bytes per sample) */
  view.setUint16(32, 2, true);
  /* bits per sample */
  view.setUint16(34, 16, true);
  /* data chunk identifier */
  writeString(36, 'data');
  /* data chunk length */
  view.setUint32(40, pcmData.length, true);

  return new Blob([header, pcmData], { type: 'audio/wav' });
}

import React, { useState, useEffect, useRef } from 'react';
import { GoogleGenAI, Modality, Type } from '@google/genai';
import { Persona, Message, Feedback, Scenario } from '../types';
import { decode, decodeAudioData, createWavBlob } from '../services/audioUtils';
import { FeedbackForm } from './FeedbackForm';
import { generateTranscript, downloadFile, shareToInstructor } from '../services/reportUtils';

interface TextModeProps {
  persona: Persona;
  scenario: Scenario;
  onExit: () => void;
}

interface Alternative {
  text: string;
  label: string;
}

export const TextMode: React.FC<TextModeProps> = ({ persona, scenario, onExit }) => {
  const [messages, setMessages] = useState<Message[]>([]);
  const [inputValue, setInputValue] = useState("");
  const [isTyping, setIsTyping] = useState(false);
  const [isSpeaking, setIsSpeaking] = useState<number | null>(null);
  const [isDownloading, setIsDownloading] = useState<number | null>(null);
  const [isListening, setIsListening] = useState(false);
  const [feedbackOpen, setFeedbackOpen] = useState<number | null>(null);
  const [showBriefing, setShowBriefing] = useState(true);
  const [speechRate, setSpeechRate] = useState(1.0);
  const [pendingAlternatives, setPendingAlternatives] = useState<Alternative[] | null>(null);

  const scrollRef = useRef<HTMLDivElement>(null);
  const audioContextRef = useRef<AudioContext | null>(null);
  const recognitionRef = useRef<any>(null);
  const currentAudioSourceRef = useRef<AudioBufferSourceNode | null>(null);

  const getAIResponse = async (history: Message[]) => {
    setIsTyping(true);
    setPendingAlternatives(null);
    try {
      const ai = new GoogleGenAI({ apiKey: process.env.API_KEY || '' });

      const contents = history.map(m => ({
        role: m.role,
        parts: [{ text: m.text }]
      }));

      const systemInstruction = `You are ${persona.name}, ${persona.title}. ${persona.systemInstruction} 
      Current Situation: ${scenario.systemPrompt} 
      Task: Provide 3 alternative ways you would respond to the student right now. 
      Vary the tone slightly for each (e.g., one more direct, one more supportive, one more formal) while staying in character. 
      Keep each response between 1-3 sentences.`;

      const response = await ai.models.generateContent({
        model: 'gemini-3-flash-preview',
        contents,
        config: {
          systemInstruction,
          responseMimeType: "application/json",
          responseSchema: {
            type: Type.OBJECT,
            properties: {
              options: {
                type: Type.ARRAY,
                items: {
                  type: Type.OBJECT,
                  properties: {
                    text: { type: Type.STRING, description: "The response text." },
                    label: { type: Type.STRING, description: "A short tone label (e.g., 'Direct', 'Formal', 'Supportive')." }
                  },
                  required: ["text", "label"]
                },
                minItems: 3,
                maxItems: 3
              }
            },
            required: ["options"]
          }
        }
      });

      const jsonStr = response.text.trim();
      const data = JSON.parse(jsonStr);
      setPendingAlternatives(data.options);
    } catch (err) {
      console.error("AI Error:", err);
    } finally {
      setIsTyping(false);
    }
  };

  useEffect(() => {
    getAIResponse([]);

    const SpeechRecognition = (window as any).SpeechRecognition || (window as any).webkitRecognition || (window as any).webkitSpeechRecognition;
    if (SpeechRecognition) {
      recognitionRef.current = new SpeechRecognition();
      recognitionRef.current.continuous = false; 
      recognitionRef.current.interimResults = true;
      recognitionRef.current.lang = 'en-US';
      recognitionRef.current.onresult = (event: any) => {
        const transcript = Array.from(event.results)
          .map((result: any) => result[0])
          .map((result: any) => result.transcript)
          .join('');
        setInputValue(transcript);
      };
      recognitionRef.current.onstart = () => setIsListening(true);
      recognitionRef.current.onend = () => setIsListening(false);
    }

    return () => {
      if (audioContextRef.current) audioContextRef.current.close();
      if (recognitionRef.current) recognitionRef.current.stop();
      if (currentAudioSourceRef.current) currentAudioSourceRef.current.stop();
    };
  }, [persona, scenario]);

  const playTTS = async (text: string, index: number) => {
    if (currentAudioSourceRef.current) {
      try { currentAudioSourceRef.current.stop(); } catch (e) {}
      currentAudioSourceRef.current = null;
    }

    setIsSpeaking(index);
    try {
      const ai = new GoogleGenAI({ apiKey: process.env.API_KEY || '' });
      const response = await ai.models.generateContent({
        model: "gemini-2.5-flash-preview-tts",
        contents: [{ parts: [{ text }] }],
        config: {
          responseModalities: [Modality.AUDIO],
          speechConfig: {
            voiceConfig: { prebuiltVoiceConfig: { voiceName: persona.voiceName } },
          },
        },
      });

      const audioData = response.candidates?.[0]?.content?.parts?.[0]?.inlineData?.data;
      if (audioData) {
        if (!audioContextRef.current) {
          audioContextRef.current = new (window.AudioContext || (window as any).webkitAudioContext)({ sampleRate: 24000 });
        }
        const buffer = await decodeAudioData(decode(audioData), audioContextRef.current, 24000, 1);
        const source = audioContextRef.current.createBufferSource();
        source.buffer = buffer;
        source.playbackRate.value = speechRate;
        source.connect(audioContextRef.current.destination);
        source.onended = () => {
          if (currentAudioSourceRef.current === source) {
            setIsSpeaking(null);
            currentAudioSourceRef.current = null;
          }
        };
        currentAudioSourceRef.current = source;
        source.start();
      }
    } catch (err) {
      console.error("TTS Error:", err);
      setIsSpeaking(null);
    }
  };

  const handleDownloadAudio = async (text: string, index: number) => {
    setIsDownloading(index);
    try {
      const ai = new GoogleGenAI({ apiKey: process.env.API_KEY || '' });
      const response = await ai.models.generateContent({
        model: "gemini-2.5-flash-preview-tts",
        contents: [{ parts: [{ text }] }],
        config: {
          responseModalities: [Modality.AUDIO],
          speechConfig: {
            voiceConfig: { prebuiltVoiceConfig: { voiceName: persona.voiceName } },
          },
        },
      });

      const audioData = response.candidates?.[0]?.content?.parts?.[0]?.inlineData?.data;
      if (audioData) {
        const pcmBytes = decode(audioData);
        const wavBlob = createWavBlob(pcmBytes, 24000);
        const url = URL.createObjectURL(wavBlob);
        const a = document.createElement('a');
        a.href = url;
        a.download = `Audio_${persona.name.replace(/\s/g, '_')}_Turn${index + 1}.wav`;
        a.click();
        URL.revokeObjectURL(url);
      }
    } catch (err) {
      console.error("Download Error:", err);
    } finally {
      setIsDownloading(null);
    }
  };

  const handleSelectAlternative = (alt: Alternative) => {
    const newMessage: Message = { role: 'model', text: alt.text, timestamp: Date.now() };
    const updatedMessages = [...messages, newMessage];
    setMessages(updatedMessages);
    setPendingAlternatives(null);
    playTTS(alt.text, updatedMessages.length - 1);
  };

  const handleSend = async (e?: React.FormEvent) => {
    e?.preventDefault();
    if (!inputValue.trim() || isTyping || pendingAlternatives) return;

    const userMsg: Message = { role: 'user', text: inputValue, timestamp: Date.now() };
    const newHistory = [...messages, userMsg];
    setMessages(newHistory);
    setInputValue("");
    getAIResponse(newHistory);
  };

  const saveFeedback = (index: number, feedback: Feedback) => {
    const updatedMessages = [...messages];
    updatedMessages[index].feedback = feedback;
    setMessages(updatedMessages);
    setFeedbackOpen(null);

    const allFeedback = JSON.parse(localStorage.getItem('umich_eli_feedback') || '[]');
    allFeedback.push({ 
      personaId: persona.id, 
      scenarioId: scenario.id, 
      messageText: messages[index].text, 
      ...feedback 
    });
    localStorage.setItem('umich_eli_feedback', JSON.stringify(allFeedback));
  };

  const handleDownload = () => {
    const transcript = generateTranscript(persona, scenario, messages);
    downloadFile(transcript, `Portfolio_${persona.name.replace(/\s/g, '_')}_${scenario.title.replace(/\s/g, '_')}.txt`, 'text/plain');
  };

  const handleShare = () => {
    shareToInstructor(persona, scenario);
  };

  useEffect(() => {
    if (scrollRef.current) {
      scrollRef.current.scrollTop = scrollRef.current.scrollHeight;
    }
  }, [messages, isTyping, pendingAlternatives]);

  return (
    <div className="flex flex-col h-full bg-white rounded-3xl overflow-hidden shadow-2xl border-2 border-[#00274C]">
      {/* Header */}
      <div className="p-6 bg-[#00274C] flex flex-col md:flex-row justify-between items-center gap-4 shrink-0">
        <div className="flex items-center gap-4 text-white w-full md:w-auto">
          <img src={persona.avatar} alt={persona.name} className="w-12 h-12 rounded-full border-2 border-[#FFCB05]" />
          <div>
            <h2 className="text-lg font-black">{persona.name}</h2>
            <p className="text-[10px] font-bold text-[#FFCB05] uppercase tracking-widest">{scenario.title}</p>
          </div>
        </div>

        <div className="flex items-center gap-3 w-full md:w-auto justify-end">
          <button 
            onClick={handleDownload}
            disabled={messages.length === 0}
            className="flex items-center gap-2 text-[#FFCB05] hover:text-white font-black text-[10px] uppercase tracking-widest transition-colors border border-[#FFCB05]/30 px-3 py-2 rounded-lg disabled:opacity-30"
          >
            <svg className="w-4 h-4" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M12 10v6m0 0l-3-3m3 3l3-3m2 8H7a2 2 0 01-2-2V5a2 2 0 012-2h5.586a1 1 0 01.707.293l5.414 5.414a1 1 0 01.293.707V19a2 2 0 01-2 2z"/></svg>
            Portfolio
          </button>
          <button 
            onClick={handleShare}
            className="flex items-center gap-2 text-[#FFCB05] hover:text-white font-black text-[10px] uppercase tracking-widest transition-colors border border-[#FFCB05]/30 px-3 py-2 rounded-lg"
          >
            <svg className="w-4 h-4" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M3 8l7.89 5.26a2 2 0 002.22 0L21 8M5 19h14a2 2 0 002-2V7a2 2 0 00-2-2H5a2 2 0 00-2 2v10a2 2 0 002 2z"/></svg>
            Share
          </button>
          <button onClick={onExit} className="text-white bg-red-600/20 hover:bg-red-600/40 font-black text-[10px] uppercase tracking-widest transition-colors border border-red-600/30 px-4 py-2 rounded-lg">Exit</button>
        </div>
      </div>

      {/* Message History */}
      <div ref={scrollRef} className="flex-grow p-6 overflow-y-auto space-y-6 bg-[#F8F9FA]">
        {showBriefing && (
          <div className="mb-8 p-6 bg-[#00274C]/5 border-l-4 border-[#00274C] rounded-r-2xl relative group">
            <button onClick={() => setShowBriefing(false)} className="absolute top-4 right-4 text-[#00274C]/30 hover:text-[#00274C]"><svg className="w-4 h-4" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M6 18L18 6M6 6l12 12" /></svg></button>
            <div className="flex items-center gap-2 mb-2 text-[#00274C]">
              <span className="text-[10px] font-black uppercase tracking-widest">Scenario Briefing</span>
            </div>
            <p className="text-slate-700 text-sm leading-relaxed italic pr-8 font-medium">"{scenario.context}"</p>
          </div>
        )}

        {messages.map((m, i) => (
          <div key={i} className={`flex items-start gap-3 ${m.role === 'user' ? 'flex-row-reverse' : 'flex-row'}`}>
            <div className={`max-w-[80%] space-y-2 ${m.role === 'user' ? 'text-right' : ''}`}>
              <div className={`p-4 rounded-2xl shadow-sm text-sm font-medium ${
                m.role === 'user' ? 'bg-[#00274C] text-white rounded-tr-none' : 'bg-white text-[#00274C] rounded-tl-none border border-[#00274C]/10'
              }`}>
                <div className="flex justify-between items-start gap-4 mb-1">
                  <span className={`text-[10px] uppercase font-black tracking-widest ${m.role === 'user' ? 'text-[#FFCB05]' : 'text-[#00274C]/40'}`}>
                    {m.role === 'user' ? 'You' : persona.name}
                  </span>
                  {m.role === 'model' && (
                    <div className="flex gap-2">
                      <button 
                        onClick={() => playTTS(m.text, i)} 
                        className={`p-1 rounded-lg transition-colors ${isSpeaking === i ? 'bg-[#FFCB05] text-[#00274C]' : 'text-[#00274C]/30 hover:text-[#00274C] hover:bg-[#00274C]/5'}`}
                        title="Hear response"
                      >
                        <svg className={`w-3.5 h-3.5 ${isSpeaking === i ? 'animate-pulse' : ''}`} fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M15.536 8.464a5 5 0 010 7.072m2.828-9.9a9 9 0 010 12.728M5.586 15H4a1 1 0 01-1-1v-4a1 1 0 011-1h1.586l4.707-4.707C10.923 3.663 12 4.109 12 5v14c0 .891-1.077 1.337-1.707.707L5.586 15z"/></svg>
                      </button>
                      <button 
                        onClick={() => handleDownloadAudio(m.text, i)} 
                        className={`p-1 rounded-lg transition-colors ${isDownloading === i ? 'bg-[#FFCB05] text-[#00274C]' : 'text-[#00274C]/30 hover:text-[#00274C] hover:bg-[#00274C]/5'}`}
                        title="Download Audio"
                        disabled={isDownloading !== null}
                      >
                        <svg className={`w-3.5 h-3.5 ${isDownloading === i ? 'animate-bounce' : ''}`} fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M4 16v1a2 2 0 002 2h12a2 2 0 002-2v-1m-4-4l-4 4m0 0l-4-4m4 4V4"/></svg>
                      </button>
                      <button 
                        onClick={() => setFeedbackOpen(feedbackOpen === i ? null : i)}
                        className={`p-1 rounded-lg transition-colors ${m.feedback ? 'text-[#FFCB05] bg-[#00274C]' : 'text-[#00274C]/30 hover:text-[#00274C] hover:bg-[#00274C]/5'}`}
                        title="Provide assessment"
                      >
                        <svg className="w-3.5 h-3.5" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M11 5H6a2 2 0 00-2 2v11a2 2 0 002 2h11a2 2 0 002-2v-5m-1.414-9.414a2 2 0 112.828 2.828L11.828 15H9v-2.828l8.586-8.586z"/></svg>
                      </button>
                    </div>
                  )}
                </div>
                <p className="leading-relaxed text-left">{m.text}</p>
                {m.feedback && (
                  <div className="mt-3 pt-2 border-t border-[#00274C]/5 flex items-center gap-2">
                    <div className="flex text-[#FFCB05]">
                      {[...Array(m.feedback.rating)].map((_, idx) => (
                        <svg key={idx} className="w-2.5 h-2.5 fill-current" viewBox="0 0 20 20"><path d="M9.049 2.927c.3-.921 1.603-.921 1.902 0l1.07 3.292a1 1 0 00.95.69h3.462c.969 0 1.371 1.24.588 1.81l-2.8 2.034a1 1 0 00-.364 1.118l1.07 3.292c.3.921-.755 1.688-1.54 1.118l-2.8-2.034a1 1 0 00-1.175 0l-2.8 2.034c-.784.57-1.838-.197-1.539-1.118l1.07-3.292a1 1 0 00-.364-1.118L2.98 8.72c-.783-.57-.38-1.81.588-1.81h3.461a1 1 0 00.951-.69l1.07-3.292z"/></svg>
                      ))}
                    </div>
                    <span className="text-[8px] font-black uppercase text-[#00274C]/40 tracking-wider">Assessment Saved</span>
                  </div>
                )}
              </div>
              {feedbackOpen === i && <FeedbackForm onSave={(f) => saveFeedback(i, f)} onCancel={() => setFeedbackOpen(null)} />}
            </div>
          </div>
        ))}

        {/* Alternative Selection UI */}
        {pendingAlternatives && !isTyping && (
          <div className="space-y-4 animate-in fade-in slide-in-from-bottom-4 duration-500 pb-4">
            <div className="flex items-center gap-3">
              <div className="h-px bg-[#00274C]/10 flex-grow"></div>
              <span className="text-[10px] font-black text-[#00274C] uppercase tracking-widest px-2">Choose Response Tone</span>
              <div className="h-px bg-[#00274C]/10 flex-grow"></div>
            </div>
            <div className="grid grid-cols-1 md:grid-cols-3 gap-4">
              {pendingAlternatives.map((alt, idx) => (
                <div 
                  key={idx}
                  onClick={() => handleSelectAlternative(alt)}
                  className="bg-white border-2 border-transparent hover:border-[#00274C] p-5 rounded-2xl shadow-sm hover:shadow-xl cursor-pointer transition-all flex flex-col group relative"
                >
                  <span className="inline-block self-start px-2.5 py-1 mb-4 bg-[#FFCB05] text-[#00274C] rounded-md text-[9px] font-black uppercase tracking-wider group-hover:bg-[#00274C] group-hover:text-[#FFCB05] transition-colors shadow-sm">
                    {alt.label}
                  </span>
                  <p className="text-[#00274C] text-sm leading-snug flex-grow font-medium">{alt.text}</p>
                  <div className="mt-4 flex items-center justify-between opacity-0 group-hover:opacity-100 transition-opacity">
                    <span className="text-[10px] font-black text-[#00274C] uppercase">Select</span>
                    <svg className="w-4 h-4 text-[#00274C]" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M5 13l4 4L19 7"/></svg>
                  </div>
                </div>
              ))}
            </div>
          </div>
        )}

        {isTyping && (
          <div className="flex justify-start">
            <div className="bg-white border border-[#00274C]/10 p-4 rounded-2xl shadow-sm flex items-center gap-3">
              <div className="flex gap-1">
                <div className="w-1.5 h-1.5 bg-[#00274C] rounded-full animate-bounce"></div>
                <div className="w-1.5 h-1.5 bg-[#00274C] rounded-full animate-bounce delay-75"></div>
                <div className="w-1.5 h-1.5 bg-[#00274C] rounded-full animate-bounce delay-150"></div>
              </div>
              <span className="text-[10px] font-black text-[#00274C]/40 uppercase tracking-widest">{persona.name} is formulating options...</span>
            </div>
          </div>
        )}
      </div>

      {/* Input Area */}
      <div className="p-6 bg-white border-t-2 border-[#00274C] shrink-0">
        <form onSubmit={handleSend} className="space-y-3">
          <div className="flex items-center justify-between mb-1">
            <span className={`text-[10px] font-black uppercase tracking-widest ${isListening ? 'text-[#00274C]' : 'text-[#00274C]/30'}`}>
              {pendingAlternatives ? 'Response Selection Required' : isListening ? 'Voice Input Active' : 'Keyboard Entry'}
            </span>
            <div className="flex items-center gap-4">
              <div className="hidden md:flex flex-col items-end gap-1">
                <label className="text-[8px] font-bold text-[#00274C]/40 uppercase tracking-widest">
                  Speech Rate: <span className="text-[#00274C] font-black">{speechRate.toFixed(1)}x</span>
                </label>
                <input 
                  type="range" min="0.5" max="2.0" step="0.1" value={speechRate} 
                  onChange={(e) => setSpeechRate(parseFloat(e.target.value))}
                  className="w-20 h-1 bg-[#F8F9FA] rounded-lg appearance-none cursor-pointer accent-[#00274C]"
                />
              </div>
              <button 
                type="button"
                disabled={!!pendingAlternatives}
                onClick={() => isListening ? recognitionRef.current?.stop() : recognitionRef.current?.start()}
                className={`flex items-center gap-2 px-4 py-1.5 rounded-full text-[10px] font-black uppercase tracking-widest transition-all border-2 ${
                  isListening ? 'bg-[#FFCB05] border-[#00274C] text-[#00274C] animate-pulse' : 'bg-white border-[#00274C]/10 text-[#00274C]/60 hover:border-[#00274C]'
                } ${pendingAlternatives ? 'opacity-30 cursor-not-allowed' : ''}`}
              >
                <svg className="w-3.5 h-3.5" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M19 11a7 7 0 01-7 7m0 0a7 7 0 01-7-7m7 7v4m0 0H8m4 0h4m-4-8a3 3 0 01-3-3V5a3 3 0 116 0v6a3 3 0 01-3 3z"/></svg>
                {isListening ? 'Stop' : 'Dictate'}
              </button>
            </div>
          </div>
          <div className="relative">
            <input
              type="text"
              value={inputValue}
              onChange={(e) => setInputValue(e.target.value)}
              disabled={isTyping || !!pendingAlternatives}
              placeholder={pendingAlternatives ? "Select a response tone above..." : isListening ? "Listening..." : "Type your professional response..."}
              className={`w-full p-4 pr-16 bg-[#F8F9FA] rounded-2xl border-2 outline-none transition-all text-sm font-bold text-[#00274C] ${isListening ? 'border-[#FFCB05] ring-4 ring-[#FFCB05]/10' : 'border-[#00274C]/10 focus:border-[#00274C]'}`}
            />
            <button 
              type="submit" 
              disabled={!inputValue.trim() || isTyping || !!pendingAlternatives} 
              className="absolute right-2 top-2 bottom-2 bg-[#00274C] hover:bg-[#003d77] disabled:bg-slate-300 text-[#FFCB05] px-4 rounded-xl shadow-lg transition-all"
            >
              <svg className="w-5 h-5" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M5 13l4 4L19 7"/></svg>
            </button>
          </div>
        </form>
      </div>
    </div>
  );
};

