          </div>
        ) : !session.scenario ? (
          <div className="max-w-4xl mx-auto space-y-12 animate-in fade-in slide-in-from-bottom duration-500">
            <button onClick={resetToPersona} className="flex items-center gap-2 text-[#00274C]/60 hover:text-[#00274C] transition-colors font-bold text-sm uppercase tracking-wider">
              <svg className="w-4 h-4" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M15 19l-7-7 7-7"/></svg>
              Back to personas
            </button>

            <div className="text-center space-y-4">
              <h2 className="text-3xl font-extrabold text-[#00274C] tracking-tight">Select a Practice Scenario</h2>
              <p className="text-slate-500">Choose a specific situation to navigate with {session.persona.name}.</p>
            </div>

            <div className="grid grid-cols-1 md:grid-cols-2 gap-6">
              {session.persona.scenarios.map(s => (
                <div 
                  key={s.id} 
                  onClick={() => handleSelectScenario(s)}
                  className="bg-white border-2 border-slate-100 hover:border-[#00274C] rounded-3xl p-8 cursor-pointer transition-all hover:shadow-xl group"
                >
                  <h3 className="text-xl font-bold text-[#00274C] mb-3 group-hover:text-[#00274C]">{s.title}</h3>
                  <p className="text-slate-600 text-sm leading-relaxed mb-6">{s.context}</p>
                  <div className="flex items-center gap-2 text-xs font-bold text-[#00274C] uppercase tracking-widest bg-[#FFCB05]/10 self-start px-3 py-1.5 rounded-full">
                    <span>Select this situation</span>
                    <svg className="w-3 h-3 group-hover:translate-x-1 transition-transform" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M17 8l4 4m0 0l-4 4m4-4H3"/></svg>
                  </div>
                </div>
              ))}
            </div>
