        ) : (
          <div className="max-w-4xl mx-auto space-y-12 animate-in fade-in slide-in-from-bottom duration-500">
            <button onClick={resetToScenario} className="flex items-center gap-2 text-[#00274C]/60 hover:text-[#00274C] transition-colors font-bold text-sm uppercase tracking-wider">
              <svg className="w-4 h-4" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M15 19l-7-7 7-7"/></svg>
              Change scenario
            </button>

            <div className="bg-white rounded-[2rem] p-10 md:p-14 shadow-2xl border-t-8 border-[#FFCB05] flex flex-col md:flex-row gap-12 items-center relative overflow-hidden">
              <div className="absolute top-0 right-0 p-8 opacity-[0.05] pointer-events-none">
                 <svg className="w-64 h-64 text-[#00274C]" fill="currentColor" viewBox="0 0 24 24"><path d="M12 2C6.48 2 2 6.48 2 12s4.48 10 10 10 10-4.48 10-10S17.52 2 12 2zm1 15h-2v-6h2v6zm0-8h-2V7h2v2z"/></svg>
              </div>

              <div className="w-48 h-48 flex-shrink-0 z-10">
                <img src={session.persona.avatar} alt={session.persona.name} className="w-full h-full rounded-3xl object-cover shadow-2xl border-4 border-[#00274C]/10" />
              </div>
              <div className="space-y-6 flex-grow z-10 text-center md:text-left">
                <div>
                  <h2 className="text-3xl font-black text-[#00274C]">{session.persona.name}</h2>
                  <p className="text-[#00274C]/70 font-bold uppercase tracking-wider text-xs mb-2">{session.persona.title}</p>
                  <div className="inline-block px-4 py-1.5 bg-[#FFCB05] text-[#00274C] rounded-full text-[10px] font-black uppercase tracking-widest shadow-sm">
                    Scenario: {session.scenario.title}
                  </div>
                </div>

                <p className="text-slate-700 leading-relaxed italic text-sm border-l-4 border-[#FFCB05] pl-4 py-1">
                  "{session.scenario.context}"
                </p>

                <div className="flex flex-col sm:flex-row gap-4 pt-4">
                  <button 
                    onClick={() => startSession('text')}
                    className="flex-1 bg-white border-2 border-[#00274C] text-[#00274C] py-4 px-6 rounded-2xl font-black uppercase tracking-wider text-xs transition-all flex items-center justify-center gap-3 shadow-sm hover:bg-[#00274C] hover:text-[#FFCB05]"
                  >
                    <svg className="w-5 h-5" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M8 10h.01M12 10h.01M16 10h.01M9 16H5a2 2 0 01-2-2V6a2 2 0 012-2h14a2 2 0 012 2v8a2 2 0 01-2 2h-5l-5 5v-5z"></path></svg>
                    Turn-based Text
                  </button>
                  <button 
                    onClick={() => startSession('voice')}
                    className="flex-1 bg-[#00274C] text-[#FFCB05] py-4 px-6 rounded-2xl font-black uppercase tracking-wider text-xs transition-all flex items-center justify-center gap-3 shadow-xl hover:bg-[#003d77]"
                  >
                    <svg className="w-5 h-5" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M19 11a7 7 0 01-7 7m0 0a7 7 0 01-7-7m7 7v4m0 0H8m4 0h4m-4-8a3 3 0 01-3-3V5a3 3 0 116 0v6a3 3 0 01-3 3z"></path></svg>
                    Real-time Voice
