            <div className="text-center space-y-4">
              <h2 className="text-3xl font-extrabold text-[#00274C] tracking-tight">Select a Practice Scenario</h2>
              <p className="text-slate-500">Choose a specific situation to navigate with {session.persona.name}.</p>
