                <div className="flex flex-col sm:flex-row gap-4 pt-4">
                  <button 
                    onClick={() => startSession('text')}
                    className="flex-1 bg-white border-2 border-[#00274C] text-[#00274C] py-4 px-6 rounded-2xl font-black uppercase tracking-wider text-xs transition-all flex items-center justify-center gap-3 shadow-sm hover:bg-[#00274C] hover:text-[#FFCB05]"
                  >
                    <svg className="w-5 h-5" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M8 10h.01M12 10h.01M16 10h.01M9 16H5a2 2 0 01-2-2V6a2 2 0 012-2h14a2 2 0 012 2v8a2 2 0 01-2 2h-5l-5 5v-5z"></path></svg>
                    Turn-based Text
                  </button>
                  <button 
                    onClick={() => startSession('voice')}
                    className="flex-1 bg-[#00274C] text-[#FFCB05] py-4 px-6 rounded-2xl font-black uppercase tracking-wider text-xs transition-all flex items-center justify-center gap-3 shadow-xl hover:bg-[#003d77]"
                  >
                    <svg className="w-5 h-5" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M19 11a7 7 0 01-7 7m0 0a7 7 0 01-7-7m7 7v4m0 0H8m4 0h4m-4-8a3 3 0 01-3-3V5a3 3 0 116 0v6a3 3 0 01-3 3z"></path></svg>
                    Real-time Voice
                  </button>
                </div>
              </div>
            </div>
          </div>
        )}
      </main>

      <footer className="bg-[#00274C] border-t border-[#FFCB05] py-10 mt-12 shrink-0">
        <div className="max-w-7xl mx-auto px-6 text-center text-white/40 text-[10px] font-bold uppercase tracking-widest">
          <p>© 2024 PRACTICE HIGH-STAKES ACADEMIC ENGLISH SIMULATOR</p>
        </div>
      </footer>
