          <div className="max-w-3xl text-white/90 text-xs md:text-sm font-medium text-center lg:text-right leading-relaxed italic border-t lg:border-t-0 lg:border-r-4 border-[#FFCB05] pt-4 lg:pt-0 lg:pr-6">
