                <div className="flex flex-col sm:flex-row gap-5 pt-6">
                  <button 
                    onClick={() => startSession('text')}
                    className="flex-1 bg-white border-4 border-[#00274C] text-[#00274C] py-5 px-8 rounded-2xl font-black uppercase tracking-widest text-xs transition-all flex items-center justify-center gap-3 shadow-sm hover:bg-[#00274C] hover:text-[#FFCB05] active:scale-95"
                  >
                    <svg className="w-6 h-6" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M8 10h.01M12 10h.01M16 10h.01M9 16H5a2 2 0 01-2-2V6a2 2 0 012-2h14a2 2 0 012 2v8a2 2 0 01-2 2h-5l-5 5v-5z"></path></svg>
                    Turn-based Text
                  </button>
                  <button 
                    onClick={() => startSession('voice')}
                    className="flex-1 bg-[#00274C] text-[#FFCB05] py-5 px-8 rounded-2xl font-black uppercase tracking-widest text-xs transition-all flex items-center justify-center gap-3 shadow-xl hover:bg-[#003d77] active:scale-95 border-4 border-[#00274C]"
                  >
                    <svg className="w-6 h-6" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M19 11a7 7 0 01-7 7m0 0a7 7 0 01-7-7m7 7v4m0 0H8m4 0h4m-4-8a3 3 0 01-3-3V5a3 3 0 116 0v6a3 3 0 01-3 3z"></path></svg>
                    Real-time Voice
                  </button>
                </div>
              </div>
            </div>
          </div>
        )}
      </main>

      <footer className="bg-[#00274C] border-t-8 border-[#FFCB05] pt-20 pb-12 shrink-0 text-white relative">
        <div className="max-w-7xl mx-auto px-6 grid grid-cols-1 lg:grid-cols-3 gap-16 mb-16">
          {/* How To Use */}
          <section className="space-y-8">
            <h3 className="text-[#FFCB05] font-black uppercase tracking-[0.2em] text-xs border-b-2 border-[#FFCB05]/30 pb-3">Training Protocol</h3>
            <ul className="space-y-6">
              {[
                { step: '01', title: 'Choose Mentor', text: 'Select a professional or academic authority.' },
                { step: '02', title: 'Set Context', text: 'Define the high-stakes situation for simulation.' },
                { step: '03', title: 'Engage', text: 'Converse via Text (deliberate) or Voice (natural flow).' },
                { step: '04', title: 'Study & Save', text: 'Flag key AI responses and download your Portfolio (Audio/Transcript) to share with your instructor.' }
              ].map((item, idx) => (
                <li key={idx} className="flex gap-4">
                  <span className="text-[#FFCB05] font-black text-xs pt-1">{item.step}</span>
                  <div>
                    <h4 className="font-black uppercase text-[11px] mb-1 tracking-wider">{item.title}</h4>
