          <section className="space-y-8 lg:col-span-2">
            <h3 className="text-[#FFCB05] font-black uppercase tracking-[0.2em] text-xs border-b-2 border-[#FFCB05]/30 pb-3">Session Intelligence FAQ</h3>
            <div className="grid grid-cols-1 md:grid-cols-2 gap-x-12 gap-y-8">
              {[
