          </section>
        </div>

        <div className="max-w-7xl mx-auto px-6 pt-12 border-t border-white/10 flex flex-col md:flex-row justify-between items-center gap-6">
          <div className="text-white/40 text-[10px] font-black uppercase tracking-[0.3em]">
            © 2024 PRACTICE HIGH-STAKES ACADEMIC ENGLISH SIMULATOR
          </div>
