              Change Scenario
            </button>

            <div className="bg-white rounded-[3rem] p-10 md:p-16 shadow-2xl border-b-[12px] border-[#FFCB05] flex flex-col md:flex-row gap-12 items-center relative overflow-hidden">
              <div className="absolute -top-10 -right-10 w-64 h-64 bg-[#00274C]/5 rounded-full blur-3xl"></div>

              <div className="w-56 h-56 flex-shrink-0 z-10">
                <img src={session.persona.avatar} alt={session.persona.name} className="w-full h-full rounded-[2.5rem] object-cover shadow-2xl border-8 border-white" />
              </div>
              <div className="space-y-6 flex-grow z-10 text-center md:text-left">
                <div>
                  <h2 className="text-4xl font-black text-[#00274C] tracking-tight">{session.persona.name}</h2>
                  <p className="text-[#00274C]/60 font-black uppercase tracking-widest text-[10px] mb-2">{session.persona.title}</p>
                  <div className="inline-block px-4 py-2 bg-[#00274C] text-[#FFCB05] rounded-xl text-[10px] font-black uppercase tracking-widest shadow-md">
                    Target: {session.scenario.title}
                  </div>
                </div>

                <p className="text-slate-700 leading-relaxed italic text-lg font-medium border-l-8 border-[#FFCB05] pl-6 py-2">
                  "{session.scenario.context}"
